export interface CSVRow {
  week_number: string;
  week_title: string;
  day_number: string;
  day_name: string;
  lesson_title: string;
  language: string;
  text_1: string;
  text_2: string;
  question_1: string;
  input_1: string;
  text_3: string;
  text_4: string;
  text_5: string;
  text_6: string;
  question_2: string;
  input_2: string;
}

export interface ExtractedData {
  rows: CSVRow[];
}

import { CSVRow } from '../types';

export const generateCSV = (data: CSVRow[]): string => {
  // Define headers in the specific order requested
  const headers: (keyof CSVRow)[] = [
    'week_number',
    'week_title',
    'day_number',
    'day_name',
    'lesson_title',
    'language',
    'text_1',
    'text_2',
    'question_1',
    'input_1',
    'text_3',
    'text_4',
    'text_5',
    'text_6',
    'question_2',
    'input_2'
  ];

  const csvRows = [
    headers.join(','), // Header row
    ...data.map(row => {
      return headers.map(fieldName => {
        const value = row[fieldName] || ''; // Handle undefined/null
        // Escape quotes by doubling them, and wrap content in quotes if it contains commas or quotes
        const escaped = value.replace(/"/g, '""');
        return `"${escaped}"`;
      }).join(',');
    })
  ];

  return csvRows.join('\n');
};

export const downloadCSV = (csvContent: string, filename: string = 'study-guide-export.csv') => {
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');
  if (link.download !== undefined) {
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }
};

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { CSVRow } from "../types";

const SYSTEM_INSTRUCTION = `
You are an expert OCR and Data Extraction specialist. 
Your task is to analyze an image of a study guide and extract the content into a specific JSON structure that maps to a CSV schema.

The CSV Schema has the following columns:
week_number, week_title, day_number, day_name, lesson_title, language, text_1, text_2, question_1, input_1, text_3, text_4, text_5, text_6, question_2, input_2

Guidelines:
1. Identify the 'Lesson Title' (usually the main heading).
2. Identify 'text_n' blocks. These are paragraphs of reading text. Map them sequentially (text_1, text_2, etc.).
3. Identify 'question_n' blocks. These are usually questions set apart, often in a colored box or bolded.
4. 'input_n' columns correspond to empty lines or spaces provided for the user to write answers. If a question is followed by empty lines, leave 'input_n' as an empty string, but ensure the key exists.
5. Infer 'week_number', 'day_number', 'day_name' from context if visible (e.g., "Wednesday", "Week 4"). If not explicitly visible, make a best logical guess or leave empty.
6. Set 'language' based on the text (e.g., "en").

Reference Example Logic (Mental Model):
- A header like "The Mind of Christ" -> lesson_title.
- First paragraph -> text_1.
- Second paragraph -> text_2.
- A bold question in a box -> question_1.
- Blank lines following it -> input_1 (empty string).
- Next paragraphs -> text_3, text_4...

Return valid JSON adhering to the schema.
`;

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    rows: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          week_number: { type: Type.STRING },
          week_title: { type: Type.STRING },
          day_number: { type: Type.STRING },
          day_name: { type: Type.STRING },
          lesson_title: { type: Type.STRING },
          language: { type: Type.STRING },
          text_1: { type: Type.STRING },
          text_2: { type: Type.STRING },
          question_1: { type: Type.STRING },
          input_1: { type: Type.STRING },
          text_3: { type: Type.STRING },
          text_4: { type: Type.STRING },
          text_5: { type: Type.STRING },
          text_6: { type: Type.STRING },
          question_2: { type: Type.STRING },
          input_2: { type: Type.STRING },
        },
        required: ["lesson_title", "text_1"], // Minimal requirements
      },
    },
  },
};

export const processImageWithGemini = async (base64Image: string): Promise<CSVRow[]> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-latest", // Efficient for multimodal/OCR tasks
      contents: [
        {
          role: "user",
          parts: [
            {
              inlineData: {
                mimeType: "image/jpeg", // Assuming JPEG for simplicity, works with PNG too usually
                data: base64Image,
              },
            },
            {
              text: "Extract the study guide data from this image into the specified CSV-compatible JSON format.",
            },
          ],
        },
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("No response from Gemini");

    const parsed = JSON.parse(text);
    return parsed.rows || [];
  } catch (error) {
    console.error("Gemini Extraction Error:", error);
    throw error;
  }
};

import React, { useRef, useState } from 'react';
import { CloudArrowUpIcon, PhotoIcon } from '@heroicons/react/24/outline';

interface FileUploadProps {
  onFileSelect: (base64: string, previewUrl: string) => void;
  isLoading: boolean;
}

export const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, isLoading }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [dragActive, setDragActive] = useState(false);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const processFile = (file: File) => {
    if (!file || !file.type.startsWith('image/')) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Extract base64 part only
      const base64 = result.split(',')[1];
      onFileSelect(base64, result);
    };
    reader.readAsDataURL(file);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (e.dataTransfer.files && e.dataTransfer.files[0]) {
      processFile(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      processFile(e.target.files[0]);
    }
  };

  return (
    <div 
      className={`relative border-2 border-dashed rounded-xl p-8 transition-colors text-center ${
        dragActive 
          ? 'border-indigo-500 bg-indigo-50' 
          : 'border-gray-300 hover:border-gray-400 bg-white'
      } ${isLoading ? 'opacity-50 pointer-events-none' : ''}`}
      onDragEnter={handleDrag}
      onDragLeave={handleDrag}
      onDragOver={handleDrag}
      onDrop={handleDrop}
    >
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        onChange={handleChange}
        className="hidden"
      />

      <div className="flex flex-col items-center justify-center gap-3">
        <div className="bg-indigo-100 p-3 rounded-full">
          <CloudArrowUpIcon className="w-8 h-8 text-indigo-600" />
        </div>
        <div>
          <h3 className="text-lg font-medium text-gray-900">Upload Study Guide Image</h3>
          <p className="text-sm text-gray-500 mt-1">Drag & drop or click to browse</p>
        </div>
        <button
          onClick={() => fileInputRef.current?.click()}
          className="mt-2 px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 transition-colors shadow-sm"
        >
          Select File
        </button>
        <p className="text-xs text-gray-400 mt-2">Supports JPG, PNG</p>
      </div>
    </div>
  );
};

import React from 'react';
