const SYSTEM_INSTRUCTION = `
You are an expert OCR and Data Extraction specialist. 
Your task is to analyze an image of a study guide and extract the content into a specific JSON structure that maps to a CSV schema.

The CSV Schema requires extracting data in the exact visual order it appears on the page, from top to bottom.

Columns to extract:
week_number, week_title, day_number, day_name, lesson_title, language, 
text_1, text_2, text_3, question_1, input_1, text_4, question_2, input_2, text_5, text_6

Extraction Logic (Top-to-Bottom Flow):
1. **Header Info**: Identify 'Lesson Title', 'Week', 'Day' at the top.
2. **Reading Blocks (Pre-Question)**: Capture the introductory paragraphs. Map these to 'text_1', 'text_2', and 'text_3' sequentially.
3. **First Question Block**: Identify the first distinct question (often bold/colored). Map to 'question_1'.
4. **First Input**: If there is space/lines for an answer immediately after Question 1, map to 'input_1' (use empty string "" if just lines).
5. **Middle Text**: If there is more reading text *after* the first question/input but *before* the second question, map this to 'text_4'.
6. **Second Question Block**: Identify the next question. Map to 'question_2'.
7. **Second Input**: Map space/lines after Question 2 to 'input_2'.
8. **Extra Text**: Use 'text_5'/'text_6' for any remaining text at the bottom.

Key Mental Model for this Layout:
[Title]
[Paragraph 1 -> text_1]
[Paragraph 2 -> text_2]
[Paragraph 3 -> text_3]
[Question 1 -> question_1]
[Answer Space -> input_1]
[Paragraph 4 -> text_4]
[Question 2 -> question_2]
[Answer Space -> input_2]

- Set 'language' based on the text (e.g., "en").
- If a field is not present visually, return an empty string or null.

Return valid JSON adhering to the schema.
`;

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    rows: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          week_number: { type: Type.STRING },
          week_title: { type: Type.STRING },
          day_number: { type: Type.STRING },
          day_name: { type: Type.STRING },
          lesson_title: { type: Type.STRING },
          language: { type: Type.STRING },
          // Note: The order here defines the structure of the JSON object, 
          // but the AI uses the logic above to populate them.
          text_1: { type: Type.STRING },
          text_2: { type: Type.STRING },
          text_3: { type: Type.STRING },
          question_1: { type: Type.STRING },
          input_1: { type: Type.STRING },
          text_4: { type: Type.STRING },
          question_2: { type: Type.STRING },
          input_2: { type: Type.STRING },
          text_5: { type: Type.STRING },
          text_6: { type: Type.STRING },
        },
        required: ["lesson_title", "text_1"],
      },
    },
  },
};

export const processImageWithGemini = async (base64Image: string): Promise<CSVRow[]> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: [
        {
          role: "user",
          parts: [
            {
              inlineData: {
                mimeType: "image/jpeg",
                data: base64Image,
              },
            },
            {
              text: "Extract the study guide data following the visual top-to-bottom flow: Text 1-3 -> Q1 -> Input 1 -> Text 4 -> Q2 -> Input 2.",
            },
          ],
        },
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    let text = response.text;
    if (!text) throw new Error("No response from Gemini");

    text = text.replace(/^```json\s*/, "").replace(/\s*```$/, "");

    const parsed = JSON.parse(text);
    return parsed.rows || [];
  } catch (error) {
    console.error("Gemini Extraction Error:", error);
    throw error;
  }
};

