import { GoogleGenAI, Type } from "@google/genai";
import { CSVRow } from "../types";

// Removed Metadata fields from extraction since they are now manual inputs
const SYSTEM_INSTRUCTION = `
You are an expert OCR and Data Extraction specialist.
Your goal is to map the visual layout of a study guide page into a specific sequential structure.

STRUCTURE RULES (Top to Bottom):
1. **Lesson Title**: The main heading of the page.
2. **Reading Section 1**: The first paragraphs of text. Map these to 'text_1', 'text_2', 'text_3'.
3. **Interaction 1**: 
   - Identify the **First Question** (usually bold or distinct). Map to 'question_1'.
   - Identify the **Answer Space** immediately following it (blank lines or box). Map to 'input_1'. 
   - Note: 'input_1' is a placeholder. If blank lines exist, return an empty string "".
4. **Reading Section 2 (Middle)**:
   - Identify any reading text that appears *after* Interaction 1 but *before* the next question. Map to 'text_4'.
5. **Interaction 2**:
   - Identify the **Second Question**. Map to 'question_2'.
   - Identify the **Answer Space** immediately following it. Map to 'input_2'.
6. **Remaining Text**: Any footer text or final paragraphs go to 'text_5', 'text_6'.

CRITICAL:
- Ensure 'input_n' is strictly associated with the space AFTER 'question_n'.
- Do NOT extract Week/Day info; the user provides this manually.
- Do NOT extract Language; the user provides this manually.

Return valid JSON adhering to the schema.
`;

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    rows: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          // Metadata fields are handled manually by the App, 
          // but we define them here as optional in case the model hallucinates them, 
          // though we will overwrite them.
          lesson_title: { type: Type.STRING },

          text_1: { type: Type.STRING },
          text_2: { type: Type.STRING },
          text_3: { type: Type.STRING },

          question_1: { type: Type.STRING },
          input_1: { type: Type.STRING },

          text_4: { type: Type.STRING },

          question_2: { type: Type.STRING },
          input_2: { type: Type.STRING },

          text_5: { type: Type.STRING },
          text_6: { type: Type.STRING },
        },
        required: ["lesson_title", "text_1", "question_1"],
      },
    },
  },
};

export const processImageWithGemini = async (base64Image: string, signal?: AbortSignal): Promise<Partial<CSVRow>[]> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    // We wrap the API call in a promise race to handle the abort signal immediately
    // even if the underlying SDK call takes time.
    const response: any = await new Promise((resolve, reject) => {
      const abortHandler = () => {
        reject(new DOMException("Aborted", "AbortError"));
      };

      if (signal?.aborted) {
        return abortHandler();
      }

      signal?.addEventListener("abort", abortHandler);

      ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [
          {
            role: "user",
            parts: [
              {
                inlineData: {
                  mimeType: "image/jpeg",
                  data: base64Image,
                },
              },
              {
                text: "Extract content respecting the flow: Text -> Question 1 -> Input 1 -> Middle Text -> Question 2 -> Input 2.",
              },
            ],
          },
        ],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          responseMimeType: "application/json",
          responseSchema: responseSchema,
        },
      })
      .then(result => {
        signal?.removeEventListener("abort", abortHandler);
        resolve(result);
      })
      .catch(error => {
        signal?.removeEventListener("abort", abortHandler);
        reject(error);
      });
    });

    let text = response.text;
    if (!text) throw new Error("No response from Gemini");

    text = text.replace(/^```json\s*/, "").replace(/\s*```$/, "");

    const parsed = JSON.parse(text);
    return parsed.rows || [];
  } catch (error) {
    // If it was an abort error, just rethrow it so the UI handles it as a cancellation
    if (error instanceof DOMException && error.name === 'AbortError') {
      throw error;
    }
    console.error("Gemini Extraction Error:", error);
    throw error;
  }
};

import React, { useRef, useState } from 'react';
import { CloudArrowUpIcon, XCircleIcon } from '@heroicons/react/24/outline';
import { SparklesIcon } from '@heroicons/react/24/solid';

interface FileUploadProps {
  onFileSelect: (base64: string, previewUrl: string) => void;
  onCancel?: () => void;
  isLoading: boolean;
  progress?: number;
}

export const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, onCancel, isLoading, progress = 0 }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [dragActive, setDragActive] = useState(false);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const processFile = (file: File) => {
    if (!file || !file.type.startsWith('image/')) return;

    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Extract base64 part only
      const base64 = result.split(',')[1];
      onFileSelect(base64, result);
    };
    reader.readAsDataURL(file);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (!isLoading && e.dataTransfer.files && e.dataTransfer.files[0]) {
      processFile(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      processFile(e.target.files[0]);
    }
  };

  return (
    <div 
      className={`relative border-2 border-dashed rounded-xl p-8 transition-all text-center overflow-hidden ${
        dragActive 
          ? 'border-indigo-500 bg-indigo-50' 
          : 'border-gray-300 hover:border-gray-400 bg-white'
      }`}
      onDragEnter={handleDrag}
      onDragLeave={handleDrag}
      onDragOver={handleDrag}
      onDrop={handleDrop}
    >
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        onChange={handleChange}
        className="hidden"
        disabled={isLoading}
      />

      {isLoading ? (
        <div className="flex flex-col items-center justify-center py-2 animate-in fade-in duration-300">
           <div className="relative mb-4">
             <div className="absolute inset-0 bg-indigo-200 rounded-full animate-ping opacity-75"></div>
             <div className="relative bg-white p-3 rounded-full shadow-sm z-10">
               <SparklesIcon className="w-8 h-8 text-indigo-600 animate-pulse" />
             </div>
           </div>

           <h3 className="text-lg font-medium text-gray-900">Analyzing Image...</h3>
           <p className="text-sm text-gray-500 mt-1 mb-6">Extracting text and structure</p>

           {/* Progress Bar */}
           <div className="w-full max-w-xs mb-6">
             <div className="flex justify-between text-xs text-gray-500 mb-1.5 font-medium">
               <span>Processing</span>
               <span>{Math.round(progress)}%</span>
             </div>
             <div className="w-full bg-gray-100 rounded-full h-2.5 overflow-hidden border border-gray-200">
               <div
                 className="bg-indigo-600 h-2.5 rounded-full transition-all duration-300 ease-out shadow-[0_0_10px_rgba(79,70,229,0.3)]"
                 style={{ width: `${progress}%` }}
               ></div>
             </div>
           </div>

           {onCancel && (
             <button
               onClick={(e) => {
                 e.stopPropagation();
                 onCancel();
               }}
               className="flex items-center gap-1.5 px-4 py-2 bg-white text-red-600 rounded-full text-xs font-semibold hover:bg-red-50 transition-colors border border-red-200 shadow-sm"
             >
               <XCircleIcon className="w-4 h-4" />
               Cancel Process
             </button>
           )}
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center gap-3">
          <div className="bg-indigo-100 p-3 rounded-full">
            <CloudArrowUpIcon className="w-8 h-8 text-indigo-600" />
          </div>
          <div>
            <h3 className="text-lg font-medium text-gray-900">Upload Study Guide Image</h3>
            <p className="text-sm text-gray-500 mt-1">Drag & drop or click to browse</p>
          </div>
          <button
            onClick={() => fileInputRef.current?.click()}
            className="mt-2 px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 transition-colors shadow-sm"
          >
            Select File
          </button>
          <p className="text-xs text-gray-400 mt-2">Supports JPG, PNG</p>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { FileUpload } from './components/FileUpload';
