import { CSVRow } from '../types';

export const DEFAULT_HEADERS: (keyof CSVRow)[] = [
  // 1. Context Metadata (Manual Inputs)
  'week_number',
  'week_title',
  'day_number',
  'day_name',
  'lesson_title',
  'language',

  // 2. First Block of Text
  'text_1',
  'text_2',
  'text_3',

  // 3. First Interaction Pair
  'question_1',
  'input_1', // Always follows question 1

  // 4. Middle Text Block
  'text_4',

  // 5. Second Interaction Pair
  'question_2',
  'input_2', // Always follows question 2

  // 6. Remaining Text
  'text_5',
  'text_6'
];

export const generateCSV = (data: CSVRow[], customHeaders?: (keyof CSVRow)[]): string => {
  // Use custom headers if provided, otherwise default
  const headers = customHeaders || DEFAULT_HEADERS;

  const csvRows = [
    headers.join(','), // Header row
    ...data.map(row => {
      return headers.map(fieldName => {
        const value = row[fieldName] || ''; // Handle undefined/null
        // Escape quotes by doubling them, and wrap content in quotes if it contains commas or quotes
        const escaped = String(value).replace(/"/g, '""');
        return `"${escaped}"`;
      }).join(',');
    })
  ];

  return csvRows.join('\n');
};

export const downloadCSV = (csvContent: string, filename: string = 'study-guide-export.csv') => {
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');
  if (link.download !== undefined) {
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { CSVRow } from "../types";

// Removed Metadata fields from extraction since they are now manual inputs
const SYSTEM_INSTRUCTION = `
You are an expert OCR and Data Extraction specialist.
Your goal is to map the visual layout of a study guide page into a specific sequential structure.

VISUAL FLOW RULES (Strict Top-to-Bottom):
1. **Lesson Title**: Found at the very top.
2. **Intro Text**: Paragraphs before the first question -> 'text_1', 'text_2', 'text_3'.
3. **Interaction 1**: 
   - 'question_1': The first bold question found.
   - 'input_1': The space/lines immediately following Question 1.
4. **Middle Text (CRITICAL)**: 
   - 'text_4': Most pages have reading text *BETWEEN* Question 1 and Question 2. 
   - **DO NOT** skip this. **DO NOT** jump from Input 1 to Question 2. Look for the text paragraph in the middle.
5. **Interaction 2**:
   - 'question_2': The second question found (after the Middle Text).
   - 'input_2': The space/lines immediately following Question 2.
6. **Closing Text**: Any remaining text at the bottom -> 'text_5', 'text_6'.

CRITICAL:
- Do NOT merge Question 1 and Question 2. They are usually separated by 'text_4'.
- If 'input_1' or 'input_2' are blank lines, return an empty string "".
- Ignore Week/Day/Language info (handled manually).

Return valid JSON adhering to the schema.
`;

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    rows: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          lesson_title: { type: Type.STRING },

          text_1: { type: Type.STRING },
          text_2: { type: Type.STRING },
          text_3: { type: Type.STRING },

          question_1: { type: Type.STRING },
          input_1: { type: Type.STRING },

          text_4: { type: Type.STRING, description: "Text content found strictly BETWEEN input_1 and question_2" },

          question_2: { type: Type.STRING },
          input_2: { type: Type.STRING },

          text_5: { type: Type.STRING },
          text_6: { type: Type.STRING },
        },
        required: ["lesson_title", "text_1", "question_1"],
      },
    },
  },
};

export const processImageWithGemini = async (base64Image: string, signal?: AbortSignal): Promise<Partial<CSVRow>[]> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response: any = await new Promise((resolve, reject) => {
      const abortHandler = () => {
        reject(new DOMException("Aborted", "AbortError"));
      };

      if (signal?.aborted) {
        return abortHandler();
      }

      signal?.addEventListener("abort", abortHandler);

      ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: [
          {
            role: "user",
            parts: [
              {
                inlineData: {
                  mimeType: "image/jpeg",
                  data: base64Image,
                },
              },
              {
                text: "Extract content respecting the visual gap between questions. Usually: Text -> Q1 -> Input -> MIDDLE TEXT -> Q2 -> Input.",
              },
            ],
          },
        ],
        config: {
          systemInstruction: SYSTEM_INSTRUCTION,
          responseMimeType: "application/json",
          responseSchema: responseSchema,
        },
      })
      .then(result => {
        signal?.removeEventListener("abort", abortHandler);
        resolve(result);
      })
      .catch(error => {
        signal?.removeEventListener("abort", abortHandler);
        reject(error);
      });
    });

    let text = response.text;
    if (!text) throw new Error("No response from Gemini");

    text = text.replace(/^```json\s*/, "").replace(/\s*```$/, "");

    const parsed = JSON.parse(text);
    return parsed.rows || [];
  } catch (error) {
    if (error instanceof DOMException && error.name === 'AbortError') {
      throw error;
    }
    console.error("Gemini Extraction Error:", error);
    throw error;
  }
};

