export interface StudyMetadata {
  week_number: string;
  week_title: string;
  day_number: string;
  day_name: string;
  language: string;
}

export interface CSVRow extends StudyMetadata {
  lesson_title: string;

  // Initial Text Blocks
  text_1: string;
  text_2: string;
  text_3: string;

  // Interaction 1
  question_1: string;
  input_1: string;

  // Text after Q1
  text_4: string;

  // Interaction 2
  question_2: string;
  input_2: string;

  // Text after Q2
  text_5: string;

  // Interaction 3
  question_3: string;
  input_3: string;

  // Text after Q3
  text_6: string;

  // Interaction 4
  question_4: string;
  input_4: string;

  // Final Text Blocks
  text_7: string;
  text_8: string;
}

export interface ExtractedData {
  rows: CSVRow[];
}

import { CSVRow } from '../types';

export const DEFAULT_HEADERS: (keyof CSVRow)[] = [
  // 1. Context Metadata (Manual Inputs)
  'week_number',
  'week_title',
  'day_number',
  'day_name',
  'lesson_title',
  'language',

  // 2. First Block of Text
  'text_1',
  'text_2',
  'text_3',

  // 3. First Interaction Pair
  'question_1',
  'input_1',

  // 4. Second Block
  'text_4',
  'question_2',
  'input_2',

  // 5. Third Block
  'text_5',
  'question_3',
  'input_3',

  // 6. Fourth Block
  'text_6',
  'question_4',
  'input_4',

  // 7. Remaining Text
  'text_7',
  'text_8'
];

export const generateCSV = (data: CSVRow[], customHeaders?: (keyof CSVRow)[]): string => {
  // Use custom headers if provided, otherwise default
  const headers = customHeaders || DEFAULT_HEADERS;

  const csvRows = [
    headers.join(','), // Header row
    ...data.map(row => {
      return headers.map(fieldName => {
        const value = row[fieldName] || ''; // Handle undefined/null
        // Escape quotes by doubling them, and wrap content in quotes if it contains commas or quotes
        const escaped = String(value).replace(/"/g, '""');
        return `"${escaped}"`;
      }).join(',');
    })
  ];

  return csvRows.join('\n');
};

export const downloadCSV = (csvContent: string, filename: string = 'study-guide-export.csv') => {
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');
  if (link.download !== undefined) {
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }
};

