        questionIndex++;
        textIndexInGroup = 0; // Reset text counter for the next section

        // Map specific question slots
        if (questionIndex === 1) {
            row.question_1 = block.value;
            row.input_1 = ""; // Auto-add input
        } else if (questionIndex === 2) {
            row.question_2 = block.value;
            row.input_2 = "";
        } else if (questionIndex === 3) {
            row.question_3 = block.value;
            row.input_3 = "";
        } else if (questionIndex === 4) {
            row.question_4 = block.value;
            row.input_4 = "";
        }
      } else {
        // It's a Text Block
        textIndexInGroup++;

        if (questionIndex === 0) {
          // Before any questions
          if (textIndexInGroup === 1) row.text_1 = (row.text_1 ? row.text_1 + '\n' : '') + block.value;
          else if (textIndexInGroup === 2) row.text_2 = block.value;
          else if (textIndexInGroup >= 3) row.text_3 = (row.text_3 ? row.text_3 + '\n' : '') + block.value;
        } 
        else if (questionIndex === 1) {
          // Between Q1 and Q2 -> text_4
          row.text_4 = (row.text_4 ? row.text_4 + '\n' : '') + block.value;
        }
        else if (questionIndex === 2) {
          // Between Q2 and Q3 -> text_5
          row.text_5 = (row.text_5 ? row.text_5 + '\n' : '') + block.value;
        }
        else if (questionIndex === 3) {
           // Between Q3 and Q4 -> text_6
           row.text_6 = (row.text_6 ? row.text_6 + '\n' : '') + block.value;
        }
        else if (questionIndex >= 4) {
           // After Q4 -> text_7, text_8
           if (!row.text_7) row.text_7 = block.value;
           else row.text_8 = (row.text_8 ? row.text_8 + '\n' : '') + block.value;
        }
      }
    });

    onSubmit(row);
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="p-4 border-b border-gray-100 bg-gray-50 flex-shrink-0">
            <h3 className="text-sm font-semibold text-gray-900 uppercase tracking-wider">Content Builder</h3>
            <p className="text-xs text-gray-500 mt-1">Build your page structure. Blocks are mapped sequentially to the CSV.</p>
        </div>

        <div className="flex-1 overflow-y-auto p-4 custom-scrollbar space-y-4" ref={blocksContainerRef}>
            {/* Lesson Title */}
            <div>
                <label className="block text-xs font-medium text-gray-700 mb-1">Lesson Title <span className="text-red-500">*</span></label>
                <input 
                    type="text" 
                    className="w-full rounded-lg border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 text-sm py-2 px-3 border"
                    placeholder="e.g. Introduction to Science"
                    value={lessonTitle}
                    onChange={(e) => setLessonTitle(e.target.value)}
                />
            </div>

            <hr className="border-gray-100" />

            {/* Dynamic Blocks */}
            <div className="space-y-3">
                {blocks.map((block, index) => (
                    <div key={block.id} className="relative group transition-all">
                         <div className="flex items-center justify-between mb-1">
                             <label className="flex items-center gap-2 text-xs font-medium text-gray-600">
                                {block.type === 'question' ? (
                                    <>
                                        <QuestionMarkCircleIcon className="w-4 h-4 text-orange-500" />
                                        <span className="text-orange-700">Question Block</span>
                                    </>
                                ) : (
                                    <>
                                        <DocumentTextIcon className="w-4 h-4 text-blue-500" />
                                        <span className="text-blue-700">Text Block</span>
                                    </>
                                )}
                             </label>

                             {/* Reordering Controls */}
                             <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button
                                    onClick={() => moveBlock(index, 'up')}
                                    disabled={index === 0}
                                    className="p-1 hover:bg-gray-100 rounded text-gray-400 hover:text-gray-600 disabled:opacity-30"
                                    title="Move Up"
                                >
                                    <ChevronUpIcon className="w-3 h-3" />
                                </button>
                                <button
                                    onClick={() => moveBlock(index, 'down')}
                                    disabled={index === blocks.length - 1}
                                    className="p-1 hover:bg-gray-100 rounded text-gray-400 hover:text-gray-600 disabled:opacity-30"
                                    title="Move Down"
                                >
                                    <ChevronDownIcon className="w-3 h-3" />
                                </button>
                                <div className="w-px h-3 bg-gray-200 mx-1"></div>
                                <button 
                                    onClick={() => removeBlock(block.id)}
                                    className="p-1 hover:bg-red-50 rounded text-gray-400 hover:text-red-500 transition-colors"
                                    title="Remove block"
                                >
                                    <TrashIcon className="w-3 h-3" />
                                </button>
                             </div>
                         </div>

                         <div className="relative">
                             <textarea 
                                className={`w-full rounded-lg shadow-sm text-sm p-3 border min-h-[80px] focus:ring-1 focus:ring-opacity-50 transition-colors ${
                                    block.type === 'question' 
                                    ? 'border-orange-200 focus:border-orange-500 focus:ring-orange-500 bg-orange-50/30' 
                                    : 'border-blue-200 focus:border-blue-500 focus:ring-blue-500 bg-blue-50/30'
                                }`}
                                placeholder={block.type === 'question' ? "Type the question..." : "Type content text..."}
                                value={block.value}
                                onChange={(e) => updateBlock(block.id, e.target.value)}
                             />
                             {block.type === 'question' && (
                                 <div className="absolute bottom-2 right-2 text-[10px] text-orange-400 bg-white/50 px-1.5 py-0.5 rounded border border-orange-100">
                                     + Input field added automatically
                                 </div>
                             )}
                         </div>

                         {/* Visual Connector */}
                         {index < blocks.length - 1 && (
                            <div className="flex justify-center my-1">
                                <div className="w-0.5 h-3 bg-gray-200"></div>
                            </div>
                         )}
                    </div>
                ))}
            </div>

            {/* Add Buttons */}
            <div className="grid grid-cols-2 gap-3 mt-4 pb-2">
                <button 
                    onClick={() => addBlock('text')}
                    className="flex items-center justify-center gap-2 py-2.5 px-4 border border-dashed border-blue-300 rounded-lg text-xs font-semibold text-blue-600 hover:bg-blue-50 hover:border-blue-400 transition-all"
                >
                    <PlusCircleIcon className="w-4 h-4" />
                    Add Text
                </button>
                <button 
                    onClick={() => addBlock('question')}
                    className="flex items-center justify-center gap-2 py-2.5 px-4 border border-dashed border-orange-300 rounded-lg text-xs font-semibold text-orange-600 hover:bg-orange-50 hover:border-orange-400 transition-all"
                >
                    <PlusCircleIcon className="w-4 h-4" />
                    Add Question
                </button>
            </div>
        </div>

        <div className="p-4 border-t border-gray-200 bg-gray-50 flex-shrink-0">
            <button 
                onClick={handleProcess}
                className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-2.5 rounded-lg text-sm font-medium transition-all shadow-sm active:scale-[0.98]"
            >
                <ArrowRightCircleIcon className="w-5 h-5" />
                Update Table
            </button>
        </div>
    </div>
  );
};

import React from 'react';
import { CSVRow } from '../types';
import { ChevronLeftIcon, ChevronRightIcon, PencilSquareIcon } from '@heroicons/react/24/solid';

interface TablePreviewProps {
  data: CSVRow[];
  columns: (keyof CSVRow)[];
  onMoveColumn: (index: number, direction: 'left' | 'right') => void;
  onEditHeader?: (key: keyof CSVRow) => void;
}

export const TablePreview: React.FC<TablePreviewProps> = ({ data, columns, onMoveColumn, onEditHeader }) => {
  if (data.length === 0) return null;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden flex flex-col h-full">
      <div className="px-6 py-4 border-b border-gray-200 bg-gray-50 flex items-center justify-between">
        <h3 className="font-semibold text-gray-800">Generated Table Preview</h3>
        <div className="flex items-center gap-2">
            <span className="text-xs text-gray-400 mr-2 hidden sm:inline-block">
                Click headers to edit content
            </span>
            <span className="text-xs bg-indigo-100 text-indigo-700 px-2 py-1 rounded-full font-medium">
            {data.length} Rows
            </span>
        </div>
      </div>

      <div className="overflow-auto flex-1">
        <table className="min-w-full divide-y divide-gray-200 text-sm">
          <thead className="bg-gray-50">
            <tr>
              {columns.map((header, idx) => (
                <th
                  key={header}
                  scope="col"
                  onClick={() => onEditHeader?.(header)}
                  className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider whitespace-nowrap group cursor-pointer hover:bg-indigo-50 hover:text-indigo-700 transition-colors relative"
                  title="Click to edit/split this column"
                >
                  <div className="flex flex-col gap-2">
                    <div className="flex items-center gap-1">
                        <span>{header.replace(/_/g, ' ')}</span>
                        <PencilSquareIcon className="w-3 h-3 opacity-0 group-hover:opacity-100 transition-opacity" />
                    </div>
                    <div 
                        className="flex items-center gap-1 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity"
                        onClick={(e) => e.stopPropagation()} 
                    >
                      <button
                        onClick={() => onMoveColumn(idx, 'left')}
                        disabled={idx === 0}
                        className="p-1 hover:bg-gray-200 rounded disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
                        title="Move Left"
                      >
                        <ChevronLeftIcon className="w-3 h-3 text-gray-600" />
                      </button>
                      <button
                        onClick={() => onMoveColumn(idx, 'right')}
                        disabled={idx === columns.length - 1}
                        className="p-1 hover:bg-gray-200 rounded disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
                        title="Move Right"
                      >
                        <ChevronRightIcon className="w-3 h-3 text-gray-600" />
                      </button>
                    </div>
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {data.map((row, idx) => (
              <tr key={idx} className="hover:bg-gray-50 transition-colors">
                {columns.map((header) => (
                  <td key={`${idx}-${header}`} className="px-6 py-4 min-w-[200px] text-gray-700 align-top border-r border-transparent hover:border-gray-100">
                    <div className="line-clamp-4 hover:line-clamp-none transition-all">
                      {row[header] || <span className="text-gray-300 italic">Empty</span>}
                    </div>
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useRef, useMemo } from 'react';
import { FileUpload } from './components/FileUpload';
import { TablePreview } from './components/TablePreview';
import { MetadataForm } from './components/MetadataForm';
import { ManualEntryForm } from './components/ManualEntryForm';
import { processImageWithGemini } from './services/geminiService';
import { generateCSV, downloadCSV, DEFAULT_HEADERS } from './utils/csvHelper';
import { CSVRow, StudyMetadata } from './types';
import { 
  ArrowDownTrayIcon, 
  TableCellsIcon, 
  ExclamationTriangleIcon, 
  MagnifyingGlassPlusIcon, 
  XMarkIcon,
  PhotoIcon,
  PencilSquareIcon
} from '@heroicons/react/24/outline';

// Standard Day Mapping
// Updated: 1=Saturday, 2=Sunday, 3=Monday, ..., 7=Friday
const DAY_MAP: Record<string, string> = {
  '1': 'Saturday',
  '2': 'Sunday',
  '3': 'Monday',
  '4': 'Tuesday',
  '5': 'Wednesday',
  '6': 'Thursday',
  '7': 'Friday',
};

const App: React.FC = () => {
  // State for manual metadata
  const [metadata, setMetadata] = useState<StudyMetadata>({
    week_number: '',
    week_title: '',
    day_number: '',
    day_name: '',
    language: ''
  });

  const [activeTab, setActiveTab] = useState<'upload' | 'manual'>('upload');

  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isImageModalOpen, setIsImageModalOpen] = useState(false); // State for Lightbox
  const [generatedData, setGeneratedData] = useState<CSVRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [progress, setProgress] = useState(0); // State for progress bar
  const [error, setError] = useState<string | null>(null);

  // Manage column order in state so user can change it
  const [columnOrder, setColumnOrder] = useState<(keyof CSVRow)[]>(DEFAULT_HEADERS);

  // Ref to hold the AbortController
  const abortControllerRef = useRef<AbortController | null>(null);

  // Check if all metadata fields are filled
  const isMetadataComplete = useMemo(() => {
    return Object.values(metadata).every(val => typeof val === 'string' && val.trim().length > 0);
  }, [metadata]);

  const handleMetadataChange = (field: keyof StudyMetadata, value: string) => {
    setMetadata(prev => {
      const updated = { ...prev, [field]: value };

      // Synchronization Logic: Day Number <-> Day Name
      if (field === 'day_number') {
        const mappedName = DAY_MAP[value];
        if (mappedName) {
          updated.day_name = mappedName;
        }
      } else if (field === 'day_name') {
        // Find key by value
        const mappedNumber = Object.keys(DAY_MAP).find(key => DAY_MAP[key] === value);
        if (mappedNumber) {
          updated.day_number = mappedNumber;
        }
      }

      // If we already have data, update it in real-time
      if (generatedData.length > 0) {
        setGeneratedData(currentRows => currentRows.map(row => ({
          ...row,
          ...updated
        })));
      }

      return updated;
    });
  };

  const updateTableData = (newRows: CSVRow[]) => {
      // AUTOMATIC COLUMN CLEANUP
      const metadataKeys: (keyof StudyMetadata)[] = ['week_number', 'week_title', 'day_number', 'day_name', 'language'];

      // 1. Identify which columns have actual content anywhere in the dataset
      const columnsWithData = new Set<keyof CSVRow>();
      DEFAULT_HEADERS.forEach(header => {
        const hasContent = newRows.some(row => {
            const val = row[header];
            return val && String(val).trim().length > 0;
        });
        if (hasContent) {
            columnsWithData.add(header);
        }
      });

      // 2. Filter headers based on rules
      const activeHeaders = DEFAULT_HEADERS.filter(header => {
        // Rule A: Always keep metadata columns (as they are manually editable)
        if (metadataKeys.includes(header as any)) return true;

        // Rule B: Special dependency for Input columns (Dynamic Check)
        // Checks if header is 'input_X' and requires 'question_X' to be present
        if (typeof header === 'string' && header.startsWith('input_')) {
            const parts = header.split('_');
            if (parts.length === 2) {
                const number = parts[1];
                const correspondingQuestion = `question_${number}` as keyof CSVRow;
                return columnsWithData.has(correspondingQuestion);
            }
        }

        // Rule C: For all other columns (Text, Questions), keep only if they have data
        return columnsWithData.has(header);
      });

      setColumnOrder(activeHeaders);
      setGeneratedData(newRows);
  };

  const handleMoveColumn = (index: number, direction: 'left' | 'right') => {
    if (direction === 'left' && index === 0) return;
    if (direction === 'right' && index === columnOrder.length - 1) return;

    const newOrder = [...columnOrder];
    const targetIndex = direction === 'left' ? index - 1 : index + 1;

    // Swap
    [newOrder[index], newOrder[targetIndex]] = [newOrder[targetIndex], newOrder[index]];

    setColumnOrder(newOrder);
  };

  const handleEditHeader = (key: keyof CSVRow) => {
    // When a header is clicked, switch to manual mode.
    // The form will automatically populate via the `initialData` prop.
    setActiveTab('manual');
  };

  const handleCancel = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    setIsLoading(false);
    setProgress(0);
    setError(null);
  };

  const handleManualEntrySubmit = (partialRow: Partial<CSVRow>) => {
    // Merge manual entry with metadata
    const completeRow: CSVRow = {
        ...partialRow,
        ...metadata
    } as CSVRow;

    // For manual entry, we typically replace the data or append? 
    // Assuming single-page/single-row focus for this app, replacing is safer to avoid confusion.
    updateTableData([completeRow]);

    // Clear preview image since we are doing manual data
    // setPreviewUrl(null); // Keep preview URL so user can compare if they want
    setError(null);
  };

  const handleFileSelect = async (base64: string, preview: string) => {
    // Cancel any previous pending request
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    // Create new controller
    const controller = new AbortController();
    abortControllerRef.current = controller;

    setPreviewUrl(preview);
    setGeneratedData([]);
    setError(null);
    setIsLoading(true);
    setProgress(0); // Reset progress

    try {
      // Pass the setProgress callback to the service
      const extractedRows = await processImageWithGemini(
        base64, 
        controller.signal, 
        (percent) => setProgress(percent)
      );

      // Set to 100% on success
      setProgress(100);

      // Merge extraction results with manual metadata
      const completeRows: CSVRow[] = extractedRows.map((row: any) => ({
        ...row,
        ...metadata // Spread manual metadata over the extracted row
      }));

      updateTableData(completeRows);
    } catch (err: any) {
      if (err.name === 'AbortError') {
        console.log("Process cancelled by user");
      } else {
        setError(err.message || "Failed to process image");
      }
      setProgress(0);
    } finally {
      if (abortControllerRef.current === controller) {
        setIsLoading(false);
        abortControllerRef.current = null;
      }
    }
  };

  const handleDownload = () => {
    if (generatedData.length === 0) return;

    if (!isMetadataComplete) {
      alert("Please fill in all Manual Context Data fields before exporting.");
      return;
    }

    // Construct filename: Week Title + Day Name
    let filename = 'study-guide-export.csv';

    const wTitle = metadata.week_title?.trim();
    const dName = metadata.day_name?.trim();

    if (wTitle || dName) {
      // Concatenate with a separator if both exist
      const nameParts = [wTitle, dName].filter(Boolean);
      const rawName = nameParts.join(' - ');

      // Basic sanitization for filenames (remove invalid characters)
      const safeName = rawName.replace(/[\\/:*?"<>|]/g, ''); 

      if (safeName.length > 0) {
        filename = `${safeName}.csv`;
      }
    }

    // Pass current columnOrder to respect user's visual arrangement and filtering
    const csvContent = generateCSV(generatedData, columnOrder);
    downloadCSV(csvContent, filename);
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <TableCellsIcon className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold text-gray-900 tracking-tight">CSV Builder</h1>
          </div>

          <div className="flex items-center gap-4">
             {generatedData.length > 0 && (
                <button
                  onClick={handleDownload}
                  disabled={!isMetadataComplete}
                  title={!isMetadataComplete ? "Please fill all manual context data to enable download" : "Download CSV"}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm ${
                    isMetadataComplete 
                      ? "bg-indigo-600 hover:bg-indigo-700 text-white" 
                      : "bg-gray-300 text-gray-500 cursor-not-allowed"
                  }`}
                >
                  <ArrowDownTrayIcon className="w-4 h-4" />
                  Download CSV
                </button>
             )}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 bg-gray-50 p-4 sm:p-6 lg:p-8">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-8rem)]">

          {/* Left Column: Context, Upload & Image */}
          <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-y-auto pr-2 custom-scrollbar">

            {/* 1. Metadata Form */}
            <section>
              <MetadataForm 
                metadata={metadata} 
                onChange={handleMetadataChange} 
                disabled={isLoading} 
              />
            </section>

            {/* 2. Content Source Tabs */}
            <section className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden flex flex-col min-h-[400px]">
              {/* Tab Header */}
              <div className="flex border-b border-gray-200">
                <button 
                  onClick={() => setActiveTab('upload')}
                  className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 transition-colors ${
                    activeTab === 'upload' 
                      ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' 
                      : 'bg-gray-50 text-gray-500 hover:text-gray-700 hover:bg-gray-100'
                  }`}
                >
                  <PhotoIcon className="w-4 h-4" />
                  Upload Image
                </button>
                <button 
                  onClick={() => setActiveTab('manual')}
                  className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 transition-colors ${
                    activeTab === 'manual' 
                      ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' 
                      : 'bg-gray-50 text-gray-500 hover:text-gray-700 hover:bg-gray-100'
                  }`}
                >
                  <PencilSquareIcon className="w-4 h-4" />
                  Manual Entry
                </button>
              </div>

              {/* Tab Content */}
              <div className="flex-1 flex flex-col p-4 bg-gray-50/50">
                {activeTab === 'upload' ? (
                  <>
                    <h2 className="text-sm font-semibold text-gray-900 mb-4 uppercase tracking-wider">AI Extraction</h2>
                    <FileUpload 
                      onFileSelect={handleFileSelect} 
                      isLoading={isLoading} 
                      onCancel={handleCancel}
                      progress={progress}
                    />

                    {/* Error Message */}
                    {error && (
                      <div className="mt-4 bg-red-50 border border-red-200 rounded-xl p-4 flex items-start gap-3 text-red-700">
                        <ExclamationTriangleIcon className="w-5 h-5 flex-shrink-0 mt-0.5" />
                        <p className="text-sm">{error}</p>
                      </div>
                    )}

                    {/* Image Preview */}
                    {previewUrl && (
                      <div className="mt-6 flex-1 flex flex-col">
                        <div className="flex items-center justify-between mb-2">
                            <h2 className="text-sm font-semibold text-gray-900 uppercase tracking-wider">Source Image</h2>
                            <span className="text-xs text-gray-400">Click to expand</span>
                        </div>

                        <div 
                            className="relative flex-1 bg-gray-100 rounded-lg overflow-hidden border border-gray-200 group cursor-zoom-in min-h-[200px]"
                            onClick={() => setIsImageModalOpen(true)}
                        >
                          <img 
                            src={previewUrl} 
                            alt="Preview" 
                            className="absolute inset-0 w-full h-full object-contain"
                          />
                          <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors flex items-center justify-center">
                            <div className="bg-black/50 text-white p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity transform scale-75 group-hover:scale-100">
                                <MagnifyingGlassPlusIcon className="w-6 h-6" />
                            </div>
                          </div>
                        </div>
                      </div>
                    )}
                  </>
                ) : (
                  <div className="h-full flex flex-col">
                    <ManualEntryForm 
                        onSubmit={handleManualEntrySubmit} 
                        initialData={generatedData.length > 0 ? generatedData[0] : undefined}
                    />
                  </div>
                )}
              </div>
            </section>

          </div>

          {/* Right Column: Table Preview */}
          <div className="lg:col-span-8 flex flex-col h-full">
            {generatedData.length > 0 ? (
              <TablePreview 
                data={generatedData} 
                columns={columnOrder} 
                onMoveColumn={handleMoveColumn}
                onEditHeader={handleEditHeader}
              />
            ) : (
              <div className="flex-1 bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col items-center justify-center text-center p-12">
                <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mb-4">
                  <TableCellsIcon className="w-8 h-8 text-gray-300" />
                </div>
