import React, { useState, useRef, useMemo } from 'react';
import { FileUpload } from './components/FileUpload';
import { TablePreview } from './components/TablePreview';
import { MetadataForm } from './components/MetadataForm';
import { ManualEntryForm } from './components/ManualEntryForm';
import { processImageWithGemini } from './services/geminiService';
import { generateCSV, downloadCSV, DEFAULT_HEADERS } from './utils/csvHelper';
import { CSVRow, StudyMetadata } from './types';
import { 
  ArrowDownTrayIcon, 
  TableCellsIcon, 
  ExclamationTriangleIcon, 
  MagnifyingGlassPlusIcon, 
  XMarkIcon,
  PhotoIcon,
  PencilSquareIcon
} from '@heroicons/react/24/outline';

// Standard Day Mapping
// Updated: 1=Saturday, 2=Sunday, 3=Monday, ..., 7=Friday
const DAY_MAP: Record<string, string> = {
  '1': 'Saturday',
  '2': 'Sunday',
  '3': 'Monday',
  '4': 'Tuesday',
  '5': 'Wednesday',
  '6': 'Thursday',
  '7': 'Friday',
};

const App: React.FC = () => {
  // State for manual metadata
  const [metadata, setMetadata] = useState<StudyMetadata>({
    week_number: '',
    week_title: '',
    day_number: '',
    day_name: '',
    language: ''
  });

  const [activeTab, setActiveTab] = useState<'upload' | 'manual'>('upload');

  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isImageModalOpen, setIsImageModalOpen] = useState(false); // State for Lightbox
  const [generatedData, setGeneratedData] = useState<CSVRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [progress, setProgress] = useState(0); // State for progress bar
  const [error, setError] = useState<string | null>(null);

  // Manage column order in state so user can change it
  const [columnOrder, setColumnOrder] = useState<(keyof CSVRow)[]>(DEFAULT_HEADERS);

  // Ref to hold the AbortController
  const abortControllerRef = useRef<AbortController | null>(null);

  // Check if all metadata fields are filled
  const isMetadataComplete = useMemo(() => {
    return Object.values(metadata).every(val => typeof val === 'string' && val.trim().length > 0);
  }, [metadata]);

  const handleMetadataChange = (field: keyof StudyMetadata, value: string) => {
    setMetadata(prev => {
      const updated = { ...prev, [field]: value };

      // Synchronization Logic: Day Number <-> Day Name
      if (field === 'day_number') {
        const mappedName = DAY_MAP[value];
        if (mappedName) {
          updated.day_name = mappedName;
        }
      } else if (field === 'day_name') {
        // Find key by value
        const mappedNumber = Object.keys(DAY_MAP).find(key => DAY_MAP[key] === value);
        if (mappedNumber) {
          updated.day_number = mappedNumber;
        }
      }

      // If we already have data, update it in real-time
      if (generatedData.length > 0) {
        setGeneratedData(currentRows => currentRows.map(row => ({
          ...row,
          ...updated
        })));
      }

      return updated;
    });
  };

  const updateTableData = (newRows: CSVRow[]) => {
      // AUTOMATIC COLUMN CLEANUP
      const metadataKeys: (keyof StudyMetadata)[] = ['week_number', 'week_title', 'day_number', 'day_name', 'language'];

      // 1. Identify which columns have actual content anywhere in the dataset
      const columnsWithData = new Set<keyof CSVRow>();
      DEFAULT_HEADERS.forEach(header => {
        const hasContent = newRows.some(row => {
            const val = row[header];
            return val && String(val).trim().length > 0;
        });
        if (hasContent) {
            columnsWithData.add(header);
        }
      });

      // 2. Filter headers based on rules
      const activeHeaders = DEFAULT_HEADERS.filter(header => {
        // Rule A: Always keep metadata columns (as they are manually editable)
        if (metadataKeys.includes(header as any)) return true;

        // Rule B: Special dependency for Input columns (Dynamic Check)
        // Checks if header is 'input_X' and requires 'question_X' to be present
        if (typeof header === 'string' && header.startsWith('input_')) {
            const parts = header.split('_');
            if (parts.length === 2) {
                const number = parts[1];
                const correspondingQuestion = `question_${number}` as keyof CSVRow;
                return columnsWithData.has(correspondingQuestion);
            }
        }

        // Rule C: For all other columns (Text, Questions), keep only if they have data
        return columnsWithData.has(header);
      });

      setColumnOrder(activeHeaders);
      setGeneratedData(newRows);
  };

  const handleMoveColumn = (index: number, direction: 'left' | 'right') => {
    if (direction === 'left' && index === 0) return;
    if (direction === 'right' && index === columnOrder.length - 1) return;

    const newOrder = [...columnOrder];
    const targetIndex = direction === 'left' ? index - 1 : index + 1;

    // Swap
    [newOrder[index], newOrder[targetIndex]] = [newOrder[targetIndex], newOrder[index]];

    setColumnOrder(newOrder);
  };

  const handleEditHeader = (key: keyof CSVRow) => {
    // When a header is clicked, switch to manual mode.
    // The form will automatically populate via the `initialData` prop.
    setActiveTab('manual');
  };

  const handleCancel = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    setIsLoading(false);
    setProgress(0);
    setError(null);
  };

  const handleClearTable = () => {
    if (confirm("Are you sure you want to clear the generated table data?")) {
        setGeneratedData([]);
        setPreviewUrl(null);
        setError(null);
    }
  };

  const handleManualEntrySubmit = (partialRow: Partial<CSVRow>) => {
    // Merge manual entry with metadata
    const completeRow: CSVRow = {
        ...partialRow,
        ...metadata
    } as CSVRow;

    // For manual entry, we typically replace the data or append? 
    // Assuming single-page/single-row focus for this app, replacing is safer to avoid confusion.
    updateTableData([completeRow]);

    // Clear preview image since we are doing manual data
    // setPreviewUrl(null); // Keep preview URL so user can compare if they want
    setError(null);
  };

  const handleFileSelect = async (base64: string, preview: string) => {
    // Cancel any previous pending request
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }

    // Create new controller
    const controller = new AbortController();
    abortControllerRef.current = controller;

    setPreviewUrl(preview);
    setGeneratedData([]);
    setError(null);
    setIsLoading(true);
    setProgress(0); // Reset progress

    try {
      // Pass the setProgress callback to the service
      const extractedRows = await processImageWithGemini(
        base64, 
        controller.signal, 
        (percent) => setProgress(percent)
      );

      // Set to 100% on success
      setProgress(100);

      // Merge extraction results with manual metadata
      const completeRows: CSVRow[] = extractedRows.map((row: any) => ({
        ...row,
        ...metadata // Spread manual metadata over the extracted row
      }));

      updateTableData(completeRows);
    } catch (err: any) {
      if (err.name === 'AbortError') {
        console.log("Process cancelled by user");
      } else {
        setError(err.message || "Failed to process image");
      }
      setProgress(0);
    } finally {
      if (abortControllerRef.current === controller) {
        setIsLoading(false);
        abortControllerRef.current = null;
      }
    }
  };

  const handleDownload = () => {
    if (generatedData.length === 0) return;

    if (!isMetadataComplete) {
      alert("Please fill in all Manual Context Data fields before exporting.");
      return;
    }

    // Construct filename: Week Title + Day Name
    let filename = 'study-guide-export.csv';

    const wTitle = metadata.week_title?.trim();
    const dName = metadata.day_name?.trim();

    if (wTitle || dName) {
      // Concatenate with a separator if both exist
      const nameParts = [wTitle, dName].filter(Boolean);
      const rawName = nameParts.join(' - ');

      // Basic sanitization for filenames (remove invalid characters)
      const safeName = rawName.replace(/[\\/:*?"<>|]/g, ''); 

      if (safeName.length > 0) {
        filename = `${safeName}.csv`;
      }
    }

    // Pass current columnOrder to respect user's visual arrangement and filtering
    const csvContent = generateCSV(generatedData, columnOrder);
    downloadCSV(csvContent, filename);
  };

  return (
    <div className="min-h-screen flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <TableCellsIcon className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold text-gray-900 tracking-tight">CSV Builder</h1>
          </div>

          <div className="flex items-center gap-4">
             {generatedData.length > 0 && (
                <button
                  onClick={handleDownload}
                  disabled={!isMetadataComplete}
                  title={!isMetadataComplete ? "Please fill all manual context data to enable download" : "Download CSV"}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm ${
                    isMetadataComplete 
                      ? "bg-indigo-600 hover:bg-indigo-700 text-white" 
                      : "bg-gray-300 text-gray-500 cursor-not-allowed"
                  }`}
                >
                  <ArrowDownTrayIcon className="w-4 h-4" />
                  Download CSV
                </button>
             )}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 bg-gray-50 p-4 sm:p-6 lg:p-8">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-8rem)]">

          {/* Left Column: Context, Upload & Image */}
          <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-y-auto pr-2 custom-scrollbar">

            {/* 1. Metadata Form */}
            <section>
              <MetadataForm 
                metadata={metadata} 
                onChange={handleMetadataChange} 
                disabled={isLoading} 
              />
            </section>

            {/* 2. Content Source Tabs */}
            <section className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden flex flex-col min-h-[400px]">
              {/* Tab Header */}
              <div className="flex border-b border-gray-200">
                <button 
                  onClick={() => setActiveTab('upload')}
                  className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 transition-colors ${
                    activeTab === 'upload' 
                      ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' 
                      : 'bg-gray-50 text-gray-500 hover:text-gray-700 hover:bg-gray-100'
                  }`}
                >
                  <PhotoIcon className="w-4 h-4" />
                  Upload Image
                </button>
                <button 
                  onClick={() => setActiveTab('manual')}
                  className={`flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 transition-colors ${
                    activeTab === 'manual' 
                      ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' 
                      : 'bg-gray-50 text-gray-500 hover:text-gray-700 hover:bg-gray-100'
                  }`}
                >
                  <PencilSquareIcon className="w-4 h-4" />
                  Manual Entry
                </button>
              </div>

              {/* Tab Content */}
              <div className="flex-1 flex flex-col p-4 bg-gray-50/50">
                {activeTab === 'upload' ? (
                  <>
                    <h2 className="text-sm font-semibold text-gray-900 mb-4 uppercase tracking-wider">AI Extraction</h2>
                    <FileUpload 
                      onFileSelect={handleFileSelect} 
                      isLoading={isLoading} 
                      onCancel={handleCancel}
                      progress={progress}
                    />

                    {/* Error Message */}
                    {error && (
                      <div className="mt-4 bg-red-50 border border-red-200 rounded-xl p-4 flex items-start gap-3 text-red-700">
                        <ExclamationTriangleIcon className="w-5 h-5 flex-shrink-0 mt-0.5" />
                        <p className="text-sm">{error}</p>
                      </div>
                    )}

                    {/* Image Preview */}
                    {previewUrl && (
                      <div className="mt-6 flex-1 flex flex-col">
                        <div className="flex items-center justify-between mb-2">
                            <h2 className="text-sm font-semibold text-gray-900 uppercase tracking-wider">Source Image</h2>
                            <span className="text-xs text-gray-400">Click to expand</span>
                        </div>

                        <div 
                            className="relative flex-1 bg-gray-100 rounded-lg overflow-hidden border border-gray-200 group cursor-zoom-in min-h-[200px]"
                            onClick={() => setIsImageModalOpen(true)}
                        >
                          <img 
                            src={previewUrl} 
                            alt="Preview" 
                            className="absolute inset-0 w-full h-full object-contain"
                          />
                          <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors flex items-center justify-center">
                            <div className="bg-black/50 text-white p-2 rounded-full opacity-0 group-hover:opacity-100 transition-opacity transform scale-75 group-hover:scale-100">
                                <MagnifyingGlassPlusIcon className="w-6 h-6" />
                            </div>
                          </div>
                        </div>
                      </div>
                    )}
                  </>
                ) : (
                  <div className="h-full flex flex-col">
                    <ManualEntryForm 
                        onSubmit={handleManualEntrySubmit} 
                        initialData={generatedData.length > 0 ? generatedData[0] : undefined}
                    />
                  </div>
                )}
              </div>
            </section>

          </div>

          {/* Right Column: Table Preview */}
          <div className="lg:col-span-8 flex flex-col h-full">
            {generatedData.length > 0 ? (
              <TablePreview 
                data={generatedData} 
                columns={columnOrder} 
                onMoveColumn={handleMoveColumn}
                onEditHeader={handleEditHeader}
                onClear={handleClearTable}
              />
            ) : (
              <div className="flex-1 bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col items-center justify-center text-center p-12">
                <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mb-4">
                  <TableCellsIcon className="w-8 h-8 text-gray-300" />
                </div>
                <h3 className="text-lg font-medium text-gray-900">Ready to Process</h3>
                <p className="text-gray-500 max-w-sm mt-2">
                  Fill in the context details on the left, then either upload an image or manually enter content to generate the CSV.
                </p>
              </div>
            )}
          </div>

        </div>
      </main>

      {/* Image Modal (Lightbox) */}
      {isImageModalOpen && previewUrl && activeTab === 'upload' && (
        <div 
            className="fixed inset-0 z-[100] bg-black/90 flex items-center justify-center p-4 sm:p-8 backdrop-blur-sm"
            onClick={() => setIsImageModalOpen(false)}
        >
            <button 
                className="absolute top-4 right-4 bg-white/10 hover:bg-white/20 text-white rounded-full p-2 transition-colors"
                onClick={() => setIsImageModalOpen(false)}
            >
                <XMarkIcon className="w-8 h-8" />
            </button>
            <img 
                src={previewUrl} 
                alt="Full Size Source" 
                className="max-w-full max-h-full object-contain shadow-2xl rounded-sm"
                onClick={(e) => e.stopPropagation()} 
            />
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { CSVRow } from '../types';
import { 
  ScissorsIcon, 
  CheckCircleIcon,
  DocumentTextIcon,
  QuestionMarkCircleIcon,
  BookmarkIcon,
  KeyboardIcon
} from '@heroicons/react/24/outline';

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

interface SmartSplitterProps {
  onSubmit: (row: Partial<CSVRow>) => void;
  onClearTable?: () => void;
}

export const SmartSplitter: React.FC<SmartSplitterProps> = ({ onSubmit, onClearTable }) => {
  const [confirmedBlocks, setConfirmedBlocks] = useState<SplitBlock[]>([]);
  const [currentText, setCurrentText] = useState('');
  const [isNamingModalOpen, setIsNamingModalOpen] = useState(false);
  const [namingInput, setNamingInput] = useState('');
  const [splitIndex, setSplitIndex] = useState<number | null>(null);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const modalInputRef = useRef<HTMLInputElement>(null);

  // Focus modal input when opened
  useEffect(() => {
    if (isNamingModalOpen) {
      modalInputRef.current?.focus();
    }
  }, [isNamingModalOpen]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const target = e.target as HTMLTextAreaElement;
      const cursorPosition = target.selectionStart;

      setSplitIndex(cursorPosition);
      setIsNamingModalOpen(true);
      setNamingInput('');
    }
  };

  const handleModalKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      validateAndConfirm();
    }
  };

  const validateAndConfirm = () => {
    const input = namingInput.toLowerCase().trim();
    if (!input) return;

    // Rule 2: Validation of characters
    const validFirst = ['t', 'x', 'q'];
    const validSecond = ['d'];

    const firstChar = input[0];
    const secondChar = input[1];

    if (!validFirst.includes(firstChar)) {
      alert('Invalid type. Use "t" for Title, "x" for Text, or "q" for Question.');
      return;
    }

    if (secondChar && !validSecond.includes(secondChar)) {
      alert('Invalid completion. Only "d" is allowed as a second character.');
      return;
    }

    if (input.length > 2) {
      alert('Too many characters. Use "t/x/q" or "td/xd/qd".');
      return;
    }

    // Process the split
    if (splitIndex === null) return;

    const blockText = currentText.slice(0, splitIndex).trim();
    const remainingText = currentText.slice(splitIndex).trim();

    const newBlock: SplitBlock = {
      id: crypto.randomUUID(),
      type: firstChar as 't' | 'x' | 'q',
      text: blockText
    };

    setConfirmedBlocks([...confirmedBlocks, newBlock]);
    setCurrentText(remainingText);
    setIsNamingModalOpen(false);
    setSplitIndex(null);

    // Rule 1: Completion (Done)
    if (secondChar === 'd') {
      // Note: In a real scenario we'd also process the remaining text 
      // but the prompt implies the naming describes the text to the LEFT of split.
      // If 'd' is pressed, it means this was the last meaningful split.
      finalize(confirmedBlocks.concat(newBlock));
    }
  };

  const finalize = (blocksToProcess: SplitBlock[]) => {
    const row: Partial<CSVRow> = {};

    let textCount = 0;
    let questionCount = 0;

    blocksToProcess.forEach(block => {
      if (block.type === 't') {
        row.lesson_title = block.text;
      } else if (block.type === 'q') {
        questionCount++;
        const qKey = `question_${questionCount}` as keyof CSVRow;
        const iKey = `input_${questionCount}` as keyof CSVRow;
        if (questionCount <= 4) {
          (row as any)[qKey] = block.text;
          (row as any)[iKey] = ""; // Auto-add input
        }
      } else if (block.type === 'x') {
        textCount++;
        // Reusing the mapping logic from ManualEntryForm essentially
        if (questionCount === 0) {
          if (textCount === 1) row.text_1 = block.text;
          else if (textCount === 2) row.text_2 = block.text;
          else row.text_3 = (row.text_3 ? row.text_3 + '\n' : '') + block.text;
        } else if (questionCount === 1) {
          row.text_4 = (row.text_4 ? row.text_4 + '\n' : '') + block.text;
        } else if (questionCount === 2) {
          row.text_5 = (row.text_5 ? row.text_5 + '\n' : '') + block.text;
        } else if (questionCount === 3) {
          row.text_6 = (row.text_6 ? row.text_6 + '\n' : '') + block.text;
        } else if (questionCount >= 4) {
          if (!row.text_7) row.text_7 = block.text;
          else row.text_8 = (row.text_8 ? row.text_8 + '\n' : '') + block.text;
        }
      }
    });

    onSubmit(row);
    // Reset splitter
    setConfirmedBlocks([]);
    setCurrentText('');
  };

  const handleReset = () => {
    if (confirm("Reset current split session?")) {
        setConfirmedBlocks([]);
        setCurrentText('');
    }
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden relative">
      <div className="p-4 border-b border-gray-100 bg-gray-50 flex items-center justify-between">
        <div>
          <h3 className="text-sm font-semibold text-gray-900 uppercase tracking-wider flex items-center gap-2">
            <ScissorsIcon className="w-4 h-4 text-indigo-500" />
            Smart Splitter
          </h3>
          <p className="text-[10px] text-gray-500 mt-0.5">Paste text, position cursor, and press <b>Tab</b> to split.</p>
        </div>
        <button 
          onClick={handleReset}
          className="p-1.5 text-gray-400 hover:text-red-500 transition-colors"
          title="Reset"
        >
          <KeyboardIcon className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Confirmed Stack */}
        <div className="bg-gray-50 border-b border-gray-100 max-h-48 overflow-y-auto p-2 custom-scrollbar">
          {confirmedBlocks.length === 0 ? (
            <div className="py-4 text-center">
              <span className="text-xs text-gray-400 italic">No blocks split yet.</span>
            </div>
          ) : (
            <div className="space-y-1.5">
              {confirmedBlocks.map((block, idx) => (
                <div key={block.id} className="flex gap-2 items-start bg-white p-2 rounded border border-gray-200 shadow-sm animate-in slide-in-from-top-1">
                  <div className={`px-1.5 py-0.5 rounded text-[10px] font-bold uppercase ${
                    block.type === 't' ? 'bg-purple-100 text-purple-700' :
                    block.type === 'q' ? 'bg-orange-100 text-orange-700' :
                    'bg-blue-100 text-blue-700'
                  }`}>
                    {block.type === 't' ? 'Title' : block.type === 'q' ? 'Question' : 'Text'}
                  </div>
                  <p className="text-[11px] text-gray-600 line-clamp-2">{block.text}</p>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Workspace */}
        <div className="flex-1 p-4 relative group">
          <textarea
            ref={textareaRef}
            className="w-full h-full resize-none border-none focus:ring-0 text-sm leading-relaxed text-gray-800 placeholder-gray-300 custom-scrollbar"
            placeholder="Paste document text here..."
            value={currentText}
            onChange={(e) => setCurrentText(e.target.value)}
            onKeyDown={handleKeyDown}
          />

          <div className="absolute bottom-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
            <div className="bg-indigo-600 text-white px-2 py-1 rounded text-[10px] font-medium shadow-lg flex items-center gap-1.5">
                <KeyboardIcon className="w-3 h-3" />
                Press TAB to categorize selection
            </div>
          </div>
        </div>
      </div>

      {/* Modal Overlay */}
      {isNamingModalOpen && (
        <div className="absolute inset-0 bg-gray-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white rounded-2xl shadow-2xl border border-indigo-100 w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-200">
            <div className="bg-indigo-600 px-6 py-4 flex items-center justify-between">
              <h4 className="text-white font-bold text-sm tracking-wide uppercase">Classify Block</h4>
              <div className="bg-white/20 px-2 py-0.5 rounded text-[10px] text-white font-mono">
                [ENTER] TO VALIDATE
              </div>
            </div>

            <div className="p-6">
               <div className="relative mb-6">
                  <input
                    ref={modalInputRef}
                    type="text"
                    className="w-full bg-gray-50 border-2 border-indigo-100 rounded-xl px-4 py-3 text-2xl font-bold text-indigo-600 text-center uppercase focus:border-indigo-500 focus:ring-0 transition-all placeholder-gray-200"
                    placeholder="T, X, or Q"
                    maxLength={2}
                    value={namingInput}
                    onChange={(e) => setNamingInput(e.target.value)}
                    onKeyDown={handleModalKeyDown}
                  />
                  <div className="absolute -bottom-6 left-0 right-0 text-center text-[10px] text-gray-400 font-medium">
                    Add "D" to finish (e.g. "QD")
                  </div>
               </div>

               <div className="grid grid-cols-3 gap-2 mt-8">
                  <div className="text-center p-2 rounded-lg border border-gray-100 bg-gray-50/50">
                    <div className="text-sm font-bold text-indigo-600">T</div>
                    <div className="text-[10px] text-gray-500 uppercase">Title</div>
                  </div>
                  <div className="text-center p-2 rounded-lg border border-gray-100 bg-gray-50/50">
                    <div className="text-sm font-bold text-indigo-600">X</div>
                    <div className="text-[10px] text-gray-500 uppercase">Text</div>
