import React, { useState, useRef, useMemo } from 'react';
import { FileUpload } from './components/FileUpload';
import { TablePreview } from './components/TablePreview';
import { MetadataForm } from './components/MetadataForm';
import { ManualEntryForm } from './components/ManualEntryForm';
import { SmartSplitter } from './components/SmartSplitter';
import { processImageWithGemini } from './services/geminiService';
import { generateCSV, downloadCSV, DEFAULT_HEADERS } from './utils/csvHelper';
import { CSVRow, StudyMetadata } from './types';
import { 
  ArrowDownTrayIcon, 
  TableCellsIcon, 
  ExclamationTriangleIcon, 
  MagnifyingGlassPlusIcon, 
  XMarkIcon,
  PhotoIcon,
  PencilSquareIcon,
  ScissorsIcon
} from '@heroicons/react/24/outline';

// Standard Day Mapping
// Updated: 1=Saturday, 2=Sunday, 3=Monday, ..., 7=Friday
const DAY_MAP: Record<string, string> = {
  '1': 'Saturday',
  '2': 'Sunday',
  '3': 'Monday',
  '4': 'Tuesday',
  '5': 'Wednesday',
  '6': 'Thursday',
  '7': 'Friday',
};

const App: React.FC = () => {
  // State for manual metadata
  const [metadata, setMetadata] = useState<StudyMetadata>({
    week_number: '',
    week_title: '',
    day_number: '',
    day_name: '',
    language: ''
  });

  const [activeTab, setActiveTab] = useState<'upload' | 'manual' | 'smart'>('upload');

  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isImageModalOpen, setIsImageModalOpen] = useState(false); // State for Lightbox
  const [generatedData, setGeneratedData] = useState<CSVRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [progress, setProgress] = useState(0); // State for progress bar
  const [error, setError] = useState<string | null>(null);

  // Manage column order in state so user can change it
  const [columnOrder, setColumnOrder] = useState<(keyof CSVRow)[]>(DEFAULT_HEADERS);

  // Ref to hold the AbortController
  const abortControllerRef = useRef<AbortController | null>(null);

  // Check if all metadata fields are filled
  const isMetadataComplete = useMemo(() => {
    return Object.values(metadata).every(val => typeof val === 'string' && val.trim().length > 0);
  }, [metadata]);

  const handleMetadataChange = (field: keyof StudyMetadata, value: string) => {
    setMetadata(prev => {
      const updated = { ...prev, [field]: value };

      // Synchronization Logic: Day Number <-> Day Name
      if (field === 'day_number') {
        const mappedName = DAY_MAP[value];
        if (mappedName) {
          updated.day_name = mappedName;
        }
      } else if (field === 'day_name') {
        // Find key by value
        const mappedNumber = Object.keys(DAY_MAP).find(key => DAY_MAP[key] === value);
        if (mappedNumber) {
          updated.day_number = mappedNumber;
        }
      }

      // If we already have data, update it in real-time
      if (generatedData.length > 0) {
        setGeneratedData(currentRows => currentRows.map(row => ({
          ...row,
          ...updated
        })));
      }

      return updated;
    });
  };

  const updateTableData = (newRows: CSVRow[]) => {
      // AUTOMATIC COLUMN CLEANUP
      const metadataKeys: (keyof StudyMetadata)[] = ['week_number', 'week_title', 'day_number', 'day_name', 'language'];

      // 1. Identify which columns have actual content anywhere in the dataset
      const columnsWithData = new Set<keyof CSVRow>();
      DEFAULT_HEADERS.forEach(header => {
        const hasContent = newRows.some(row => {
            const val = row[header];
            return val && String(val).trim().length > 0;
        });
        if (hasContent) {
            columnsWithData.add(header);
        }
      });

      // 2. Filter headers based on rules
      const activeHeaders = DEFAULT_HEADERS.filter(header => {
        // Rule A: Always keep metadata columns (as they are manually editable)
        if (metadataKeys.includes(header as any)) return true;

        // Rule B: Special dependency for Input columns (Dynamic Check)
        // Checks if header is 'input_X' and requires 'question_X' to be present
        if (typeof header === 'string' && header.startsWith('input_')) {
            const parts = header.split('_');
            if (parts.length === 2) {
                const number = parts[1];
                const correspondingQuestion = `question_${number}` as keyof CSVRow;
                return columnsWithData.has(correspondingQuestion);
            }
        }

        // Rule C: For all other columns (Text, Questions), keep only if they have data
        return columnsWithData.has(header);
      });

      setColumnOrder(activeHeaders);
      setGeneratedData(newRows);
  };

  const handleMoveColumn = (index: number, direction: 'left' | 'right') => {
    if (direction === 'left' && index === 0) return;
    if (direction === 'right' && index === columnOrder.length - 1) return;

    const newOrder = [...columnOrder];
    const targetIndex = direction === 'left' ? index - 1 : index + 1;

    // Swap
    [newOrder[index], newOrder[targetIndex]] = [newOrder[targetIndex], newOrder[index]];

    setColumnOrder(newOrder);
  };

  const handleEditHeader = (key: keyof CSVRow) => {
    // Switch to manual mode for fine-tuning
    setActiveTab('manual');
  };

  const handleCancel = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
      abortControllerRef.current = null;
    }
    setIsLoading(false);
    setProgress(0);
    setError(null);
  };

  const handleClearTable = () => {
    if (confirm("Are you sure you want to clear the generated table data?")) {
        setGeneratedData([]);
        setPreviewUrl(null);
        setError(null);
    }
  };

  const handleManualEntrySubmit = (partialRow: Partial<CSVRow>) => {
    const completeRow: CSVRow = {
        ...partialRow,
        ...metadata
    } as CSVRow;
    updateTableData([completeRow]);
    setError(null);
  };

  const handleFileSelect = async (base64: string, preview: string) => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
    const controller = new AbortController();
    abortControllerRef.current = controller;

    setPreviewUrl(preview);
    setGeneratedData([]);
    setError(null);
    setIsLoading(true);
    setProgress(0);

    try {
      const extractedRows = await processImageWithGemini(
        base64, 
        controller.signal, 
        (percent) => setProgress(percent)
      );
      setProgress(100);
      const completeRows: CSVRow[] = extractedRows.map((row: any) => ({
        ...row,
        ...metadata 
      }));
      updateTableData(completeRows);
    } catch (err: any) {
      if (err.name === 'AbortError') {
        console.log("Process cancelled by user");
      } else {
        setError(err.message || "Failed to process image");
      }
      setProgress(0);
    } finally {
      if (abortControllerRef.current === controller) {
        setIsLoading(false);
        abortControllerRef.current = null;
      }
    }
  };

  const handleDownload = () => {
    if (generatedData.length === 0) return;
    if (!isMetadataComplete) {
      alert("Please fill in all Manual Context Data fields before exporting.");
      return;
    }
    let filename = 'study-guide-export.csv';
    const wTitle = metadata.week_title?.trim();
    const dName = metadata.day_name?.trim();
    if (wTitle || dName) {
      const nameParts = [wTitle, dName].filter(Boolean);
      const rawName = nameParts.join(' - ');
      const safeName = rawName.replace(/[\\/:*?"<>|]/g, ''); 
      if (safeName.length > 0) filename = `${safeName}.csv`;
    }
    const csvContent = generateCSV(generatedData, columnOrder);
    downloadCSV(csvContent, filename);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <TableCellsIcon className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold text-gray-900 tracking-tight">CSV Builder</h1>
          </div>
          <div className="flex items-center gap-4">
             {generatedData.length > 0 && (
                <button
                  onClick={handleDownload}
                  disabled={!isMetadataComplete}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm ${
                    isMetadataComplete ? "bg-indigo-600 hover:bg-indigo-700 text-white" : "bg-gray-300 text-gray-500 cursor-not-allowed"
                  }`}
                >
                  <ArrowDownTrayIcon className="w-4 h-4" />
                  Download CSV
                </button>
             )}
          </div>
        </div>
      </header>

      <main className="flex-1 bg-gray-50 p-4 sm:p-6 lg:p-8">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-8rem)]">
          <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-y-auto pr-2 custom-scrollbar">
            <MetadataForm metadata={metadata} onChange={handleMetadataChange} disabled={isLoading} />
            <section className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden flex flex-col min-h-[400px]">
              <div className="flex border-b border-gray-200">
                <button onClick={() => setActiveTab('upload')} className={`flex-1 py-3 text-[10px] font-bold uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'upload' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'bg-gray-50 text-gray-500 hover:text-gray-700 hover:bg-gray-100'}`}>
                  <PhotoIcon className="w-3.5 h-3.5" /> Image
                </button>
                <button onClick={() => setActiveTab('manual')} className={`flex-1 py-3 text-[10px] font-bold uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'manual' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'bg-gray-50 text-gray-500 hover:text-gray-700 hover:bg-gray-100'}`}>
                  <PencilSquareIcon className="w-3.5 h-3.5" /> Manual
                </button>
                <button onClick={() => setActiveTab('smart')} className={`flex-1 py-3 text-[10px] font-bold uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'smart' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'bg-gray-50 text-gray-500 hover:text-gray-700 hover:bg-gray-100'}`}>
                  <ScissorsIcon className="w-3.5 h-3.5" /> Smart Split
                </button>
              </div>
              <div className="flex-1 flex flex-col p-4 bg-gray-50/50 overflow-hidden">
                {activeTab === 'upload' && (
                  <div className="h-full overflow-y-auto custom-scrollbar">
                    <h2 className="text-xs font-semibold text-gray-900 mb-4 uppercase tracking-widest">AI Extraction</h2>
                    <FileUpload onFileSelect={handleFileSelect} isLoading={isLoading} onCancel={handleCancel} progress={progress} />
                    {error && <div className="mt-4 bg-red-50 border border-red-200 rounded-xl p-4 flex items-start gap-3 text-red-700"><ExclamationTriangleIcon className="w-5 h-5 flex-shrink-0 mt-0.5" /><p className="text-sm">{error}</p></div>}
                    {previewUrl && (
                      <div className="mt-6">
                        <h2 className="text-[10px] font-bold text-gray-400 mb-2 uppercase tracking-widest">Source Image</h2>
                        <div className="relative bg-gray-100 rounded-lg overflow-hidden border border-gray-200 group cursor-zoom-in h-40" onClick={() => setIsImageModalOpen(true)}>
                          <img src={previewUrl} alt="Preview" className="absolute inset-0 w-full h-full object-contain" />
                          <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors flex items-center justify-center">
                            <MagnifyingGlassPlusIcon className="w-6 h-6 text-white opacity-0 group-hover:opacity-100 transition-opacity" />
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                )}
                {activeTab === 'manual' && <ManualEntryForm onSubmit={handleManualEntrySubmit} initialData={generatedData.length > 0 ? generatedData[0] : undefined} />}
                {activeTab === 'smart' && <SmartSplitter onSubmit={handleManualEntrySubmit} onClearTable={handleClearTable} />}
              </div>
            </section>
          </div>
          <div className="lg:col-span-8 flex flex-col h-full overflow-hidden">
            {generatedData.length > 0 ? <TablePreview data={generatedData} columns={columnOrder} onMoveColumn={handleMoveColumn} onEditHeader={handleEditHeader} onClear={handleClearTable} /> : (
              <div className="flex-1 bg-white rounded-xl shadow-sm border border-gray-200 flex flex-col items-center justify-center text-center p-12">
                <div className="w-16 h-16 bg-gray-50 rounded-full flex items-center justify-center mb-4"><TableCellsIcon className="w-8 h-8 text-gray-300" /></div>
                <h3 className="text-lg font-medium text-gray-900 tracking-tight">Ready to Process</h3>
                <p className="text-gray-400 max-w-sm mt-2 text-sm">Fill in context on the left, then use Upload, Manual entry, or Smart Split to generate your table.</p>
              </div>
            )}
          </div>
        </div>
      </main>
      {isImageModalOpen && previewUrl && activeTab === 'upload' && (
        <div className="fixed inset-0 z-[100] bg-black/90 flex items-center justify-center p-4 sm:p-8 backdrop-blur-sm" onClick={() => setIsImageModalOpen(false)}>
          <button className="absolute top-4 right-4 bg-white/10 hover:bg-white/20 text-white rounded-full p-2 transition-colors"><XMarkIcon className="w-8 h-8" /></button>
          <img src={previewUrl} alt="Full Size" className="max-w-full max-h-full object-contain shadow-2xl rounded-sm" onClick={(e) => e.stopPropagation()} />
        </div>
      )}
    </div>
  );
};

