import React, { useState, useRef, useEffect } from 'react';
import { CSVRow } from '../types';
import { 
  ScissorsIcon, 
  CheckCircleIcon,
  DocumentTextIcon,
  QuestionMarkCircleIcon,
  CommandLineIcon,
  ArrowPathIcon
} from '@heroicons/react/24/outline';

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

interface SmartSplitterProps {
  onSubmit: (row: Partial<CSVRow>) => void;
  onClearTable?: () => void;
}

export const SmartSplitter: React.FC<SmartSplitterProps> = ({ onSubmit, onClearTable }) => {
  const [confirmedBlocks, setConfirmedBlocks] = useState<SplitBlock[]>([]);
  const [currentText, setCurrentText] = useState('');
  const [isNamingModalOpen, setIsNamingModalOpen] = useState(false);
  const [namingInput, setNamingInput] = useState('');
  const [splitIndex, setSplitIndex] = useState<number | null>(null);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const modalInputRef = useRef<HTMLInputElement>(null);

  // Focus modal input when opened
  useEffect(() => {
    if (isNamingModalOpen) {
      modalInputRef.current?.focus();
    }
  }, [isNamingModalOpen]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const target = e.target as HTMLTextAreaElement;
      const cursorPosition = target.selectionStart;

      // We only allow splitting if there is text to the left
      if (cursorPosition === 0 && currentText.length > 0) return;

      setSplitIndex(cursorPosition);
      setIsNamingModalOpen(true);
      setNamingInput('');
    }
  };

  const handleModalKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    // Only allow specific keys as per requirement: t, x, q, d, and Enter
    const validKeys = ['t', 'x', 'q', 'd', 'backspace', 'enter', 'arrowleft', 'arrowright'];
    if (!validKeys.includes(e.key.toLowerCase())) {
      // We still allow standard navigation keys but block other characters
      if (e.key.length === 1) {
        e.preventDefault();
        return;
      }
    }

    if (e.key === 'Enter') {
      e.preventDefault();
      validateAndConfirm();
    }
  };

  const validateAndConfirm = () => {
    const input = namingInput.toLowerCase(); // requirement: lowercase
    if (!input) return;

    // Rule 2: Validation of characters
    const validFirst = ['t', 'x', 'q'];
    const validSecond = ['d'];

    const firstChar = input[0];
    const secondChar = input[1];

    if (!validFirst.includes(firstChar)) {
      alert('Invalid type. Use "t" for Title, "x" for Text, or "q" for Question.');
      return;
    }

    if (secondChar && !validSecond.includes(secondChar)) {
      alert('Invalid completion. Only "d" is allowed as a second character.');
      return;
    }

    // Process the split
    if (splitIndex === null) return;

    // Rule 1: The text to the LEFT of the cursor becomes the block
    const blockText = currentText.slice(0, splitIndex).trim();
    const remainingText = currentText.slice(splitIndex).trim();

    // Check "done" condition: cursor must be at the end (or only whitespace remaining)
    if (secondChar === 'd' && remainingText.length > 0) {
      alert('The "d" (done) tag is only valid when splitting at the very end of the text.');
      return;
    }

    const newBlock: SplitBlock = {
      id: crypto.randomUUID(),
      type: firstChar as 't' | 'x' | 'q',
      text: blockText
    };

    const updatedBlocks = [...confirmedBlocks, newBlock];
    setConfirmedBlocks(updatedBlocks);
    setCurrentText(remainingText);
    setIsNamingModalOpen(false);
    setSplitIndex(null);

    // If 'd' was used, finish the whole thing
    if (secondChar === 'd') {
      finalize(updatedBlocks);
    }
  };

  const finalize = (blocksToProcess: SplitBlock[]) => {
    const row: Partial<CSVRow> = {};

    let textCount = 0;
    let questionCount = 0;

    blocksToProcess.forEach(block => {
      if (block.type === 't') {
        row.lesson_title = block.text;
      } else if (block.type === 'q') {
        questionCount++;
        const qKey = `question_${questionCount}` as keyof CSVRow;
        const iKey = `input_${questionCount}` as keyof CSVRow;
        if (questionCount <= 4) {
          (row as any)[qKey] = block.text;
          (row as any)[iKey] = ""; // Requirement: "after each block of Question, include an input field"
        }
      } else if (block.type === 'x') {
        textCount++;
        // Sequence mapping to match CSV structure
        if (questionCount === 0) {
          if (textCount === 1) row.text_1 = block.text;
          else if (textCount === 2) row.text_2 = block.text;
          else row.text_3 = (row.text_3 ? row.text_3 + '\n' : '') + block.text;
        } else if (questionCount === 1) {
          row.text_4 = (row.text_4 ? row.text_4 + '\n' : '') + block.text;
        } else if (questionCount === 2) {
          row.text_5 = (row.text_5 ? row.text_5 + '\n' : '') + block.text;
        } else if (questionCount === 3) {
          row.text_6 = (row.text_6 ? row.text_6 + '\n' : '') + block.text;
        } else if (questionCount >= 4) {
          if (!row.text_7) row.text_7 = block.text;
          else row.text_8 = (row.text_8 ? row.text_8 + '\n' : '') + block.text;
        }
      }
    });

    onSubmit(row);
    // Reset splitter for next use
    setConfirmedBlocks([]);
    setCurrentText('');
  };

  const handleReset = () => {
    if (confirm("Clear all text and reset the split session?")) {
        setConfirmedBlocks([]);
        setCurrentText('');
    }
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden relative">
      <div className="p-4 border-b border-gray-100 bg-gray-50 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-100 p-2 rounded-lg">
            <ScissorsIcon className="w-5 h-5 text-indigo-600" />
          </div>
          <div>
            <h3 className="text-sm font-bold text-gray-900 uppercase tracking-tight">Smart Splitter</h3>
            <p className="text-[10px] text-gray-500 font-medium">Position cursor and press <kbd className="bg-gray-200 px-1 rounded shadow-sm">TAB</kbd></p>
          </div>
        </div>
        <button 
          onClick={handleReset}
          className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-all"
          title="Clear everything"
        >
          <ArrowPathIcon className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Confirmed Stack - Visual feedback of what has been split */}
        <div className="bg-gray-50 border-b border-gray-100 max-h-40 overflow-y-auto p-3 custom-scrollbar">
          {confirmedBlocks.length === 0 ? (
            <div className="py-2 text-center">
              <span className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Workspace Empty</span>
            </div>
          ) : (
            <div className="flex flex-wrap gap-2">
              {confirmedBlocks.map((block) => (
                <div key={block.id} className="flex items-center gap-2 bg-white px-2 py-1 rounded-md border border-gray-200 shadow-sm transition-all hover:border-indigo-200">
                  <span className={`text-[9px] font-black px-1 rounded ${
                    block.type === 't' ? 'bg-purple-600 text-white' :
                    block.type === 'q' ? 'bg-orange-500 text-white' :
                    'bg-blue-500 text-white'
                  }`}>
                    {block.type.toUpperCase()}
                  </span>
                  <span className="text-[10px] text-gray-600 truncate max-w-[100px]">{block.text}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Workspace - The "Big Block" */}
        <div className="flex-1 p-5 relative group bg-white">
          <textarea
            ref={textareaRef}
            className="w-full h-full resize-none border-none focus:ring-0 text-sm leading-relaxed text-gray-800 placeholder-gray-200 custom-scrollbar font-normal"
            placeholder="Paste your original text here and start splitting with TAB..."
            value={currentText}
            onChange={(e) => setCurrentText(e.target.value)}
            onKeyDown={handleKeyDown}
          />

          <div className="absolute bottom-6 right-6 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
            <div className="bg-indigo-600 text-white px-3 py-1.5 rounded-full text-[10px] font-bold shadow-xl flex items-center gap-2">
                <CommandLineIcon className="w-3.5 h-3.5" />
                TAB TO SPLIT & NAME
            </div>
          </div>
        </div>
      </div>

      {/* Split Naming Modal */}
      {isNamingModalOpen && (
        <div className="absolute inset-0 bg-gray-900/60 backdrop-blur-sm z-[60] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white rounded-3xl shadow-2xl border border-indigo-100 w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-200">
