               </div>

               <div className="grid grid-cols-3 gap-3">
                  <div className={`text-center p-3 rounded-2xl border transition-all ${namingInput.toLowerCase().startsWith('t') ? 'bg-purple-600 border-purple-600 scale-105' : 'bg-gray-50 border-gray-100'}`}>
