import React, { useState, useRef, useEffect } from 'react';
import { CSVRow } from '../types';
import { 
  ScissorsIcon, 
  CommandLineIcon,
  ArrowPathIcon,
  CheckIcon,
  DocumentTextIcon,
  QuestionMarkCircleIcon,
  HashtagIcon
} from '@heroicons/react/24/outline';

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

interface SmartSplitterProps {
  onSubmit: (row: Partial<CSVRow>) => void;
  onClearTable?: () => void;
}

export const SmartSplitter: React.FC<SmartSplitterProps> = ({ onSubmit, onClearTable }) => {
  const [confirmedBlocks, setConfirmedBlocks] = useState<SplitBlock[]>([]);
  const [currentText, setCurrentText] = useState('');
  const [isNamingModalOpen, setIsNamingModalOpen] = useState(false);
  const [namingInput, setNamingInput] = useState('');
  const [splitIndex, setSplitIndex] = useState<number | null>(null);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const modalInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isNamingModalOpen) {
      modalInputRef.current?.focus();
    }
  }, [isNamingModalOpen]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const target = e.target as HTMLTextAreaElement;
      const cursorPosition = target.selectionStart;
      if (cursorPosition === 0 && currentText.length > 0) return;

      setSplitIndex(cursorPosition);
      setIsNamingModalOpen(true);
      setNamingInput('');
    }
  };

  const handleModalKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    const validKeys = ['t', 'x', 'q', 'd', 'backspace', 'enter', 'arrowleft', 'arrowright'];
    if (!validKeys.includes(e.key.toLowerCase()) && e.key.length === 1) {
      e.preventDefault();
      return;
    }
    if (e.key === 'Enter') {
      e.preventDefault();
      validateAndConfirm();
    }
    if (e.key === 'Escape') {
      setIsNamingModalOpen(false);
    }
  };

  const validateAndConfirm = () => {
    const input = namingInput.toLowerCase();
    if (!input) return;

    const validFirst = ['t', 'x', 'q'];
    const validSecond = ['d'];
    const firstChar = input[0];
    const secondChar = input[1];

    if (!validFirst.includes(firstChar)) return;
    if (secondChar && !validSecond.includes(secondChar)) return;

    if (splitIndex === null) return;

    const blockText = currentText.slice(0, splitIndex).trim();
    const remainingText = currentText.slice(splitIndex).trim();

    if (secondChar === 'd' && remainingText.length > 0) {
      alert('O comando "d" só é válido ao dividir no final do texto.');
      return;
    }

    const newBlock: SplitBlock = {
      id: crypto.randomUUID(),
      type: firstChar as 't' | 'x' | 'q',
      text: blockText
    };

    const updatedBlocks = [...confirmedBlocks, newBlock];
    setConfirmedBlocks(updatedBlocks);
    setCurrentText(remainingText);
    setIsNamingModalOpen(false);
    setSplitIndex(null);

    if (secondChar === 'd') {
      finalize(updatedBlocks);
    }
  };

  const finalize = (blocksToProcess: SplitBlock[]) => {
    const row: Partial<CSVRow> = {};
    let textCount = 0;
    let questionCount = 0;

    blocksToProcess.forEach(block => {
      if (block.type === 't') {
        row.lesson_title = block.text;
      } else if (block.type === 'q') {
        questionCount++;
        const qKey = `question_${questionCount}` as keyof CSVRow;
        const iKey = `input_${questionCount}` as keyof CSVRow;
        if (questionCount <= 4) {
          (row as any)[qKey] = block.text;
          (row as any)[iKey] = "";
        }
      } else if (block.type === 'x') {
        textCount++;
        if (questionCount === 0) {
          if (textCount === 1) row.text_1 = block.text;
          else if (textCount === 2) row.text_2 = block.text;
          else row.text_3 = (row.text_3 ? row.text_3 + '\n' : '') + block.text;
        } else if (questionCount === 1) {
          row.text_4 = (row.text_4 ? row.text_4 + '\n' : '') + block.text;
        } else if (questionCount === 2) {
          row.text_5 = (row.text_5 ? row.text_5 + '\n' : '') + block.text;
        } else if (questionCount === 3) {
          row.text_6 = (row.text_6 ? row.text_6 + '\n' : '') + block.text;
        } else if (questionCount >= 4) {
          if (!row.text_7) row.text_7 = block.text;
          else row.text_8 = (row.text_8 ? row.text_8 + '\n' : '') + block.text;
        }
      }
    });

    onSubmit(row);
    setConfirmedBlocks([]);
    setCurrentText('');
  };

  return (
    <div className="flex flex-col h-[640px] bg-white rounded-2xl shadow-xl border border-gray-200 overflow-hidden relative">
      {/* Header Estilizado */}
      <div className="px-5 py-4 bg-gray-50 border-b border-gray-200 flex items-center justify-between">
        <div className="flex items-center gap-3">
          <div className="bg-indigo-600 p-2 rounded-xl shadow-indigo-200 shadow-lg">
            <ScissorsIcon className="w-5 h-5 text-white" />
          </div>
          <div>
            <h3 className="text-sm font-bold text-gray-900 tracking-tight">Smart Splitter</h3>
            <div className="flex items-center gap-2 mt-0.5">
              <span className="flex items-center gap-1 text-[10px] text-gray-400 font-semibold uppercase tracking-wider">
                <kbd className="bg-white border border-gray-300 px-1 rounded shadow-sm">TAB</kbd> para dividir
              </span>
            </div>
          </div>
        </div>
        <button 
          onClick={() => confirm("Limpar tudo?") && (setConfirmedBlocks([]), setCurrentText(''))}
          className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
        >
          <ArrowPathIcon className="w-5 h-5" />
        </button>
      </div>

      <div className="flex-1 flex flex-col overflow-hidden bg-white">
        {/* Histórico de Blocos - Visual Timeline */}
        <div className="bg-gray-50/50 border-b border-gray-100 p-4 max-h-48 overflow-y-auto custom-scrollbar">
          {confirmedBlocks.length === 0 ? (
            <div className="py-2 flex flex-col items-center justify-center opacity-30">
              <CommandLineIcon className="w-8 h-8 text-gray-400" />
              <span className="text-[10px] font-bold uppercase mt-2 tracking-widest text-gray-500">Aguardando entrada...</span>
            </div>
          ) : (
            <div className="space-y-3">
              {confirmedBlocks.map((block, idx) => (
                <div key={block.id} className="flex gap-4 items-start animate-in slide-in-from-left-2 duration-300">
                  <div className="flex flex-col items-center h-full pt-1">
                    <div className={`w-6 h-6 rounded-full flex items-center justify-center shadow-sm ${
                      block.type === 't' ? 'bg-purple-600' :
                      block.type === 'q' ? 'bg-amber-500' :
                      'bg-blue-600'
                    }`}>
                      <CheckIcon className="w-3.5 h-3.5 text-white" />
                    </div>
                    {idx < confirmedBlocks.length - 1 && <div className="w-0.5 flex-1 bg-gray-200 my-1 rounded-full"></div>}
                  </div>
                  <div className="flex-1 bg-white border border-gray-100 rounded-xl p-3 shadow-sm hover:border-indigo-200 transition-colors">
                    <div className="flex items-center justify-between mb-1">
                      <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-full ${
                        block.type === 't' ? 'bg-purple-100 text-purple-700' :
                        block.type === 'q' ? 'bg-amber-100 text-amber-700' :
                        'bg-blue-100 text-blue-700'
                      }`}>
                        {block.type === 't' ? 'Título' : block.type === 'q' ? 'Pergunta' : 'Texto'}
                      </span>
                      <span className="text-[9px] text-gray-300 font-mono">#{idx + 1}</span>
                    </div>
                    <p className="text-[11px] text-gray-600 leading-relaxed line-clamp-2">{block.text}</p>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Editor de Texto Principal */}
        <div className="flex-1 p-6 relative">
          <textarea
            ref={textareaRef}
            className="w-full h-full resize-none border-none focus:ring-0 text-base leading-relaxed text-gray-700 placeholder-gray-200 custom-scrollbar font-normal selection:bg-indigo-100 selection:text-indigo-900"
            placeholder="Cole o texto original aqui... Use TAB para separar por categorias."
            value={currentText}
            onChange={(e) => setCurrentText(e.target.value)}
            onKeyDown={handleKeyDown}
          />
        </div>
      </div>

      {/* Modal - Command Palette Style */}
      {isNamingModalOpen && (
        <div className="absolute inset-0 bg-gray-900/40 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white rounded-[2rem] shadow-2xl border border-white/20 w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-8">
              <div className="flex items-center justify-center gap-3 mb-6">
                <div className="h-10 w-10 bg-indigo-50 rounded-2xl flex items-center justify-center">
                  <CommandLineIcon className="w-6 h-6 text-indigo-600" />
                </div>
                <h4 className="text-gray-900 font-bold text-sm uppercase tracking-widest">Classificar Bloco</h4>
              </div>

              <div className="relative group">
                <input
                  ref={modalInputRef}
                  type="text"
                  className="w-full bg-gray-50 border-2 border-gray-100 rounded-3xl px-4 py-6 text-5xl font-black text-indigo-600 text-center uppercase focus:border-indigo-500 focus:bg-white focus:ring-0 transition-all placeholder-gray-200 shadow-inner"
                  placeholder="?"
                  maxLength={2}
                  value={namingInput}
                  onChange={(e) => setNamingInput(e.target.value)}
                  onKeyDown={handleModalKeyDown}
                />
              </div>

              <div className="mt-8 grid grid-cols-3 gap-3">
                <div className={`p-4 rounded-2xl border-2 transition-all text-center ${namingInput.toLowerCase().startsWith('t') ? 'bg-purple-600 border-purple-400 shadow-lg shadow-purple-200' : 'bg-white border-gray-50'}`}>
                   <span className={`block text-xl font-black ${namingInput.toLowerCase().startsWith('t') ? 'text-white' : 'text-purple-600'}`}>T</span>
                   <span className={`text-[8px] font-bold uppercase tracking-tighter ${namingInput.toLowerCase().startsWith('t') ? 'text-purple-100' : 'text-gray-400'}`}>Título</span>
                </div>
                <div className={`p-4 rounded-2xl border-2 transition-all text-center ${namingInput.toLowerCase().startsWith('x') ? 'bg-blue-600 border-blue-400 shadow-lg shadow-blue-200' : 'bg-white border-gray-50'}`}>
                   <span className={`block text-xl font-black ${namingInput.toLowerCase().startsWith('x') ? 'text-white' : 'text-blue-600'}`}>X</span>
                   <span className={`text-[8px] font-bold uppercase tracking-tighter ${namingInput.toLowerCase().startsWith('x') ? 'text-blue-100' : 'text-gray-400'}`}>Texto</span>
                </div>
                <div className={`p-4 rounded-2xl border-2 transition-all text-center ${namingInput.toLowerCase().startsWith('q') ? 'bg-amber-500 border-amber-400 shadow-lg shadow-amber-200' : 'bg-white border-gray-50'}`}>
                   <span className={`block text-xl font-black ${namingInput.toLowerCase().startsWith('q') ? 'text-white' : 'text-amber-600'}`}>Q</span>
                   <span className={`text-[8px] font-bold uppercase tracking-tighter ${namingInput.toLowerCase().startsWith('q') ? 'text-amber-100' : 'text-gray-400'}`}>Pergunta</span>
                </div>
