} from '@heroicons/react/24/outline';

const DAY_MAP: Record<string, string> = {
  '1': 'Saturday',
  '2': 'Sunday',
  '3': 'Monday',
  '4': 'Tuesday',
  '5': 'Wednesday',
  '6': 'Thursday',
  '7': 'Friday',
};

// Interface para os blocos temporários do Smart Split
interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

const App: React.FC = () => {
  const [metadata, setMetadata] = useState<StudyMetadata>({
    week_number: '',
    week_title: '',
    day_number: '',
    day_name: '',
    language: ''
  });

  const [activeTab, setActiveTab] = useState<'upload' | 'manual' | 'smart'>('upload');
  const [previewUrl, setPreviewUrl] = useState<string | null>(null);
  const [isImageModalOpen, setIsImageModalOpen] = useState(false);
  const [generatedData, setGeneratedData] = useState<CSVRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [columnOrder, setColumnOrder] = useState<(keyof CSVRow)[]>(DEFAULT_HEADERS);

  // Estado compartilhado para os blocos do Smart Split
  const [smartBlocks, setSmartBlocks] = useState<SplitBlock[]>([]);

  const abortControllerRef = useRef<AbortController | null>(null);

  const isMetadataComplete = useMemo(() => {
    return Object.values(metadata).every(val => typeof val === 'string' && val.trim().length > 0);
  }, [metadata]);

  const handleMetadataChange = (field: keyof StudyMetadata, value: string) => {
    setMetadata(prev => {
      const updated = { ...prev, [field]: value };
      if (field === 'day_number') {
        const mappedName = DAY_MAP[value];
        if (mappedName) updated.day_name = mappedName;
      } else if (field === 'day_name') {
        const mappedNumber = Object.keys(DAY_MAP).find(key => DAY_MAP[key] === value);
        if (mappedNumber) updated.day_number = mappedNumber;
      }
      if (generatedData.length > 0) {
        setGeneratedData(currentRows => currentRows.map(row => ({ ...row, ...updated })));
      }
      return updated;
    });
  };

  const updateTableData = (newRows: CSVRow[]) => {
      const metadataKeys: (keyof StudyMetadata)[] = ['week_number', 'week_title', 'day_number', 'day_name', 'language'];
      const columnsWithData = new Set<keyof CSVRow>();
      DEFAULT_HEADERS.forEach(header => {
        const hasContent = newRows.some(row => {
            const val = row[header];
            return val && String(val).trim().length > 0;
        });
        if (hasContent) columnsWithData.add(header);
      });

      const activeHeaders = DEFAULT_HEADERS.filter(header => {
        if (metadataKeys.includes(header as any)) return true;
        if (typeof header === 'string' && header.startsWith('input_')) {
            const parts = header.split('_');
            if (parts.length === 2) {
                const number = parts[1];
                const correspondingQuestion = `question_${number}` as keyof CSVRow;
                return columnsWithData.has(correspondingQuestion);
            }
        }
        return columnsWithData.has(header);
      });

      setColumnOrder(activeHeaders);
      setGeneratedData(newRows);
      // Ao gerar dados, se estávamos no smart split, voltamos para a visualização da tabela
      if (activeTab === 'smart') {
         // Não alteramos a aba, apenas a visualização à direita será a tabela se generatedData > 0
      }
  };

  const handleManualEntrySubmit = (partialRow: Partial<CSVRow>) => {
    const completeRow: CSVRow = { ...partialRow, ...metadata } as CSVRow;
    updateTableData([completeRow]);
    setError(null);
    setSmartBlocks([]); // Limpa blocos se vier do smart
  };

  const handleClearTable = () => {
    if (confirm("Deseja limpar os dados da tabela?")) {
        setGeneratedData([]);
        setPreviewUrl(null);
        setError(null);
        setSmartBlocks([]);
    }
  };

  const handleDownload = () => {
    if (generatedData.length === 0 || !isMetadataComplete) return;
    const csvContent = generateCSV(generatedData, columnOrder);
    downloadCSV(csvContent, `${metadata.week_title || 'export'}.csv`);
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <TableCellsIcon className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold text-gray-900 tracking-tight">CSV Builder</h1>
          </div>
          <div className="flex items-center gap-4">
             {generatedData.length > 0 && (
                <button
                  onClick={handleDownload}
                  disabled={!isMetadataComplete}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium transition-colors shadow-sm ${
                    isMetadataComplete ? "bg-indigo-600 hover:bg-indigo-700 text-white" : "bg-gray-300 text-gray-500 cursor-not-allowed"
                  }`}
                >
                  <ArrowDownTrayIcon className="w-4 h-4" />
                  Download CSV
                </button>
             )}
          </div>
        </div>
      </header>

      <main className="flex-1 p-4 sm:p-6 lg:p-8 overflow-hidden">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-10rem)]">

          {/* COLUNA ESQUERDA: Configuração e Empilhamento */}
          <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-hidden">
            <div className="overflow-y-auto custom-scrollbar flex-1 space-y-6 pr-1">
              <MetadataForm metadata={metadata} onChange={handleMetadataChange} disabled={isLoading} />

              <section className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden flex flex-col">
                <div className="flex border-b border-gray-200 bg-gray-50/50">
                  <button onClick={() => setActiveTab('upload')} className={`flex-1 py-3 text-[10px] font-bold uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'upload' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PhotoIcon className="w-3.5 h-3.5" /> Image
                  </button>
                  <button onClick={() => setActiveTab('manual')} className={`flex-1 py-3 text-[10px] font-bold uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'manual' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PencilSquareIcon className="w-3.5 h-3.5" /> Manual
                  </button>
                  <button onClick={() => setActiveTab('smart')} className={`flex-1 py-3 text-[10px] font-bold uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'smart' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <ScissorsIcon className="w-3.5 h-3.5" /> Smart Split
                  </button>
                </div>

                <div className="p-4 bg-white">
                  {activeTab === 'upload' && (
                    <FileUpload onFileSelect={(b, p) => { setPreviewUrl(p); /* process logic... */ }} isLoading={isLoading} progress={progress} />
                  )}
                  {activeTab === 'manual' && <div className="text-[10px] text-gray-400 font-bold uppercase mb-2">Editor Sequencial</div>}

                  {activeTab === 'smart' && (
