                      </div>

                      <div className="space-y-3 max-h-[300px] overflow-y-auto custom-scrollbar pr-1">
                        {smartBlocks.length === 0 ? (
                          <div className="border-2 border-dashed border-gray-100 rounded-xl p-6 text-center">
                            <CommandLineIcon className="w-6 h-6 text-gray-200 mx-auto mb-2" />
                            <p className="text-[10px] text-gray-300 font-bold uppercase">Nenhum bloco editado</p>
                          </div>
                        ) : (
                          smartBlocks.map((block, idx) => (
                            <div key={block.id} className="flex gap-3 items-start animate-in slide-in-from-left-2">
                              <div className={`w-5 h-5 rounded-full flex items-center justify-center shrink-0 mt-1 shadow-sm ${
                                block.type === 't' ? 'bg-purple-600' : block.type === 'q' ? 'bg-amber-500' : 'bg-blue-600'
