import React, { useState, useRef, useEffect } from 'react';
import { CSVRow } from '../types';
import { 
  ScissorsIcon, 
  CommandLineIcon,
  ArrowPathIcon,
  CheckIcon,
  DocumentTextIcon,
  QuestionMarkCircleIcon
} from '@heroicons/react/24/outline';

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

interface SmartSplitterProps {
  onSubmit: (row: Partial<CSVRow>) => void;
  onBlocksUpdate: (blocks: SplitBlock[]) => void;
}

export const SmartSplitter: React.FC<SmartSplitterProps> = ({ onSubmit, onBlocksUpdate }) => {
  const [confirmedBlocks, setConfirmedBlocks] = useState<SplitBlock[]>([]);
  const [currentText, setCurrentText] = useState('');
  const [isNamingModalOpen, setIsNamingModalOpen] = useState(false);
  const [namingInput, setNamingInput] = useState('');
  const [splitIndex, setSplitIndex] = useState<number | null>(null);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const modalInputRef = useRef<HTMLInputElement>(null);

  // Sincroniza blocos locais com o pai para exibição na sidebar
  useEffect(() => {
    onBlocksUpdate(confirmedBlocks);
  }, [confirmedBlocks, onBlocksUpdate]);

  useEffect(() => {
    if (isNamingModalOpen) {
      modalInputRef.current?.focus();
    }
  }, [isNamingModalOpen]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const target = e.target as HTMLTextAreaElement;
      const cursorPosition = target.selectionStart;
      if (cursorPosition === 0 && currentText.length > 0) return;

      setSplitIndex(cursorPosition);
      setIsNamingModalOpen(true);
      setNamingInput('');
    }
  };

  const handleModalKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      validateAndConfirm();
    }
    if (e.key === 'Escape') {
      setIsNamingModalOpen(false);
    }
  };

  const validateAndConfirm = () => {
    const input = namingInput.toLowerCase();
    if (!input) return;

    const validFirst = ['t', 'x', 'q'];
    const validSecond = ['d'];
    const firstChar = input[0];
    const secondChar = input[1];

    if (!validFirst.includes(firstChar)) return;
    if (secondChar && !validSecond.includes(secondChar)) return;

    if (splitIndex === null) return;

    const blockText = currentText.slice(0, splitIndex).trim();
    const remainingText = currentText.slice(splitIndex).trim();

    if (secondChar === 'd' && remainingText.length > 0) {
      alert('O comando "d" só é válido ao dividir no final do texto.');
      return;
    }

    const newBlock: SplitBlock = {
      id: crypto.randomUUID(),
      type: firstChar as 't' | 'x' | 'q',
      text: blockText
    };

    const updatedBlocks = [...confirmedBlocks, newBlock];
    setConfirmedBlocks(updatedBlocks);
    setCurrentText(remainingText);
    setIsNamingModalOpen(false);
    setSplitIndex(null);

    if (secondChar === 'd') {
      finalize(updatedBlocks);
    }
  };

  const finalize = (blocksToProcess: SplitBlock[]) => {
    const row: Partial<CSVRow> = {};
    let textCount = 0;
    let questionCount = 0;

    blocksToProcess.forEach(block => {
      if (block.type === 't') {
        row.lesson_title = block.text;
      } else if (block.type === 'q') {
        questionCount++;
        const qKey = `question_${questionCount}` as keyof CSVRow;
        const iKey = `input_${questionCount}` as keyof CSVRow;
        if (questionCount <= 4) {
          (row as any)[qKey] = block.text;
          (row as any)[iKey] = "";
        }
      } else if (block.type === 'x') {
        textCount++;
        if (questionCount === 0) {
          if (textCount === 1) row.text_1 = block.text;
          else if (textCount === 2) row.text_2 = block.text;
          else row.text_3 = (row.text_3 ? row.text_3 + '\n' : '') + block.text;
        } else if (questionCount === 1) {
          row.text_4 = (row.text_4 ? row.text_4 + '\n' : '') + block.text;
        } else if (questionCount === 2) {
          row.text_5 = (row.text_5 ? row.text_5 + '\n' : '') + block.text;
        } else if (questionCount === 3) {
          row.text_6 = (row.text_6 ? row.text_6 + '\n' : '') + block.text;
        } else if (questionCount >= 4) {
          if (!row.text_7) row.text_7 = block.text;
          else row.text_8 = (row.text_8 ? row.text_8 + '\n' : '') + block.text;
        }
      }
    });

    onSubmit(row);
  };

  return (
    <div className="h-full bg-white rounded-3xl shadow-sm border border-gray-200 overflow-hidden flex flex-col animate-in fade-in duration-500">
      {/* Editor Header */}
      <div className="px-8 py-5 border-b border-gray-100 flex items-center justify-between bg-white">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2.5 rounded-2xl shadow-indigo-100 shadow-xl">
             <CommandLineIcon className="w-6 h-6 text-white" />
          </div>
          <div>
            <h2 className="text-lg font-black text-gray-900 tracking-tight">Focus Editor</h2>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Segmentação de texto inteligente</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
           <div className="flex items-center gap-2 px-4 py-2 bg-gray-50 rounded-xl border border-gray-100 text-[10px] font-black text-gray-400 uppercase tracking-widest">
             <kbd className="bg-white border border-gray-200 px-1.5 py-0.5 rounded shadow-sm text-indigo-600">TAB</kbd>
             Dividir
           </div>
           <button 
              onClick={() => confirm("Resetar editor?") && (setConfirmedBlocks([]), setCurrentText(''))}
              className="p-2 text-gray-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
           >
              <ArrowPathIcon className="w-5 h-5" />
           </button>
        </div>
      </div>

      {/* Main Textarea Area */}
      <div className="flex-1 p-10 relative bg-white">
        <textarea
          ref={textareaRef}
          className="w-full h-full resize-none border-none focus:ring-0 text-xl leading-relaxed text-gray-700 placeholder-gray-100 custom-scrollbar font-medium selection:bg-indigo-100 selection:text-indigo-900"
          placeholder="Cole o texto aqui e comece a dividir usando TAB..."
          value={currentText}
          onChange={(e) => setCurrentText(e.target.value)}
          onKeyDown={handleKeyDown}
        />

        {/* Empty State Overlay */}
        {!currentText && (
          <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none opacity-20">
             <ScissorsIcon className="w-24 h-24 text-gray-400 mb-4" />
             <span className="text-sm font-black uppercase tracking-[0.3em] text-gray-400">Smart Split Workspace</span>
          </div>
        )}
      </div>

      {/* Modal - Command Palette */}
      {isNamingModalOpen && (
        <div className="absolute inset-0 bg-gray-900/40 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white rounded-[2.5rem] shadow-2xl border border-white/20 w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-10">
              <div className="flex flex-col items-center gap-2 mb-8">
                <div className="h-12 w-12 bg-indigo-50 rounded-2xl flex items-center justify-center mb-2">
                  <CommandLineIcon className="w-7 h-7 text-indigo-600" />
                </div>
                <h4 className="text-gray-900 font-black text-xs uppercase tracking-[0.2em]">Classificar Bloco</h4>
              </div>

              <input
                ref={modalInputRef}
                type="text"
                className="w-full bg-gray-50 border-2 border-gray-100 rounded-3xl px-4 py-8 text-6xl font-black text-indigo-600 text-center uppercase focus:border-indigo-500 focus:bg-white focus:ring-0 transition-all placeholder-gray-100 shadow-inner"
                placeholder="?"
                maxLength={2}
                value={namingInput}
                onChange={(e) => setNamingInput(e.target.value)}
                onKeyDown={handleModalKeyDown}
              />

              <div className="mt-10 grid grid-cols-3 gap-4">
                <div className={`p-5 rounded-3xl border-2 transition-all text-center ${namingInput.toLowerCase().startsWith('t') ? 'bg-purple-600 border-purple-400 shadow-xl shadow-purple-100 scale-105' : 'bg-gray-50 border-transparent'}`}>
                   <span className={`block text-2xl font-black mb-1 ${namingInput.toLowerCase().startsWith('t') ? 'text-white' : 'text-purple-600'}`}>T</span>
                   <span className={`text-[9px] font-black uppercase tracking-tighter ${namingInput.toLowerCase().startsWith('t') ? 'text-purple-100' : 'text-gray-400'}`}>Título</span>
                </div>
                <div className={`p-5 rounded-3xl border-2 transition-all text-center ${namingInput.toLowerCase().startsWith('x') ? 'bg-blue-600 border-blue-400 shadow-xl shadow-blue-100 scale-105' : 'bg-gray-50 border-transparent'}`}>
                   <span className={`block text-2xl font-black mb-1 ${namingInput.toLowerCase().startsWith('x') ? 'text-white' : 'text-blue-600'}`}>X</span>
                   <span className={`text-[9px] font-black uppercase tracking-tighter ${namingInput.toLowerCase().startsWith('x') ? 'text-blue-100' : 'text-gray-400'}`}>Texto</span>
                </div>
                <div className={`p-5 rounded-3xl border-2 transition-all text-center ${namingInput.toLowerCase().startsWith('q') ? 'bg-amber-500 border-amber-400 shadow-xl shadow-amber-100 scale-105' : 'bg-gray-50 border-transparent'}`}>
                   <span className={`block text-2xl font-black mb-1 ${namingInput.toLowerCase().startsWith('q') ? 'text-white' : 'text-amber-600'}`}>Q</span>
                   <span className={`text-[9px] font-black uppercase tracking-tighter ${namingInput.toLowerCase().startsWith('q') ? 'text-amber-100' : 'text-gray-400'}`}>Pergunta</span>
                </div>
              </div>

              <div className="mt-12 text-center">
                 <p className="text-[11px] text-gray-300 font-bold uppercase tracking-widest leading-relaxed">
                   Use <span className="text-indigo-600">"D"</span> no final para confirmar e gerar a tabela
                 </p>
                 <div className="mt-4 flex items-center justify-center gap-2">
                    <kbd className="bg-gray-100 border border-gray-200 px-3 py-1.5 rounded-xl text-[10px] font-black text-gray-500 shadow-sm uppercase tracking-widest">ENTER</kbd>
                 </div>
              </div>
            </div>

            <button 
              onClick={() => setIsNamingModalOpen(false)}
              className="w-full py-6 bg-gray-50 text-gray-400 text-[10px] font-black uppercase hover:bg-red-50 hover:text-red-500 transition-all border-t border-gray-100 tracking-[0.4em]"
            >
              Cancelar (ESC)
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { CSVRow } from '../types';
import { 
  ScissorsIcon, 
  CommandLineIcon,
  ArrowPathIcon,
  CheckIcon,
} from '@heroicons/react/24/outline';

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

interface SmartSplitterProps {
  onBlocksUpdate: (blocks: SplitBlock[]) => void;
  blocks: SplitBlock[];
}

export const SmartSplitter: React.FC<SmartSplitterProps> = ({ onBlocksUpdate, blocks }) => {
  const [currentText, setCurrentText] = useState('');
  const [isNamingModalOpen, setIsNamingModalOpen] = useState(false);
  const [namingInput, setNamingInput] = useState('');
  const [splitIndex, setSplitIndex] = useState<number | null>(null);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const modalInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isNamingModalOpen) {
      modalInputRef.current?.focus();
    }
  }, [isNamingModalOpen]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const target = e.target as HTMLTextAreaElement;
      const cursorPosition = target.selectionStart;
      if (cursorPosition === 0 && currentText.length > 0) return;

      setSplitIndex(cursorPosition);
      setIsNamingModalOpen(true);
      setNamingInput('');
    }
  };

  const handleModalKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      validateAndConfirm();
    }
    if (e.key === 'Escape') {
      setIsNamingModalOpen(false);
    }
  };

  const validateAndConfirm = () => {
    const input = namingInput.toLowerCase();
    if (!input) return;

    const validFirst = ['t', 'x', 'q'];
    const validSecond = ['d'];
    const firstChar = input[0];
    const secondChar = input[1];

    if (!validFirst.includes(firstChar)) return;
    if (secondChar && !validSecond.includes(secondChar)) return;

    if (splitIndex === null) return;

    const blockText = currentText.slice(0, splitIndex).trim();
    const remainingText = currentText.slice(splitIndex).trim();

    const newBlock: SplitBlock = {
      id: crypto.randomUUID(),
      type: firstChar as 't' | 'x' | 'q',
      text: blockText
    };

    onBlocksUpdate([...blocks, newBlock]);
    setCurrentText(remainingText);
    setIsNamingModalOpen(false);
    setSplitIndex(null);

    // Lógica do cursor inteligente: Pula para o final do próximo parágrafo
    setTimeout(() => {
        if (textareaRef.current) {
            textareaRef.current.focus();

            // Encontrar o final do "próximo parágrafo"
            // Um parágrafo termina em \n ou no final do texto
            let nextPos = remainingText.indexOf('\n');

            // Se houver múltiplas quebras de linha seguidas, pular para o texto real
            if (nextPos !== -1) {
                // Tenta encontrar o próximo parágrafo real após quebras duplas
                const doubleBreak = remainingText.indexOf('\n\n');
                if (doubleBreak !== -1) {
                    // Pula para o fim do bloco atual antes da quebra dupla
                    nextPos = doubleBreak;
                }
            } else {
                // Se não houver quebra, vai para o final
                nextPos = remainingText.length;
            }

            textareaRef.current.setSelectionRange(nextPos, nextPos);
        }
    }, 10);
  };

  return (
    <div className="h-full bg-white rounded-3xl shadow-sm border border-gray-200 overflow-hidden flex flex-col animate-in fade-in duration-500">
      <div className="px-8 py-5 border-b border-gray-100 flex items-center justify-between bg-white">
