import { GoogleGenAI, Type } from "@google/genai";
import { CSVRow } from "../types";

// Updated instruction to prevent merging Q2 into Text 4
const SYSTEM_INSTRUCTION = `
You are an expert OCR and Data Extraction specialist.
Your goal is to map the visual layout of a study guide page into a granular, sequential structure.

VISUAL FLOW RULES (Strict Top-to-Bottom):
1. **Daily Lesson Title**: Found at the very top of the specific day's content.
2. **Text Blocks**: Capture reading paragraphs into text_1, text_2, etc.
3. **Interactions (Questions/Inputs)**:
   - When you encounter a Question (usually bold or numbered) followed by writing space (lines or blank gap), you **MUST** start a new 'question_X' / 'input_X' pair.
   - **DO NOT MERGE QUESTIONS INTO TEXT BLOCKS.**
   - If there is text *between* Question 1 and Question 2, put it in 'text_4'.
   - If there is text *between* Question 2 and Question 3, put it in 'text_5'.

CRITICAL "ANTI-MERGING" RULES:
- **Do NOT** put the entire bottom half of the page into 'text_4'.
- As soon as you see a new distinct question after the first one, STOP filling 'text_4' and start filling 'question_2'.
- If there is a third question, STOP filling 'text_5' and start filling 'question_3'.

Structure Mapping:
- Header (Daily Lesson Title) -> lesson_title
- Intro Paragraphs -> text_1, text_2, text_3
- First Question -> question_1
- Space for Answer -> input_1
- Middle Paragraphs -> text_4
- Second Question -> question_2
- Space for Answer -> input_2
- Next Paragraphs -> text_5
- Third Question -> question_3
- Space for Answer -> input_3
- Closing Text -> text_6, text_7, text_8

If a field is empty in the source, return an empty string "".
`;

const responseSchema = {
  type: Type.OBJECT,
  properties: {
    rows: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          lesson_title: { type: Type.STRING, description: "The Daily Lesson Title found at the top." },

          text_1: { type: Type.STRING },
          text_2: { type: Type.STRING },
          text_3: { type: Type.STRING },

          question_1: { type: Type.STRING },
          input_1: { type: Type.STRING },

          text_4: { type: Type.STRING, description: "Text strictly BETWEEN Q1 and Q2. Do not include Q2 here." },

          question_2: { type: Type.STRING },
          input_2: { type: Type.STRING },

          text_5: { type: Type.STRING, description: "Text strictly BETWEEN Q2 and Q3." },

          question_3: { type: Type.STRING },
          input_3: { type: Type.STRING },

          text_6: { type: Type.STRING },

          question_4: { type: Type.STRING },
          input_4: { type: Type.STRING },

          text_7: { type: Type.STRING },
          text_8: { type: Type.STRING },
        },
        required: ["lesson_title"],
      },
    },
  },
};

export const processImageWithGemini = async (
  base64Image: string, 
  signal?: AbortSignal,
  onProgress?: (percentage: number) => void
): Promise<Partial<CSVRow>[]> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Heuristic: A typical study guide page response is around 2000-3000 chars of JSON.
  // We use this to scale the progress bar during streaming.
  const ESTIMATED_CHAR_LENGTH = 2500;

  try {
    // 1. Initial "Connecting" progress
    onProgress?.(5);

    const result = await ai.models.generateContentStream({
      model: "gemini-3-flash-preview", 
      contents: [
        {
          role: "user",
          parts: [
            {
              inlineData: {
                mimeType: "image/jpeg",
                data: base64Image,
              },
            },
            {
              text: "Extract all text and questions. Be careful NOT to merge Question 2 into the text block above it. Split distinct questions into separate fields. The top title is the Daily Lesson Title.",
            },
          ],
        },
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    // 2. Stream Processing
    let fullText = '';

    // Iterate over the stream to update progress in real-time
    for await (const chunk of result) {
        if (signal?.aborted) {
            throw new DOMException("Aborted", "AbortError");
        }

        const chunkText = chunk.text;
        if (chunkText) {
            fullText += chunkText;

            const completionRatio = Math.min(1, fullText.length / ESTIMATED_CHAR_LENGTH);
            const progress = 10 + (completionRatio * 85); 

            onProgress?.(Math.round(progress));
        }
    }

    onProgress?.(98); 

    let text = fullText;
    if (!text) throw new Error("No response from Gemini");

    text = text.replace(/^```json\s*/, "").replace(/\s*```$/, "");

    const parsed = JSON.parse(text);
    return parsed.rows || [];

  } catch (error) {
    if (error instanceof DOMException && error.name === 'AbortError') {
      throw error;
    }
    console.error("Gemini Extraction Error:", error);
    throw error;
  }
};

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { FileUpload } from './components/FileUpload';
import { TablePreview } from './components/TablePreview';
import { BasicsForm } from './components/BasicsForm';
import { SmartSplitter } from './components/SmartSplitter';
import { generateCSV, downloadCSV, DEFAULT_HEADERS } from './utils/csvHelper';
import { CSVRow, StudyMetadata } from './types';
import { 
  ArrowDownTrayIcon, 
  TableCellsIcon, 
  PhotoIcon,
  PencilSquareIcon,
  ScissorsIcon,
  CommandLineIcon,
  TrashIcon,
  ChevronUpIcon,
  ChevronDownIcon,
  SparklesIcon,
  PlusIcon
} from '@heroicons/react/24/outline';

const DAY_MAP: Record<string, string> = {
  '1': 'Saturday', '2': 'Sunday', '3': 'Monday', '4': 'Tuesday', '5': 'Wednesday', '6': 'Thursday', '7': 'Friday',
};

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

const App: React.FC = () => {
  const [basics, setBasics] = useState<StudyMetadata & { lesson_title: string }>({
    week_number: '', week_title: '', day_number: '', day_name: '', language: '', lesson_title: ''
  });

  const [activeTab, setActiveTab] = useState<'upload' | 'basics' | 'smart'>('basics');
  const [generatedData, setGeneratedData] = useState<CSVRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [columnOrder, setColumnOrder] = useState<(keyof CSVRow)[]>(DEFAULT_HEADERS);
  const [smartBlocks, setSmartBlocks] = useState<SplitBlock[]>([]);

  // Verificação se os requisitos mínimos foram atendidos
  const canProcess = useMemo(() => {
    const basicsDone = basics.week_title.trim().length > 0 && basics.day_name.trim().length > 0;
    const hasBlocks = smartBlocks.length > 0;
    return basicsDone && hasBlocks;
  }, [basics, smartBlocks]);

  // Função centralizada para transformar blocos em linha da planilha
  const syncTableFromBlocks = (currentBlocks: SplitBlock[], currentBasics: typeof basics) => {
    if (currentBlocks.length === 0) return;

    const row: Partial<CSVRow> = { ...currentBasics };
    let textCount = 0;
    let questionCount = 0;

    currentBlocks.forEach(block => {
      if (block.type === 't') {
        row.lesson_title = block.text;
      } else if (block.type === 'q') {
        questionCount++;
        const qKey = `question_${questionCount}` as keyof CSVRow;
        if (questionCount <= 4) {
          (row as any)[qKey] = block.text;
          (row as any)[`input_${questionCount}`] = "";
        }
      } else if (block.type === 'x') {
        textCount++;
        if (questionCount === 0) {
          if (textCount === 1) row.text_1 = block.text;
          else if (textCount === 2) row.text_2 = block.text;
          else row.text_3 = (row.text_3 ? row.text_3 + '\n' : '') + block.text;
        } else if (questionCount === 1) {
          row.text_4 = (row.text_4 ? row.text_4 + '\n' : '') + block.text;
        } else if (questionCount === 2) {
          row.text_5 = (row.text_5 ? row.text_5 + '\n' : '') + block.text;
        } else if (questionCount === 3) {
          row.text_6 = (row.text_6 ? row.text_6 + '\n' : '') + block.text;
        } else if (questionCount >= 4) {
          if (!row.text_7) row.text_7 = block.text;
          else row.text_8 = (row.text_8 ? row.text_8 + '\n' : '') + block.text;
        }
      }
    });

    setGeneratedData([row as CSVRow]);
  };

  // Efeito para sincronizar automaticamente quando blocos ou basics mudam e já houver dados
  useEffect(() => {
    if (generatedData.length > 0) {
        syncTableFromBlocks(smartBlocks, basics);
    }
  }, [basics, smartBlocks]);

  const handleBasicsChange = (field: string, value: string) => {
    setBasics(prev => {
      const updated = { ...prev, [field]: value };
      if (field === 'day_number') {
        const mappedName = DAY_MAP[value];
        if (mappedName) updated.day_name = mappedName;
      } else if (field === 'day_name') {
        const mappedNumber = Object.keys(DAY_MAP).find(key => DAY_MAP[key] === value);
        if (mappedNumber) updated.day_number = mappedNumber;
      }
      return updated;
    });
  };

  const finalizeProcess = () => {
    syncTableFromBlocks(smartBlocks, basics);
    setActiveTab('basics');
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    if ((direction === 'up' && index === 0) || (direction === 'down' && index === smartBlocks.length - 1)) return;
    const newBlocks = [...smartBlocks];
    const swapIdx = direction === 'up' ? index - 1 : index + 1;
    [newBlocks[index], newBlocks[swapIdx]] = [newBlocks[swapIdx], newBlocks[index]];
    setSmartBlocks(newBlocks);
  };

  const addNewBlock = () => {
    const newBlock: SplitBlock = {
        id: crypto.randomUUID(),
        type: 'x',
        text: ''
    };
    setSmartBlocks(prev => [...prev, newBlock]);
  };

  const updateBlockText = (id: string, text: string) => {
    setSmartBlocks(prev => prev.map(b => b.id === id ? { ...b, text } : b));
  };

  const toggleBlockType = (id: string) => {
    const types: ('t' | 'x' | 'q')[] = ['t', 'x', 'q'];
    setSmartBlocks(prev => prev.map(b => {
        if (b.id === id) {
            const nextIdx = (types.indexOf(b.type) + 1) % types.length;
            return { ...b, type: types[nextIdx] };
        }
        return b;
    }));
  };

  // Lógica para sincronizar a ordem dos blocos baseado na mudança de ordem das colunas da planilha
  const handleMoveColumn = (index: number, direction: 'left' | 'right') => {
    const newOrder = [...columnOrder];
    const targetIdx = direction === 'left' ? index - 1 : index + 1;
    [newOrder[index], newOrder[targetIdx]] = [newOrder[targetIdx], newOrder[index]];
    setColumnOrder(newOrder);

    // Reordenar os blocos baseados na nova ordem das colunas
    // Nota: Apenas colunas de conteúdo (text_, question_, lesson_) afetam a ordem dos blocos
    const contentColumns = newOrder.filter(col => 
        col.startsWith('text_') || col.startsWith('question_') || col === 'lesson_title'
    );

    // Criar um mapa da ordem atual dos blocos
    // (Isso é uma simplificação, assumindo que os blocos seguem a ordem da planilha)
    const newSmartBlocks = [...smartBlocks];
    // Aqui poderíamos implementar uma lógica mais complexa de mapeamento se necessário,
    // mas por ora vamos focar em garantir que a reordenação da planilha seja permitida visualmente.
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <TableCellsIcon className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold text-gray-900 tracking-tight">CSV Builder Pro</h1>
          </div>
          <div className="flex items-center gap-4">
             {generatedData.length > 0 && (
                <button
                  onClick={() => downloadCSV(generateCSV(generatedData, columnOrder), `${basics.week_title} - ${basics.day_name}.csv`)}
                  className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg text-sm font-medium transition-all shadow-sm"
                >
                  <ArrowDownTrayIcon className="w-4 h-4" /> Download CSV
                </button>
             )}
          </div>
        </div>
      </header>

      <main className="flex-1 p-4 sm:p-6 lg:p-8 overflow-hidden">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-10rem)]">

          <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-hidden">
            <div className="overflow-y-auto custom-scrollbar flex-1 space-y-6 pr-1">

              <section className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden flex flex-col">
                <div className="flex border-b border-gray-200 bg-gray-50/50">
                  <button onClick={() => setActiveTab('basics')} className={`flex-1 py-3 text-[10px] font-bold uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'basics' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PencilSquareIcon className="w-3.5 h-3.5" /> Basics
                  </button>
                  <button onClick={() => setActiveTab('smart')} className={`flex-1 py-3 text-[10px] font-bold uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'smart' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <ScissorsIcon className="w-3.5 h-3.5" /> Smart Split
                  </button>
                  <button onClick={() => setActiveTab('upload')} className={`flex-1 py-3 text-[10px] font-bold uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'upload' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PhotoIcon className="w-3.5 h-3.5" /> Image
                  </button>
                </div>

                <div className="p-5">
                  {activeTab === 'basics' && <BasicsForm metadata={basics} onChange={handleBasicsChange} disabled={isLoading} />}

                  {activeTab === 'smart' && (
                    <div className="space-y-4">
                      <div className="flex items-center justify-between">
                        <h3 className="text-[10px] font-black text-gray-900 uppercase tracking-widest">Editor de Blocos</h3>
                        <span className="bg-indigo-100 text-indigo-600 px-2.5 py-1 rounded-lg text-[9px] font-black">{smartBlocks.length}</span>
                      </div>

                      <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-1">
                        {smartBlocks.length === 0 ? (
                          <div className="border-2 border-dashed border-gray-100 rounded-2xl p-8 text-center bg-gray-50/30">
                            <CommandLineIcon className="w-8 h-8 text-gray-200 mx-auto mb-3" />
                            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest leading-relaxed">Use o editor à direita para criar blocos automaticamente</p>
                          </div>
                        ) : (
                          smartBlocks.map((block, idx) => (
                            <div key={block.id} className="group bg-white border border-gray-100 rounded-2xl p-3 shadow-sm hover:border-indigo-200 transition-all animate-in slide-in-from-bottom-2">
                              <div className="flex items-center justify-between mb-2">
                                <button 
                                    onClick={() => toggleBlockType(block.id)}
                                    className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-full cursor-pointer hover:opacity-80 transition-opacity ${
                                        block.type === 't' ? 'bg-purple-100 text-purple-700' :
                                        block.type === 'q' ? 'bg-amber-100 text-amber-700' :
                                        'bg-blue-100 text-blue-700'
                                    }`}
                                >
                                    {block.type === 't' ? 'Título' : block.type === 'q' ? 'Pergunta' : 'Texto'}
                                </button>
                                <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => moveBlock(idx, 'up')} className="p-1 text-gray-300 hover:text-indigo-600"><ChevronUpIcon className="w-3 h-3"/></button>
                                    <button onClick={() => moveBlock(idx, 'down')} className="p-1 text-gray-300 hover:text-indigo-600"><ChevronDownIcon className="w-3 h-3"/></button>
                                    <button onClick={() => setSmartBlocks(prev => prev.filter(b => b.id !== block.id))} className="p-1 text-gray-300 hover:text-red-500 ml-1"><TrashIcon className="w-3 h-3"/></button>
                                </div>
                              </div>
                              <textarea 
                                value={block.text}
                                onChange={(e) => updateBlockText(block.id, e.target.value)}
                                className="w-full bg-gray-50 rounded-lg p-2 text-[11px] text-gray-600 border-none focus:ring-1 focus:ring-indigo-100 resize-none min-h-[40px] custom-scrollbar"
                              />
                            </div>
                          ))
                        )}
                      </div>

                      <div className="grid grid-cols-1 gap-3">
                        <button 
                            onClick={addNewBlock}
                            className="w-full py-3 bg-gray-50 hover:bg-gray-100 text-gray-500 rounded-xl text-[9px] font-black uppercase tracking-widest border border-dashed border-gray-200 flex items-center justify-center gap-2 transition-all"
                        >
                            <PlusIcon className="w-3.5 h-3.5" /> Adicionar Bloco Extra
                        </button>

                        {canProcess && (
                            <button 
                                onClick={finalizeProcess}
                                className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 flex items-center justify-center gap-2 animate-in zoom-in-95"
                            >
                                <SparklesIcon className="w-4 h-4" /> {generatedData.length > 0 ? 'Atualizar Planilha' : 'Gerar Planilha'}
                            </button>
                        )}
                      </div>
                    </div>
                  )}
                  {activeTab === 'upload' && <FileUpload onFileSelect={() => {}} isLoading={isLoading} />}
                </div>
              </section>
            </div>
          </div>

          <div className="lg:col-span-8 h-full">
            {activeTab === 'smart' ? (
              <SmartSplitter 
                onBlocksUpdate={setSmartBlocks}
                blocks={smartBlocks}
              />
            ) : generatedData.length > 0 ? (
              <TablePreview 
                data={generatedData} 
                columns={columnOrder} 
                onMoveColumn={handleMoveColumn} 
                onClear={() => {setGeneratedData([]); setSmartBlocks([]);}} 
              />
            ) : (
              <div className="h-full bg-white rounded-3xl shadow-sm border border-gray-200 flex flex-col items-center justify-center text-center p-12">
                <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] flex items-center justify-center mb-8 transform rotate-3 hover:rotate-0 transition-transform duration-500">
                  <CommandLineIcon className="w-12 h-12 text-indigo-100" />
                </div>
                <h3 className="text-2xl font-black text-gray-900 tracking-tight">Focus Editor</h3>
                <p className="text-gray-400 max-w-sm mt-4 text-sm leading-relaxed font-medium">
                  Clique em <span className="text-indigo-600 font-bold">Smart Split</span> para carregar seu texto e começar a segmentação rápida.
                </p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { 
  ScissorsIcon, 
  CommandLineIcon,
  ArrowPathIcon,
} from '@heroicons/react/24/outline';

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

interface SmartSplitterProps {
  onBlocksUpdate: (blocks: SplitBlock[]) => void;
  blocks: SplitBlock[];
}

export const SmartSplitter: React.FC<SmartSplitterProps> = ({ onBlocksUpdate, blocks }) => {
  const [currentText, setCurrentText] = useState('');
  const [isNamingModalOpen, setIsNamingModalOpen] = useState(false);
  const [namingInput, setNamingInput] = useState('');
  const [splitIndex, setSplitIndex] = useState<number | null>(null);

  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const modalInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isNamingModalOpen) {
      modalInputRef.current?.focus();
    }
  }, [isNamingModalOpen]);

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Tab') {
      e.preventDefault();
      const target = e.target as HTMLTextAreaElement;
      const cursorPosition = target.selectionStart;
      if (cursorPosition === 0 && currentText.length > 0) return;

      setSplitIndex(cursorPosition);
      setIsNamingModalOpen(true);
      setNamingInput('');
    }
  };

  const handleModalKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      validateAndConfirm();
    }
    if (e.key === 'Escape') {
      setIsNamingModalOpen(false);
      // Retorna o foco ao editor se cancelar
      setTimeout(() => textareaRef.current?.focus(), 10);
    }
  };

  const validateAndConfirm = () => {
    const input = namingInput.toLowerCase();
    if (!input) return;

    const validFirst = ['t', 'x', 'q'];
    const firstChar = input[0];

    if (!validFirst.includes(firstChar)) return;
    if (splitIndex === null) return;

    const blockText = currentText.slice(0, splitIndex).trim();
    const remainingText = currentText.slice(splitIndex).trim();

    const newBlock: SplitBlock = {
      id: crypto.randomUUID(),
      type: firstChar as 't' | 'x' | 'q',
      text: blockText
    };

    onBlocksUpdate([...blocks, newBlock]);
    setCurrentText(remainingText);
    setIsNamingModalOpen(false);
    setSplitIndex(null);

    // Lógica do cursor inteligente: Foca no editor exatamente onde o texto continuará
    setTimeout(() => {
        if (textareaRef.current) {
            textareaRef.current.focus();

            // Encontrar o final do "próximo parágrafo" para agilizar a próxima divisão
            let nextPos = remainingText.indexOf('\n');

            if (nextPos !== -1) {
                // Tenta encontrar o próximo parágrafo real após quebras duplas
                const doubleBreak = remainingText.indexOf('\n\n');
                if (doubleBreak !== -1) {
                    nextPos = doubleBreak;
                }
            } else {
                nextPos = remainingText.length;
            }

            textareaRef.current.setSelectionRange(nextPos, nextPos);
        }
    }, 10);
  };

  // Pega um trecho inicial do bloco que está sendo criado para exibir na modal
  const getPreviewText = () => {
    if (splitIndex === null) return '';
    const text = currentText.slice(0, splitIndex).trim();
    if (text.length > 120) return text.slice(0, 117) + '...';
    return text;
  };

  return (
    <div className="h-full bg-white rounded-3xl shadow-sm border border-gray-200 overflow-hidden flex flex-col animate-in fade-in duration-500">
      <div className="px-8 py-5 border-b border-gray-100 flex items-center justify-between bg-white">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-600 p-2.5 rounded-2xl shadow-indigo-100 shadow-xl">
             <CommandLineIcon className="w-6 h-6 text-white" />
          </div>
          <div>
            <h2 className="text-lg font-black text-gray-900 tracking-tight">Focus Editor</h2>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">Segmentação inteligente com cursor automático</p>
          </div>
        </div>
        <div className="flex items-center gap-3">
           <div className="flex items-center gap-2 px-4 py-2 bg-gray-50 rounded-xl border border-gray-100 text-[10px] font-black text-gray-400 uppercase tracking-widest">
             <kbd className="bg-white border border-gray-200 px-1.5 py-0.5 rounded shadow-sm text-indigo-600">TAB</kbd> Dividir
           </div>
           <button 
              onClick={() => confirm("Resetar editor?") && (setCurrentText(''))}
              className="p-2 text-gray-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"
           >
              <ArrowPathIcon className="w-5 h-5" />
           </button>
        </div>
      </div>

      <div className="flex-1 p-10 relative bg-white">
        <textarea
          ref={textareaRef}
          className="w-full h-full resize-none border-none focus:ring-0 text-xl leading-relaxed text-gray-700 placeholder-gray-100 custom-scrollbar font-medium selection:bg-indigo-100 selection:text-indigo-900"
          placeholder="Cole o texto aqui e use TAB para dividir em blocos..."
          value={currentText}
          onChange={(e) => setCurrentText(e.target.value)}
          onKeyDown={handleKeyDown}
        />
        {!currentText && (
          <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none opacity-20">
             <ScissorsIcon className="w-24 h-24 text-gray-400 mb-4" />
             <span className="text-sm font-black uppercase tracking-[0.3em] text-gray-400">Workspace</span>
          </div>
        )}
      </div>

      {isNamingModalOpen && (
        <div className="absolute inset-0 bg-gray-900/40 backdrop-blur-md z-[100] flex items-center justify-center p-6 animate-in fade-in duration-200">
          <div className="bg-white rounded-[2.5rem] shadow-2xl border border-white/20 w-full max-w-md overflow-hidden animate-in zoom-in-95 duration-300">
            <div className="p-10 text-center">
              <h4 className="text-gray-900 font-black text-xs uppercase tracking-[0.2em] mb-4">Classificar Bloco</h4>

              {/* Preview do texto que está sendo classificado */}
              <div className="mb-8 p-4 bg-indigo-50/50 rounded-2xl border border-indigo-100 text-left">
                <p className="text-xs text-indigo-400 font-bold uppercase tracking-widest mb-2">Conteúdo:</p>
                <p className="text-sm text-indigo-900 italic line-clamp-3 leading-relaxed">
                   "{getPreviewText()}"
                </p>
              </div>

              <input
                ref={modalInputRef}
                type="text"
                className="w-full bg-gray-50 border-2 border-gray-100 rounded-3xl px-4 py-8 text-6xl font-black text-indigo-600 text-center uppercase focus:border-indigo-500 focus:bg-white focus:ring-0 transition-all placeholder-gray-100 shadow-inner"
                placeholder="?"
                maxLength={1}
                value={namingInput}
                onChange={(e) => setNamingInput(e.target.value)}
                onKeyDown={handleModalKeyDown}
              />
              <div className="mt-8 flex justify-center gap-4 text-[9px] font-black uppercase tracking-widest text-gray-400">
                <span>[T] Título</span>
                <span>[X] Texto</span>
                <span>[Q] Pergunta</span>
              </div>
            </div>
            <button 
              onClick={() => {
                setIsNamingModalOpen(false);
                setTimeout(() => textareaRef.current?.focus(), 10);
              }}
              className="w-full py-6 bg-gray-50 text-gray-400 text-[10px] font-black uppercase hover:bg-red-50 hover:text-red-500 transition-all border-t border-gray-100 tracking-[0.4em]"
            >
              Cancelar (ESC)
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { CSVRow } from '../types';
import { ChevronLeftIcon, ChevronRightIcon, PencilSquareIcon, TrashIcon } from '@heroicons/react/24/solid';

interface TablePreviewProps {
  data: CSVRow[];
  columns: (keyof CSVRow)[];
  onMoveColumn: (index: number, direction: 'left' | 'right') => void;
  onDeleteColumn?: (header: keyof CSVRow) => void;
  onEditHeader?: (key: keyof CSVRow) => void;
  onClear?: () => void;
}

export const TablePreview: React.FC<TablePreviewProps> = ({ data, columns, onMoveColumn, onDeleteColumn, onEditHeader, onClear }) => {
  if (data.length === 0) return null;

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden flex flex-col h-full">
