            <span className="text-xs bg-indigo-100 text-indigo-700 px-2 py-1 rounded-full font-medium">
            {data.length} Rows
            </span>
            {onClear && (
                <button 
                    onClick={onClear} 
                    className="flex items-center gap-1 text-xs font-medium text-red-600 bg-red-50 hover:bg-red-100 px-2.5 py-1.5 rounded-md transition-colors border border-red-100"
                    title="Clear all table data"
