      </div>

      <div className="overflow-auto flex-1">
        <table className="min-w-full divide-y divide-gray-200 text-sm">
          <thead className="bg-gray-50">
            <tr>
              {columns.map((header, idx) => (
                <th
                  key={header}
                  scope="col"
                  onClick={() => onEditHeader?.(header)}
                  className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider whitespace-nowrap group cursor-pointer hover:bg-indigo-50 hover:text-indigo-700 transition-colors relative"
                  title="Click to edit/split this column"
                >
                  <div className="flex flex-col gap-2">
                    <div className="flex items-center gap-1">
                        <span>{header.replace(/_/g, ' ')}</span>
                        <PencilSquareIcon className="w-3 h-3 opacity-0 group-hover:opacity-100 transition-opacity" />
                    </div>
                    <div 
                        className="flex items-center gap-1 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity"
                        onClick={(e) => e.stopPropagation()} 
                    >
                      <button
                        onClick={() => onMoveColumn(idx, 'left')}
                        disabled={idx === 0}
                        className="p-1 hover:bg-gray-200 rounded disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
                        title="Move Left"
                      >
                        <ChevronLeftIcon className="w-3 h-3 text-gray-600" />
                      </button>
                      <button
                        onClick={() => onMoveColumn(idx, 'right')}
                        disabled={idx === columns.length - 1}
                        className="p-1 hover:bg-gray-200 rounded disabled:opacity-30 disabled:hover:bg-transparent transition-colors"
                        title="Move Right"
                      >
                        <ChevronRightIcon className="w-3 h-3 text-gray-600" />
                      </button>
                      <div className="w-px h-3 bg-gray-200 mx-0.5"></div>
                      <button
                        onClick={() => onDeleteColumn?.(header)}
                        className="p-1 hover:bg-red-100 rounded text-red-400 hover:text-red-600 transition-colors"
                        title="Delete Column"
                      >
                        <TrashIcon className="w-3 h-3" />
