                    </div>
                  </td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useRef, useMemo, useEffect } from 'react';
import { FileUpload } from './components/FileUpload';
import { TablePreview } from './components/TablePreview';
import { BasicsForm } from './components/BasicsForm';
import { SmartSplitter } from './components/SmartSplitter';
import { generateCSV, downloadCSV, DEFAULT_HEADERS } from './utils/csvHelper';
import { CSVRow, StudyMetadata } from './types';
import { 
  ArrowDownTrayIcon, 
  TableCellsIcon, 
  PhotoIcon,
  PencilSquareIcon,
  ScissorsIcon,
  CommandLineIcon,
  TrashIcon,
  ChevronUpIcon,
  ChevronDownIcon,
  SparklesIcon,
  PlusIcon
} from '@heroicons/react/24/outline';

const DAY_MAP: Record<string, string> = {
  '1': 'Saturday', '2': 'Sunday', '3': 'Monday', '4': 'Tuesday', '5': 'Wednesday', '6': 'Thursday', '7': 'Friday',
};

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

const App: React.FC = () => {
  const [basics, setBasics] = useState<StudyMetadata & { lesson_title: string }>({
    week_number: '', week_title: '', day_number: '', day_name: '', language: '', lesson_title: ''
  });

  const [activeTab, setActiveTab] = useState<'upload' | 'basics' | 'smart'>('basics');
  const [generatedData, setGeneratedData] = useState<CSVRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [columnOrder, setColumnOrder] = useState<(keyof CSVRow)[]>(DEFAULT_HEADERS);
  const [smartBlocks, setSmartBlocks] = useState<SplitBlock[]>([]);

  // Verificação se os requisitos mínimos foram atendidos
  const canProcess = useMemo(() => {
    const basicsDone = basics.week_title.trim().length > 0 && basics.day_name.trim().length > 0;
    const hasBlocks = smartBlocks.length > 0;
    return basicsDone && hasBlocks;
  }, [basics, smartBlocks]);

  // Função centralizada para transformar blocos em linha da planilha
  const syncTableFromBlocks = (currentBlocks: SplitBlock[], currentBasics: typeof basics) => {
    if (currentBlocks.length === 0) return;

    const row: Partial<CSVRow> = { ...currentBasics };
    let textCount = 0;
    let questionCount = 0;

    currentBlocks.forEach(block => {
      if (block.type === 't') {
        row.lesson_title = block.text;
      } else if (block.type === 'q') {
        questionCount++;
        const qKey = `question_${questionCount}` as keyof CSVRow;
        if (questionCount <= 4) {
          (row as any)[qKey] = block.text;
          (row as any)[`input_${questionCount}`] = "";
        }
      } else if (block.type === 'x') {
        textCount++;
        if (questionCount === 0) {
          if (textCount === 1) row.text_1 = block.text;
          else if (textCount === 2) row.text_2 = block.text;
          else row.text_3 = (row.text_3 ? row.text_3 + '\n' : '') + block.text;
        } else if (questionCount === 1) {
          row.text_4 = (row.text_4 ? row.text_4 + '\n' : '') + block.text;
        } else if (questionCount === 2) {
          row.text_5 = (row.text_5 ? row.text_5 + '\n' : '') + block.text;
        } else if (questionCount === 3) {
          row.text_6 = (row.text_6 ? row.text_6 + '\n' : '') + block.text;
        } else if (questionCount >= 4) {
          if (!row.text_7) row.text_7 = block.text;
          else row.text_8 = (row.text_8 ? row.text_8 + '\n' : '') + block.text;
        }
      }
    });

    setGeneratedData([row as CSVRow]);
  };

  // Efeito para sincronizar automaticamente quando blocos ou basics mudam e já houver dados
  useEffect(() => {
    if (generatedData.length > 0) {
        syncTableFromBlocks(smartBlocks, basics);
    }
  }, [basics, smartBlocks]);

  const handleBasicsChange = (field: string, value: string) => {
    setBasics(prev => {
      const updated = { ...prev, [field]: value };
      if (field === 'day_number') {
        const mappedName = DAY_MAP[value];
        if (mappedName) updated.day_name = mappedName;
      } else if (field === 'day_name') {
        const mappedNumber = Object.keys(DAY_MAP).find(key => DAY_MAP[key] === value);
        if (mappedNumber) updated.day_number = mappedNumber;
      }
      return updated;
    });
  };

  const finalizeProcess = () => {
    syncTableFromBlocks(smartBlocks, basics);
    setActiveTab('basics');
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    if ((direction === 'up' && index === 0) || (direction === 'down' && index === smartBlocks.length - 1)) return;
    const newBlocks = [...smartBlocks];
    const swapIdx = direction === 'up' ? index - 1 : index + 1;
    [newBlocks[index], newBlocks[swapIdx]] = [newBlocks[swapIdx], newBlocks[index]];
    setSmartBlocks(newBlocks);
  };

  const addNewBlock = () => {
    const newBlock: SplitBlock = {
        id: crypto.randomUUID(),
        type: 'x',
        text: ''
    };
    setSmartBlocks(prev => [...prev, newBlock]);
  };

  const updateBlockText = (id: string, text: string) => {
    setSmartBlocks(prev => prev.map(b => b.id === id ? { ...b, text } : b));
  };

  const toggleBlockType = (id: string) => {
    const types: ('t' | 'x' | 'q')[] = ['t', 'x', 'q'];
    setSmartBlocks(prev => prev.map(b => {
        if (b.id === id) {
            const nextIdx = (types.indexOf(b.type) + 1) % types.length;
            return { ...b, type: types[nextIdx] };
        }
        return b;
    }));
  };

  const handleMoveColumn = (index: number, direction: 'left' | 'right') => {
    const newOrder = [...columnOrder];
    const targetIdx = direction === 'left' ? index - 1 : index + 1;
    [newOrder[index], newOrder[targetIdx]] = [newOrder[targetIdx], newOrder[index]];
    setColumnOrder(newOrder);
  };

  const handleDeleteColumn = (header: keyof CSVRow) => {
    if (confirm(`Deseja remover a coluna "${String(header).replace(/_/g, ' ')}" da exportação?`)) {
        setColumnOrder(prev => prev.filter(col => col !== header));
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <TableCellsIcon className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold text-gray-900 tracking-tight">CSV Builder Pro</h1>
          </div>
          <div className="flex items-center gap-4">
             {generatedData.length > 0 && (
                <button
                  onClick={() => downloadCSV(generateCSV(generatedData, columnOrder), `${basics.week_title} - ${basics.day_name}.csv`)}
                  className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg text-sm font-medium transition-all shadow-sm"
                >
                  <ArrowDownTrayIcon className="w-4 h-4" /> Download CSV
                </button>
             )}
          </div>
        </div>
      </header>

      <main className="flex-1 p-4 sm:p-6 lg:p-8 overflow-hidden">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-10rem)]">

          <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-hidden">
            <div className="overflow-y-auto custom-scrollbar flex-1 space-y-6 pr-1">

              <section className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden flex flex-col">
                <div className="flex border-b border-gray-200 bg-gray-50/50">
                  <button onClick={() => setActiveTab('basics')} className={`flex-1 py-3 text-[10px] font-bold uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'basics' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PencilSquareIcon className="w-3.5 h-3.5" /> Basics
                  </button>
