import { CSVRow } from '../types';

export const DEFAULT_HEADERS: (keyof CSVRow)[] = [
  // 1. Context Metadata (Manual Inputs)
  'week_number',
  'week_title',
  'day_number',
  'day_name',
  'lesson_title',
  'language',

  // 2. First Block of Text
  'text_1',
  'text_2',
  'text_3',

  // 3. First Interaction Pair
  'question_1',
  'input_1',

  // 4. Second Block
  'text_4',
  'question_2',
  'input_2',

  // 5. Third Block
  'text_5',
  'question_3',
  'input_3',

  // 6. Fourth Block
  'text_6',
  'question_4',
  'input_4',

  // 7. Remaining Text
  'text_7',
  'text_8'
];

export const generateCSV = (data: CSVRow[], customHeaders?: (keyof CSVRow)[]): string => {
  const headers = customHeaders || DEFAULT_HEADERS;

  const csvRows = [
    headers.join(','), // Header row
    ...data.map(row => {
      return headers.map(fieldName => {
        const value = row[fieldName] || ''; 
        const escaped = String(value).replace(/"/g, '""');
        return `"${escaped}"`;
      }).join(',');
    })
  ];

  return csvRows.join('\n');
};

export const downloadCSV = (csvContent: string, filename: string = 'study-guide-export.csv') => {
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const link = document.createElement('a');
  if (link.download !== undefined) {
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  }
};

/**
 * Converte blocos do Smart Split e metadados no formato JSON solicitado.
 */
export const generateJSON = (basics: any, blocks: any[]): string => {
  const content = blocks.map(block => ({
    type: block.type === 'q' ? 'question' : block.type === 't' ? 'title' : 'paragraph',
    text: block.text
  }));

  const jsonObject = [
    {
      week_number: parseInt(basics.week_number) || basics.week_number,
      day_number: parseInt(basics.day_number) || basics.day_number,
      title: basics.lesson_title || (blocks.find(b => b.type === 't')?.text || ''),
      content: content,
      language: basics.language || 'en'
    }
  ];

  return JSON.stringify(jsonObject, null, 2);
};

export const downloadJSON = (jsonString: string, filename: string = 'study-guide-export.json') => {
  const blob = new Blob([jsonString], { type: 'application/json;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
  link.setAttribute('download', filename);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

