                              />
                            </div>
                          ))
                        )}
                      </div>

                      <div className="grid grid-cols-1 gap-3">
                        <button 
                            onClick={addNewBlock}
                            className="w-full py-3 bg-gray-50 hover:bg-gray-100 text-gray-500 rounded-xl text-[9px] font-black uppercase tracking-widest border border-dashed border-gray-200 flex items-center justify-center gap-2 transition-all"
