    </div>
  );
};

import React, { useRef, useState } from 'react';
import { UILanguage, translations } from '../utils/translations';
import { CloudArrowUpIcon, XCircleIcon } from '@heroicons/react/24/outline';
import { SparklesIcon } from '@heroicons/react/24/solid';

interface FileUploadProps {
  onFileSelect: (base64: string, previewUrl: string) => void;
  onCancel?: () => void;
  isLoading: boolean;
  progress?: number;
  uiLanguage: UILanguage;
}

export const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, onCancel, isLoading, progress = 0, uiLanguage }) => {
  const t = translations[uiLanguage];
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [dragActive, setDragActive] = useState(false);

  const handleDrag = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === "dragenter" || e.type === "dragover") {
      setDragActive(true);
    } else if (e.type === "dragleave") {
      setDragActive(false);
    }
  };

  const processFile = (file: File) => {
    if (!file || !file.type.startsWith('image/')) return;
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      onFileSelect(base64, result);
    };
    reader.readAsDataURL(file);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);
    if (!isLoading && e.dataTransfer.files && e.dataTransfer.files[0]) {
      processFile(e.dataTransfer.files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      processFile(e.target.files[0]);
    }
  };

  return (
    <div 
      className={`relative border-2 border-dashed rounded-xl p-8 transition-all text-center overflow-hidden ${
        dragActive 
          ? 'border-indigo-500 bg-indigo-50' 
          : 'border-gray-300 hover:border-gray-400 bg-white'
      }`}
      onDragEnter={handleDrag}
      onDragLeave={handleDrag}
      onDragOver={handleDrag}
      onDrop={handleDrop}
    >
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        onChange={handleChange}
        className="hidden"
        disabled={isLoading}
      />

      {isLoading ? (
        <div className="flex flex-col items-center justify-center py-2 animate-in fade-in duration-300">
           <div className="relative mb-4">
             <div className="absolute inset-0 bg-indigo-200 rounded-full animate-ping opacity-75"></div>
             <div className="relative bg-white p-3 rounded-full shadow-sm z-10">
               <SparklesIcon className="w-8 h-8 text-indigo-600 animate-pulse" />
             </div>
           </div>

           <h3 className="text-lg font-medium text-gray-900">{t.upload.analyzing}</h3>
           <p className="text-sm text-gray-500 mt-1 mb-6">{t.upload.extracting}</p>

           <div className="w-full max-w-xs mb-6">
             <div className="flex justify-between text-xs text-gray-500 mb-1.5 font-medium">
               <span>{t.upload.processing}</span>
               <span>{Math.round(progress)}%</span>
             </div>
             <div className="w-full bg-gray-100 rounded-full h-2.5 overflow-hidden border border-gray-200">
               <div
                 className="bg-indigo-600 h-2.5 rounded-full transition-all duration-300 ease-out shadow-[0_0_10px_rgba(79,70,229,0.3)]"
                 style={{ width: `${progress}%` }}
               ></div>
             </div>
           </div>

           {onCancel && (
             <button
               onClick={(e) => {
                 e.stopPropagation();
                 onCancel();
               }}
               className="flex items-center gap-1.5 px-4 py-2 bg-white text-red-600 rounded-full text-xs font-semibold hover:bg-red-50 transition-colors border border-red-200 shadow-sm"
             >
               <XCircleIcon className="w-4 h-4" />
               {t.upload.cancel}
             </button>
           )}
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center gap-3">
          <div className="bg-indigo-100 p-3 rounded-full">
            <CloudArrowUpIcon className="w-8 h-8 text-indigo-600" />
          </div>
          <div>
            <h3 className="text-lg font-medium text-gray-900">{t.upload.title}</h3>
            <p className="text-sm text-gray-500 mt-1">{t.upload.subtitle}</p>
          </div>
          <button
            onClick={() => fileInputRef.current?.click()}
            className="mt-2 px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-medium hover:bg-indigo-700 transition-colors shadow-sm"
          >
            {t.upload.selectFile}
          </button>
          <p className="text-xs text-gray-400 mt-2">{t.upload.support}</p>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useMemo, useEffect, useCallback } from 'react';
import { FileUpload } from './components/FileUpload';
import { TablePreview } from './components/TablePreview';
import { BasicsForm } from './components/BasicsForm';
import { SmartSplitter } from './components/SmartSplitter';
import { generateCSV, downloadCSV, generateJSON, downloadJSON, DEFAULT_HEADERS } from './utils/csvHelper';
import { CSVRow, StudyMetadata } from './types';
import { UILanguage, translations } from './utils/translations';
import { 
  ArrowDownTrayIcon, 
  TableCellsIcon, 
  PhotoIcon,
  PencilSquareIcon,
  ScissorsIcon,
  CommandLineIcon,
  TrashIcon,
  ChevronUpIcon,
  ChevronDownIcon,
  SparklesIcon,
  PlusIcon,
  DocumentArrowDownIcon,
  LanguageIcon,
  ComputerDesktopIcon
} from '@heroicons/react/24/outline';

const DAY_MAP: Record<string, string> = {
  '1': 'Saturday', '2': 'Sunday', '3': 'Monday', '4': 'Tuesday', '5': 'Wednesday', '6': 'Thursday', '7': 'Friday',
};

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

const App: React.FC = () => {
  const [uiLanguage, setUiLanguage] = useState<UILanguage>('pt');
  const t = translations[uiLanguage];

  // Logic to prevent mobile use
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 1024);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const [basics, setBasics] = useState<StudyMetadata & { lesson_title: string }>({
    week_number: '', week_title: '', day_number: '', day_name: '', language: '', lesson_title: ''
  });

  const [activeTab, setActiveTab] = useState<'upload' | 'basics' | 'smart'>('basics');
  const [generatedData, setGeneratedData] = useState<CSVRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [columnOrder, setColumnOrder] = useState<(keyof CSVRow)[]>(DEFAULT_HEADERS);
  const [smartBlocks, setSmartBlocks] = useState<SplitBlock[]>([]);

  const canProcess = useMemo(() => {
    const basicsDone = basics.week_title.trim().length > 0 && basics.day_name.trim().length > 0;
    const hasBlocks = smartBlocks.length > 0;
    return basicsDone && hasBlocks;
  }, [basics, smartBlocks]);

  const syncTableFromBlocks = useCallback((currentBlocks: SplitBlock[], currentBasics: typeof basics) => {
    if (currentBlocks.length === 0) return;

    const row: Partial<CSVRow> = { ...currentBasics };
    let textCount = 0;
    let questionCount = 0;

    currentBlocks.forEach(block => {
      if (block.type === 't') {
        row.lesson_title = block.text;
      } else if (block.type === 'q') {
        questionCount++;
        const qKey = `question_${questionCount}` as keyof CSVRow;
        if (questionCount <= 4) {
          (row as any)[qKey] = block.text;
          (row as any)[`input_${questionCount}`] = "";
        }
      } else if (block.type === 'x') {
        textCount++;
        if (questionCount === 0) {
          if (textCount === 1) row.text_1 = block.text;
          else if (textCount === 2) row.text_2 = block.text;
          else row.text_3 = (row.text_3 ? row.text_3 + '\n' : '') + block.text;
        } else if (questionCount === 1) {
          row.text_4 = (row.text_4 ? row.text_4 + '\n' : '') + block.text;
        } else if (questionCount === 2) {
          row.text_5 = (row.text_5 ? row.text_5 + '\n' : '') + block.text;
        } else if (questionCount === 3) {
          row.text_6 = (row.text_6 ? row.text_6 + '\n' : '') + block.text;
        } else if (questionCount >= 4) {
          if (!row.text_7) row.text_7 = block.text;
          else row.text_8 = (row.text_8 ? row.text_8 + '\n' : '') + block.text;
        }
      }
    });

    setGeneratedData([row as CSVRow]);
  }, []);

  useEffect(() => {
    if (generatedData.length > 0) {
        syncTableFromBlocks(smartBlocks, basics);
    }
  }, [basics, smartBlocks, syncTableFromBlocks, generatedData.length]);

  const handleBasicsChange = (field: string, value: string) => {
    setBasics(prev => {
      const updated = { ...prev, [field]: value };
      if (field === 'day_number') {
        const mappedName = DAY_MAP[value];
        if (mappedName) updated.day_name = mappedName;
      } else if (field === 'day_name') {
        const mappedNumber = Object.keys(DAY_MAP).find(key => DAY_MAP[key] === value);
        if (mappedNumber) updated.day_number = mappedNumber;
      }
      return updated;
    });
  };

  const finalizeProcess = () => {
    syncTableFromBlocks(smartBlocks, basics);
    setActiveTab('basics');
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    if ((direction === 'up' && index === 0) || (direction === 'down' && index === smartBlocks.length - 1)) return;
    const newBlocks = [...smartBlocks];
    const swapIdx = direction === 'up' ? index - 1 : index + 1;
    [newBlocks[index], newBlocks[swapIdx]] = [newBlocks[swapIdx], newBlocks[index]];
    setSmartBlocks(newBlocks);
  };

  const addNewBlock = () => {
    const newBlock: SplitBlock = {
        id: crypto.randomUUID(),
        type: 'x',
        text: ''
    };
    setSmartBlocks(prev => [...prev, newBlock]);
  };

  const updateBlockText = (id: string, text: string) => {
    setSmartBlocks(prev => prev.map(b => b.id === id ? { ...b, text } : b));
  };

  const toggleBlockType = (id: string) => {
    const types: ('t' | 'x' | 'q')[] = ['t', 'x', 'q'];
    setSmartBlocks(prev => prev.map(b => {
        if (b.id === id) {
            const nextIdx = (types.indexOf(b.type) + 1) % types.length;
            return { ...b, type: types[nextIdx] };
        }
        return b;
    }));
  };

  const handleMoveColumn = (index: number, direction: 'left' | 'right') => {
    const newOrder = [...columnOrder];
    const targetIdx = direction === 'left' ? index - 1 : index + 1;
    [newOrder[index], newOrder[targetIdx]] = [newOrder[targetIdx], newOrder[index]];
    setColumnOrder(newOrder);
  };

  const handleDeleteColumn = (header: keyof CSVRow) => {
    const msg = t.table.deleteColConfirm.replace('{header}', String(header).replace(/_/g, ' '));
    if (window.confirm(msg)) {
      setColumnOrder(current => current.filter(col => col !== header));
    }
  };

  const handleExportJSON = () => {
    if (!basics.week_number) {
        alert(t.export.weekRequired);
        return;
    }
    const jsonStr = generateJSON(basics, smartBlocks);
    downloadJSON(jsonStr, `${basics.week_title || 'export'} - ${basics.day_name || 'day'}.json`);
  };

  // Mobile Blocking Screen
  if (isMobile) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-500">
        <div className="absolute top-8 right-8">
           <div className="flex items-center gap-2 bg-white border border-gray-200 rounded-xl px-2 py-1 shadow-sm">
             <LanguageIcon className="w-4 h-4 text-gray-400" />
             <select 
               value={uiLanguage}
               onChange={(e) => setUiLanguage(e.target.value as UILanguage)}
               className="bg-transparent border-none focus:ring-0 text-xs font-bold uppercase text-gray-600 cursor-pointer"
             >
               <option value="pt">Português</option>
               <option value="en">English</option>
               <option value="es">Español</option>
             </select>
           </div>
        </div>
        <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-gray-100 flex flex-col items-center max-w-lg">
          <div className="bg-indigo-50 p-6 rounded-full mb-8">
            <ComputerDesktopIcon className="w-16 h-16 text-indigo-600" />
          </div>
          <h2 className="text-3xl font-black text-gray-900 mb-6 tracking-tight">{t.mobileBlock.title}</h2>
          <p className="text-gray-500 text-base leading-relaxed font-medium">
            {t.mobileBlock.message}
          </p>
          <div className="mt-10 h-1.5 w-24 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-indigo-600 w-1/2 animate-[shimmer_2s_infinite_linear]"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-lg shadow-indigo-100">
              <TableCellsIcon className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">{t.appTitle}</h1>
          </div>
          <div className="flex items-center gap-4">
             {/* Language Selector */}
             <div className="flex items-center gap-2 bg-gray-50 border border-gray-200 rounded-xl px-2 py-1">
               <LanguageIcon className="w-4 h-4 text-gray-400" />
               <select 
                 value={uiLanguage}
                 onChange={(e) => setUiLanguage(e.target.value as UILanguage)}
                 className="bg-transparent border-none focus:ring-0 text-xs font-bold uppercase text-gray-600 cursor-pointer"
               >
                 <option value="pt">Português</option>
                 <option value="en">English</option>
                 <option value="es">Español</option>
               </select>
             </div>

             {generatedData.length > 0 && (
                <div className="flex items-center gap-2">
                  <button
                    onClick={handleExportJSON}
                    className="flex items-center gap-2 px-4 py-2 bg-white hover:bg-gray-50 text-indigo-600 border border-indigo-100 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-sm active:scale-95"
                  >
                    <DocumentArrowDownIcon className="w-4 h-4" /> {t.export.json}
                  </button>
                  <button
                    onClick={() => downloadCSV(generateCSV(generatedData, columnOrder), `${basics.week_title} - ${basics.day_name}.csv`)}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-lg shadow-indigo-100 active:scale-95"
                  >
                    <ArrowDownTrayIcon className="w-4 h-4" /> {t.export.csv}
                  </button>
                </div>
             )}
          </div>
        </div>
      </header>

      <main className="flex-1 p-4 sm:p-6 lg:p-8 overflow-hidden">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-10rem)]">

          <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-hidden">
            <div className="overflow-y-auto custom-scrollbar flex-1 space-y-6 pr-1">

              <section className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden flex flex-col">
                <div className="flex border-b border-gray-200 bg-gray-50/50">
                  <button onClick={() => setActiveTab('basics')} className={`flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'basics' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PencilSquareIcon className="w-3.5 h-3.5" /> {t.tabs.basics}
                  </button>
                  <button onClick={() => setActiveTab('smart')} className={`flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'smart' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <ScissorsIcon className="w-3.5 h-3.5" /> {t.tabs.smart}
                  </button>
                  <button onClick={() => setActiveTab('upload')} className={`flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'upload' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PhotoIcon className="w-3.5 h-3.5" /> {t.tabs.upload}
                  </button>
                </div>

                <div className="p-5">
                  {activeTab === 'basics' && <BasicsForm metadata={basics} onChange={handleBasicsChange} disabled={isLoading} uiLanguage={uiLanguage} />}

                  {activeTab === 'smart' && (
                    <div className="space-y-4">
                      <div className="flex items-center justify-between">
                        <h3 className="text-[10px] font-black text-gray-900 uppercase tracking-widest">{t.smart.blockEditor}</h3>
                        <span className="bg-indigo-100 text-indigo-600 px-2.5 py-1 rounded-lg text-[9px] font-black">{smartBlocks.length}</span>
                      </div>

                      <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-1">
                        {smartBlocks.length === 0 ? (
                          <div className="border-2 border-dashed border-gray-100 rounded-2xl p-8 text-center bg-gray-50/30">
                            <CommandLineIcon className="w-8 h-8 text-gray-200 mx-auto mb-3" />
                            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest leading-relaxed">{t.smart.emptyState}</p>
                          </div>
                        ) : (
                          smartBlocks.map((block, idx) => (
                            <div key={block.id} className="group bg-white border border-gray-100 rounded-2xl p-3 shadow-sm hover:border-indigo-200 transition-all animate-in slide-in-from-bottom-2">
                              <div className="flex items-center justify-between mb-2">
                                <button 
                                    onClick={() => toggleBlockType(block.id)}
                                    className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-full cursor-pointer hover:opacity-80 transition-opacity ${
                                        block.type === 't' ? 'bg-purple-100 text-purple-700' :
                                        block.type === 'q' ? 'bg-amber-100 text-amber-700' :
                                        'bg-blue-100 text-blue-700'
                                    }`}
                                >
                                    {block.type === 't' ? t.smart.t : block.type === 'q' ? t.smart.q : t.smart.x}
                                </button>
                                <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => moveBlock(idx, 'up')} className="p-1 text-gray-300 hover:text-indigo-600"><ChevronUpIcon className="w-3 h-3"/></button>
                                    <button onClick={() => moveBlock(idx, 'down')} className="p-1 text-gray-300 hover:text-indigo-600"><ChevronDownIcon className="w-3 h-3"/></button>
                                    <button onClick={() => setSmartBlocks(prev => prev.filter(b => b.id !== block.id))} className="p-1 text-gray-300 hover:text-red-500 ml-1"><TrashIcon className="w-3 h-3"/></button>
                                </div>
                              </div>
                              <textarea 
                                value={block.text}
                                onChange={(e) => updateBlockText(block.id, e.target.value)}
                                className="w-full bg-gray-50 rounded-lg p-2 text-[11px] text-gray-600 border-none focus:ring-1 focus:ring-indigo-100 resize-none min-h-[40px] custom-scrollbar"
                              />
                            </div>
                          ))
                        )}
                      </div>

                      <div className="grid grid-cols-1 gap-3">
                        <button 
                            onClick={addNewBlock}
                            className="w-full py-3 bg-gray-50 hover:bg-gray-100 text-gray-500 rounded-xl text-[9px] font-black uppercase tracking-widest border border-dashed border-gray-200 flex items-center justify-center gap-2 transition-all shadow-sm"
                        >
                            <PlusIcon className="w-3.5 h-3.5" /> {t.smart.addBlock}
                        </button>

                        {canProcess && (
                            <button 
                                onClick={finalizeProcess}
                                className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 flex items-center justify-center gap-2 animate-in zoom-in-95"
                            >
                                <SparklesIcon className="w-4 h-4" /> {generatedData.length > 0 ? t.smart.updateTable : t.smart.generateTable}
                            </button>
                        )}
                      </div>
                    </div>
                  )}
                  {activeTab === 'upload' && <FileUpload onFileSelect={() => {}} isLoading={isLoading} uiLanguage={uiLanguage} />}
                </div>
              </section>
            </div>
          </div>

          <div className="lg:col-span-8 h-full">
            {activeTab === 'smart' ? (
              <SmartSplitter 
                onBlocksUpdate={setSmartBlocks}
                blocks={smartBlocks}
                uiLanguage={uiLanguage}
              />
            ) : generatedData.length > 0 ? (
              <TablePreview 
                data={generatedData} 
                columns={columnOrder} 
                onMoveColumn={handleMoveColumn}
                onDeleteColumn={handleDeleteColumn}
                onClear={() => {
                  if(confirm(t.table.confirmClear)) {
                    setGeneratedData([]); 
                    setSmartBlocks([]);
                  }
                }} 
                uiLanguage={uiLanguage}
              />
            ) : (
              <div className="h-full bg-white rounded-3xl shadow-sm border border-gray-200 flex flex-col items-center justify-center text-center p-12">
                <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] flex items-center justify-center mb-8 transform rotate-3 hover:rotate-0 transition-transform duration-500">
                  <CommandLineIcon className="w-12 h-12 text-indigo-100" />
                </div>
                <h3 className="text-2xl font-black text-gray-900 tracking-tight">{t.welcome.title}</h3>
                <p className="text-gray-400 max-w-sm mt-4 text-sm leading-relaxed font-medium">
                  {t.welcome.description}
                </p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect, useCallback } from 'react';
import { FileUpload } from './components/FileUpload';
import { TablePreview } from './components/TablePreview';
import { BasicsForm } from './components/BasicsForm';
import { SmartSplitter } from './components/SmartSplitter';
import { generateCSV, downloadCSV, generateJSON, downloadJSON, DEFAULT_HEADERS } from './utils/csvHelper';
import { processImageWithGemini } from './services/geminiService';
import { CSVRow, StudyMetadata } from './types';
import { UILanguage, translations } from './utils/translations';
import { 
  ArrowDownTrayIcon, 
  TableCellsIcon, 
  PhotoIcon,
  PencilSquareIcon,
  ScissorsIcon,
  CommandLineIcon,
  TrashIcon,
  ChevronUpIcon,
  ChevronDownIcon,
  SparklesIcon,
  PlusIcon,
  DocumentArrowDownIcon,
  LanguageIcon,
  ComputerDesktopIcon
} from '@heroicons/react/24/outline';

const DAY_MAP: Record<string, string> = {
  '1': 'Saturday', '2': 'Sunday', '3': 'Monday', '4': 'Tuesday', '5': 'Wednesday', '6': 'Thursday', '7': 'Friday',
};

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

const App: React.FC = () => {
  const [uiLanguage, setUiLanguage] = useState<UILanguage>('pt');
  const t = translations[uiLanguage];

  // Logic to prevent mobile use
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 1024);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const [basics, setBasics] = useState<StudyMetadata & { lesson_title: string }>({
    week_number: '', week_title: '', day_number: '', day_name: '', language: '', lesson_title: ''
  });

  const [activeTab, setActiveTab] = useState<'upload' | 'basics' | 'smart'>('basics');
  const [generatedData, setGeneratedData] = useState<CSVRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [extractionProgress, setExtractionProgress] = useState(0);
  const [columnOrder, setColumnOrder] = useState<(keyof CSVRow)[]>(DEFAULT_HEADERS);
  const [smartBlocks, setSmartBlocks] = useState<SplitBlock[]>([]);

  const canProcess = useMemo(() => {
    const basicsDone = basics.week_title.trim().length > 0 && basics.day_name.trim().length > 0;
    const hasBlocks = smartBlocks.length > 0;
    return basicsDone && hasBlocks;
  }, [basics, smartBlocks]);

  const syncTableFromBlocks = useCallback((currentBlocks: SplitBlock[], currentBasics: typeof basics) => {
    if (currentBlocks.length === 0) return;

    const row: Partial<CSVRow> = { ...currentBasics };
    let textCount = 0;
    let questionCount = 0;

    currentBlocks.forEach(block => {
      if (block.type === 't') {
        row.lesson_title = block.text;
      } else if (block.type === 'q') {
        questionCount++;
        const qKey = `question_${questionCount}` as keyof CSVRow;
        if (questionCount <= 4) {
          (row as any)[qKey] = block.text;
          (row as any)[`input_${questionCount}`] = "";
        }
      } else if (block.type === 'x') {
        textCount++;
        if (questionCount === 0) {
          if (textCount === 1) row.text_1 = block.text;
          else if (textCount === 2) row.text_2 = block.text;
          else row.text_3 = (row.text_3 ? row.text_3 + '\n' : '') + block.text;
        } else if (questionCount === 1) {
          row.text_4 = (row.text_4 ? row.text_4 + '\n' : '') + block.text;
        } else if (questionCount === 2) {
          row.text_5 = (row.text_5 ? row.text_5 + '\n' : '') + block.text;
        } else if (questionCount === 3) {
          row.text_6 = (row.text_6 ? row.text_6 + '\n' : '') + block.text;
        } else if (questionCount >= 4) {
          if (!row.text_7) row.text_7 = block.text;
          else row.text_8 = (row.text_8 ? row.text_8 + '\n' : '') + block.text;
        }
      }
    });

    setGeneratedData([row as CSVRow]);
  }, []);

  useEffect(() => {
    if (generatedData.length > 0) {
        syncTableFromBlocks(smartBlocks, basics);
    }
  }, [basics, smartBlocks, syncTableFromBlocks, generatedData.length]);

  const handleBasicsChange = (field: string, value: string) => {
    setBasics(prev => {
      const updated = { ...prev, [field]: value };
      if (field === 'day_number') {
        const mappedName = DAY_MAP[value];
        if (mappedName) updated.day_name = mappedName;
      } else if (field === 'day_name') {
        const mappedNumber = Object.keys(DAY_MAP).find(key => DAY_MAP[key] === value);
        if (mappedNumber) updated.day_number = mappedNumber;
      }
      return updated;
    });
  };

  const handleImageProcess = async (base64: string) => {
    setIsLoading(true);
    setExtractionProgress(0);
    abortControllerRef.current = new AbortController();

    try {
      const results = await processImageWithGemini(
        base64, 
        abortControllerRef.current.signal,
        (prog) => setExtractionProgress(prog)
      );

      if (results && results.length > 0) {
        const data = results[0];

        // Populate basic lesson title
        if (data.lesson_title) {
          setBasics(prev => ({ ...prev, lesson_title: data.lesson_title || '' }));
        }

        // Convert structured OCR data to Blocks for Smart Split refinement
        const newBlocks: SplitBlock[] = [];

        if (data.lesson_title) newBlocks.push({ id: crypto.randomUUID(), type: 't', text: data.lesson_title });
        if (data.text_1) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_1 });
        if (data.text_2) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_2 });
        if (data.text_3) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_3 });

        if (data.question_1) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_1 });
        if (data.text_4) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_4 });

        if (data.question_2) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_2 });
        if (data.text_5) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_5 });

        if (data.question_3) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_3 });
        if (data.text_6) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_6 });

        if (data.question_4) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_4 });
        if (data.text_7) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_7 });
        if (data.text_8) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_8 });

        setSmartBlocks(newBlocks);
        syncTableFromBlocks(newBlocks, basics);

        // Auto-navigate to smart split to let user refine
        setActiveTab('smart');
      }
    } catch (err: any) {
      if (err.name !== 'AbortError') {
        alert("Falha na extração: " + err.message);
      }
    } finally {
      setIsLoading(false);
      setExtractionProgress(0);
      abortControllerRef.current = null;
    }
  };

  const handleCancelProcess = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
  };

  const finalizeProcess = () => {
    syncTableFromBlocks(smartBlocks, basics);
    setActiveTab('basics');
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    if ((direction === 'up' && index === 0) || (direction === 'down' && index === smartBlocks.length - 1)) return;
    const newBlocks = [...smartBlocks];
    const swapIdx = direction === 'up' ? index - 1 : index + 1;
    [newBlocks[index], newBlocks[swapIdx]] = [newBlocks[swapIdx], newBlocks[index]];
    setSmartBlocks(newBlocks);
  };

  const addNewBlock = () => {
    const newBlock: SplitBlock = {
        id: crypto.randomUUID(),
        type: 'x',
        text: ''
    };
    setSmartBlocks(prev => [...prev, newBlock]);
  };

  const updateBlockText = (id: string, text: string) => {
    setSmartBlocks(prev => prev.map(b => b.id === id ? { ...b, text } : b));
  };

  const toggleBlockType = (id: string) => {
    const types: ('t' | 'x' | 'q')[] = ['t', 'x', 'q'];
    setSmartBlocks(prev => prev.map(b => {
        if (b.id === id) {
            const nextIdx = (types.indexOf(b.type) + 1) % types.length;
            return { ...b, type: types[nextIdx] };
        }
        return b;
    }));
  };

  const handleMoveColumn = (index: number, direction: 'left' | 'right') => {
    const newOrder = [...columnOrder];
    const targetIdx = direction === 'left' ? index - 1 : index + 1;
    [newOrder[index], newOrder[targetIdx]] = [newOrder[targetIdx], newOrder[index]];
    setColumnOrder(newOrder);
  };

  const handleDeleteColumn = (header: keyof CSVRow) => {
    const msg = t.table.deleteColConfirm.replace('{header}', String(header).replace(/_/g, ' '));
    if (window.confirm(msg)) {
      setColumnOrder(current => current.filter(col => col !== header));
    }
  };

  const handleExportJSON = () => {
    if (!basics.week_number) {
        alert(t.export.weekRequired);
        return;
    }
    const jsonStr = generateJSON(basics, smartBlocks);
    downloadJSON(jsonStr, `${basics.week_title || 'export'} - ${basics.day_name || 'day'}.json`);
  };

  // Mobile Blocking Screen
  if (isMobile) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-500">
        <div className="absolute top-8 right-8">
           <div className="flex items-center gap-2 bg-white border border-gray-200 rounded-xl px-2 py-1 shadow-sm">
             <LanguageIcon className="w-4 h-4 text-gray-400" />
             <select 
               value={uiLanguage}
               onChange={(e) => setUiLanguage(e.target.value as UILanguage)}
               className="bg-transparent border-none focus:ring-0 text-xs font-bold uppercase text-gray-600 cursor-pointer"
             >
               <option value="pt">Português</option>
               <option value="en">English</option>
               <option value="es">Español</option>
             </select>
           </div>
        </div>
        <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-gray-100 flex flex-col items-center max-w-lg">
          <div className="bg-indigo-50 p-6 rounded-full mb-8">
            <ComputerDesktopIcon className="w-16 h-16 text-indigo-600" />
          </div>
          <h2 className="text-3xl font-black text-gray-900 mb-6 tracking-tight">{t.mobileBlock.title}</h2>
          <p className="text-gray-500 text-base leading-relaxed font-medium">
            {t.mobileBlock.message}
          </p>
          <div className="mt-10 h-1.5 w-24 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-indigo-600 w-1/2 animate-[shimmer_2s_infinite_linear]"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-lg shadow-indigo-100">
              <TableCellsIcon className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">{t.appTitle}</h1>
          </div>
          <div className="flex items-center gap-4">
             {/* Language Selector */}
             <div className="flex items-center gap-2 bg-gray-50 border border-gray-200 rounded-xl px-2 py-1">
               <LanguageIcon className="w-4 h-4 text-gray-400" />
               <select 
                 value={uiLanguage}
                 onChange={(e) => setUiLanguage(e.target.value as UILanguage)}
                 className="bg-transparent border-none focus:ring-0 text-xs font-bold uppercase text-gray-600 cursor-pointer"
               >
                 <option value="pt">Português</option>
                 <option value="en">English</option>
                 <option value="es">Español</option>
               </select>
             </div>

             {generatedData.length > 0 && (
                <div className="flex items-center gap-2">
                  <button
                    onClick={handleExportJSON}
                    className="flex items-center gap-2 px-4 py-2 bg-white hover:bg-gray-50 text-indigo-600 border border-indigo-100 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-sm active:scale-95"
                  >
                    <DocumentArrowDownIcon className="w-4 h-4" /> {t.export.json}
                  </button>
                  <button
                    onClick={() => downloadCSV(generateCSV(generatedData, columnOrder), `${basics.week_title} - ${basics.day_name}.csv`)}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-lg shadow-indigo-100 active:scale-95"
                  >
                    <ArrowDownTrayIcon className="w-4 h-4" /> {t.export.csv}
                  </button>
                </div>
             )}
          </div>
        </div>
      </header>

      <main className="flex-1 p-4 sm:p-6 lg:p-8 overflow-hidden">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-10rem)]">

          <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-hidden">
            <div className="overflow-y-auto custom-scrollbar flex-1 space-y-6 pr-1">

              <section className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden flex flex-col">
                <div className="flex border-b border-gray-200 bg-gray-50/50">
                  <button onClick={() => setActiveTab('basics')} className={`flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'basics' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PencilSquareIcon className="w-3.5 h-3.5" /> {t.tabs.basics}
                  </button>
                  <button onClick={() => setActiveTab('smart')} className={`flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'smart' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <ScissorsIcon className="w-3.5 h-3.5" /> {t.tabs.smart}
                  </button>
                  <button onClick={() => setActiveTab('upload')} className={`flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'upload' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PhotoIcon className="w-3.5 h-3.5" /> {t.tabs.upload}
                  </button>
                </div>

                <div className="p-5">
                  {activeTab === 'basics' && <BasicsForm metadata={basics} onChange={handleBasicsChange} disabled={isLoading} uiLanguage={uiLanguage} />}

                  {activeTab === 'smart' && (
                    <div className="space-y-4">
                      <div className="flex items-center justify-between">
                        <h3 className="text-[10px] font-black text-gray-900 uppercase tracking-widest">{t.smart.blockEditor}</h3>
                        <span className="bg-indigo-100 text-indigo-600 px-2.5 py-1 rounded-lg text-[9px] font-black">{smartBlocks.length}</span>
                      </div>

                      <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-1">
                        {smartBlocks.length === 0 ? (
                          <div className="border-2 border-dashed border-gray-100 rounded-2xl p-8 text-center bg-gray-50/30">
                            <CommandLineIcon className="w-8 h-8 text-gray-200 mx-auto mb-3" />
                            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest leading-relaxed">{t.smart.emptyState}</p>
                          </div>
                        ) : (
                          smartBlocks.map((block, idx) => (
                            <div key={block.id} className="group bg-white border border-gray-100 rounded-2xl p-3 shadow-sm hover:border-indigo-200 transition-all animate-in slide-in-from-bottom-2">
                              <div className="flex items-center justify-between mb-2">
                                <button 
                                    onClick={() => toggleBlockType(block.id)}
                                    className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-full cursor-pointer hover:opacity-80 transition-opacity ${
                                        block.type === 't' ? 'bg-purple-100 text-purple-700' :
                                        block.type === 'q' ? 'bg-amber-100 text-amber-700' :
                                        'bg-blue-100 text-blue-700'
                                    }`}
                                >
                                    {block.type === 't' ? t.smart.t : block.type === 'q' ? t.smart.q : t.smart.x}
                                </button>
                                <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => moveBlock(idx, 'up')} className="p-1 text-gray-300 hover:text-indigo-600"><ChevronUpIcon className="w-3 h-3"/></button>
                                    <button onClick={() => moveBlock(idx, 'down')} className="p-1 text-gray-300 hover:text-indigo-600"><ChevronDownIcon className="w-3 h-3"/></button>
                                    <button onClick={() => setSmartBlocks(prev => prev.filter(b => b.id !== block.id))} className="p-1 text-gray-300 hover:text-red-500 ml-1"><TrashIcon className="w-3 h-3"/></button>
                                </div>
                              </div>
                              <textarea 
                                value={block.text}
                                onChange={(e) => updateBlockText(block.id, e.target.value)}
                                className="w-full bg-gray-50 rounded-lg p-2 text-[11px] text-gray-600 border-none focus:ring-1 focus:ring-indigo-100 resize-none min-h-[40px] custom-scrollbar"
                              />
                            </div>
                          ))
                        )}
                      </div>

                      <div className="grid grid-cols-1 gap-3">
                        <button 
                            onClick={addNewBlock}
                            className="w-full py-3 bg-gray-50 hover:bg-gray-100 text-gray-500 rounded-xl text-[9px] font-black uppercase tracking-widest border border-dashed border-gray-200 flex items-center justify-center gap-2 transition-all shadow-sm"
                        >
                            <PlusIcon className="w-3.5 h-3.5" /> {t.smart.addBlock}
                        </button>

                        {canProcess && (
                            <button 
                                onClick={finalizeProcess}
                                className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 flex items-center justify-center gap-2 animate-in zoom-in-95"
                            >
                                <SparklesIcon className="w-4 h-4" /> {generatedData.length > 0 ? t.smart.updateTable : t.smart.generateTable}
                            </button>
                        )}
                      </div>
                    </div>
                  )}
                  {activeTab === 'upload' && (
                    <FileUpload 
                      onFileSelect={handleImageProcess} 
                      onCancel={handleCancelProcess}
                      isLoading={isLoading} 
                      progress={extractionProgress}
                      uiLanguage={uiLanguage} 
                    />
                  )}
                </div>
              </section>
            </div>
          </div>

          <div className="lg:col-span-8 h-full">
            {activeTab === 'smart' ? (
              <SmartSplitter 
                onBlocksUpdate={setSmartBlocks}
                blocks={smartBlocks}
                uiLanguage={uiLanguage}
              />
            ) : generatedData.length > 0 ? (
              <TablePreview 
                data={generatedData} 
                columns={columnOrder} 
                onMoveColumn={handleMoveColumn}
                onDeleteColumn={handleDeleteColumn}
                onClear={() => {
                  if(confirm(t.table.confirmClear)) {
                    setGeneratedData([]); 
                    setSmartBlocks([]);
                  }
                }} 
                uiLanguage={uiLanguage}
              />
            ) : (
              <div className="h-full bg-white rounded-3xl shadow-sm border border-gray-200 flex flex-col items-center justify-center text-center p-12">
                <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] flex items-center justify-center mb-8 transform rotate-3 hover:rotate-0 transition-transform duration-500">
                  <CommandLineIcon className="w-12 h-12 text-indigo-100" />
                </div>
                <h3 className="text-2xl font-black text-gray-900 tracking-tight">{t.welcome.title}</h3>
                <p className="text-gray-400 max-w-sm mt-4 text-sm leading-relaxed font-medium">
                  {t.welcome.description}
                </p>
              </div>
            )}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect, useCallback } from 'react';
import { FileUpload } from './components/FileUpload';
import { TablePreview } from './components/TablePreview';
import { BasicsForm } from './components/BasicsForm';
import { SmartSplitter } from './components/SmartSplitter';
import { generateCSV, downloadCSV, generateJSON, downloadJSON, DEFAULT_HEADERS } from './utils/csvHelper';
import { processImageWithGemini } from './services/geminiService';
import { CSVRow, StudyMetadata } from './types';
import { UILanguage, translations } from './utils/translations';
import { 
  ArrowDownTrayIcon, 
  TableCellsIcon, 
  PhotoIcon,
  PencilSquareIcon,
  ScissorsIcon,
  CommandLineIcon,
  TrashIcon,
  ChevronUpIcon,
  ChevronDownIcon,
  SparklesIcon,
  PlusIcon,
  DocumentArrowDownIcon,
  LanguageIcon,
  ComputerDesktopIcon,
  ArrowsPointingOutIcon,
  XMarkIcon
} from '@heroicons/react/24/outline';

const DAY_MAP: Record<string, string> = {
  '1': 'Saturday', '2': 'Sunday', '3': 'Monday', '4': 'Tuesday', '5': 'Wednesday', '6': 'Thursday', '7': 'Friday',
};

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

const App: React.FC = () => {
  const [uiLanguage, setUiLanguage] = useState<UILanguage>('pt');
  const t = translations[uiLanguage];

  // Logic to prevent mobile use
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 1024);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const [basics, setBasics] = useState<StudyMetadata & { lesson_title: string }>({
    week_number: '', week_title: '', day_number: '', day_name: '', language: '', lesson_title: ''
  });

  const [activeTab, setActiveTab] = useState<'upload' | 'basics' | 'smart'>('basics');
  const [generatedData, setGeneratedData] = useState<CSVRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [extractionProgress, setExtractionProgress] = useState(0);
  const [columnOrder, setColumnOrder] = useState<(keyof CSVRow)[]>(DEFAULT_HEADERS);
  const [smartBlocks, setSmartBlocks] = useState<SplitBlock[]>([]);

  // State for Focus Edit Modal
  const [editingBlockId, setEditingBlockId] = useState<string | null>(null);
  const [focusEditText, setFocusEditText] = useState('');

  const canProcess = useMemo(() => {
    const basicsDone = basics.week_title.trim().length > 0 && basics.day_name.trim().length > 0;
    const hasBlocks = smartBlocks.length > 0;
    return basicsDone && hasBlocks;
  }, [basics, smartBlocks]);

  const syncTableFromBlocks = useCallback((currentBlocks: SplitBlock[], currentBasics: typeof basics) => {
    if (currentBlocks.length === 0) return;

    const row: Partial<CSVRow> = { ...currentBasics };
    let textCount = 0;
    let questionCount = 0;

    currentBlocks.forEach(block => {
      if (block.type === 't') {
        row.lesson_title = block.text;
      } else if (block.type === 'q') {
        questionCount++;
        const qKey = `question_${questionCount}` as keyof CSVRow;
        if (questionCount <= 4) {
          (row as any)[qKey] = block.text;
          (row as any)[`input_${questionCount}`] = "";
        }
      } else if (block.type === 'x') {
        textCount++;
        if (questionCount === 0) {
          if (textCount === 1) row.text_1 = block.text;
          else if (textCount === 2) row.text_2 = block.text;
          else row.text_3 = (row.text_3 ? row.text_3 + '\n' : '') + block.text;
        } else if (questionCount === 1) {
          row.text_4 = (row.text_4 ? row.text_4 + '\n' : '') + block.text;
        } else if (questionCount === 2) {
          row.text_5 = (row.text_5 ? row.text_5 + '\n' : '') + block.text;
        } else if (questionCount === 3) {
          row.text_6 = (row.text_6 ? row.text_6 + '\n' : '') + block.text;
        } else if (questionCount >= 4) {
          if (!row.text_7) row.text_7 = block.text;
          else row.text_8 = (row.text_8 ? row.text_8 + '\n' : '') + block.text;
        }
      }
    });

    setGeneratedData([row as CSVRow]);
  }, []);

  useEffect(() => {
    if (generatedData.length > 0) {
        syncTableFromBlocks(smartBlocks, basics);
    }
  }, [basics, smartBlocks, syncTableFromBlocks, generatedData.length]);

  const handleBasicsChange = (field: string, value: string) => {
    setBasics(prev => {
      const updated = { ...prev, [field]: value };
      if (field === 'day_number') {
        const mappedName = DAY_MAP[value];
        if (mappedName) updated.day_name = mappedName;
      } else if (field === 'day_name') {
        const mappedNumber = Object.keys(DAY_MAP).find(key => DAY_MAP[key] === value);
        if (mappedNumber) updated.day_number = mappedNumber;
      }
      return updated;
    });
  };

  const handleImageProcess = async (base64: string) => {
    setIsLoading(true);
    setExtractionProgress(0);
    abortControllerRef.current = new AbortController();

    try {
      const results = await processImageWithGemini(
        base64, 
        abortControllerRef.current.signal,
        (prog) => setExtractionProgress(prog)
      );

      if (results && results.length > 0) {
        const data = results[0];

        if (data.lesson_title) {
          setBasics(prev => ({ ...prev, lesson_title: data.lesson_title || '' }));
        }

        const newBlocks: SplitBlock[] = [];

        if (data.lesson_title) newBlocks.push({ id: crypto.randomUUID(), type: 't', text: data.lesson_title });
        if (data.text_1) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_1 });
        if (data.text_2) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_2 });
        if (data.text_3) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_3 });

        if (data.question_1) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_1 });
        if (data.text_4) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_4 });

        if (data.question_2) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_2 });
        if (data.text_5) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_5 });

        if (data.question_3) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_3 });
        if (data.text_6) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_6 });

        if (data.question_4) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_4 });
        if (data.text_7) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_7 });
        if (data.text_8) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_8 });

        setSmartBlocks(newBlocks);
        syncTableFromBlocks(newBlocks, basics);
        setActiveTab('smart');
      }
    } catch (err: any) {
      if (err.name !== 'AbortError') {
        alert("Falha na extração: " + err.message);
      }
    } finally {
      setIsLoading(false);
      setExtractionProgress(0);
      abortControllerRef.current = null;
    }
  };

  const handleCancelProcess = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
  };

  const finalizeProcess = () => {
    syncTableFromBlocks(smartBlocks, basics);
    setActiveTab('basics');
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    if ((direction === 'up' && index === 0) || (direction === 'down' && index === smartBlocks.length - 1)) return;
    const newBlocks = [...smartBlocks];
    const swapIdx = direction === 'up' ? index - 1 : index + 1;
    [newBlocks[index], newBlocks[swapIdx]] = [newBlocks[swapIdx], newBlocks[index]];
    setSmartBlocks(newBlocks);
  };

  const addNewBlock = () => {
    const newBlock: SplitBlock = {
        id: crypto.randomUUID(),
        type: 'x',
        text: ''
    };
    setSmartBlocks(prev => [...prev, newBlock]);
  };

  const updateBlockText = (id: string, text: string) => {
    setSmartBlocks(prev => prev.map(b => b.id === id ? { ...b, text } : b));
  };

  const openFocusModal = (block: SplitBlock) => {
    setEditingBlockId(block.id);
    setFocusEditText(block.text);
  };

  const saveFocusEdit = () => {
    if (editingBlockId) {
      updateBlockText(editingBlockId, focusEditText);
      setEditingBlockId(null);
    }
  };

  const toggleBlockType = (id: string) => {
    const types: ('t' | 'x' | 'q')[] = ['t', 'x', 'q'];
    setSmartBlocks(prev => prev.map(b => {
        if (b.id === id) {
            const nextIdx = (types.indexOf(b.type) + 1) % types.length;
            return { ...b, type: types[nextIdx] };
        }
        return b;
    }));
  };

  const handleMoveColumn = (index: number, direction: 'left' | 'right') => {
    const newOrder = [...columnOrder];
    const targetIdx = direction === 'left' ? index - 1 : index + 1;
    [newOrder[index], newOrder[targetIdx]] = [newOrder[targetIdx], newOrder[index]];
    setColumnOrder(newOrder);
  };

  const handleDeleteColumn = (header: keyof CSVRow) => {
    const msg = t.table.deleteColConfirm.replace('{header}', String(header).replace(/_/g, ' '));
    if (window.confirm(msg)) {
      setColumnOrder(current => current.filter(col => col !== header));
    }
  };

  const handleExportJSON = () => {
    if (!basics.week_number) {
        alert(t.export.weekRequired);
        return;
    }
    const jsonStr = generateJSON(basics, smartBlocks);
    downloadJSON(jsonStr, `${basics.week_title || 'export'} - ${basics.day_name || 'day'}.json`);
  };

  // Mobile Blocking Screen
  if (isMobile) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-500">
        <div className="absolute top-8 right-8">
           <div className="flex items-center gap-2 bg-white border border-gray-200 rounded-xl px-2 py-1 shadow-sm">
             <LanguageIcon className="w-4 h-4 text-gray-400" />
             <select 
               value={uiLanguage}
               onChange={(e) => setUiLanguage(e.target.value as UILanguage)}
               className="bg-transparent border-none focus:ring-0 text-xs font-bold uppercase text-gray-600 cursor-pointer"
             >
               <option value="pt">Português</option>
               <option value="en">English</option>
               <option value="es">Español</option>
             </select>
           </div>
        </div>
        <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-gray-100 flex flex-col items-center max-w-lg">
          <div className="bg-indigo-50 p-6 rounded-full mb-8">
            <ComputerDesktopIcon className="w-16 h-16 text-indigo-600" />
          </div>
          <h2 className="text-3xl font-black text-gray-900 mb-6 tracking-tight">{t.mobileBlock.title}</h2>
          <p className="text-gray-500 text-base leading-relaxed font-medium">
            {t.mobileBlock.message}
          </p>
          <div className="mt-10 h-1.5 w-24 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-indigo-600 w-1/2 animate-[shimmer_2s_infinite_linear]"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-lg shadow-indigo-100">
              <TableCellsIcon className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">{t.appTitle}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="flex items-center gap-2 bg-gray-50 border border-gray-200 rounded-xl px-2 py-1">
               <LanguageIcon className="w-4 h-4 text-gray-400" />
               <select 
                 value={uiLanguage}
                 onChange={(e) => setUiLanguage(e.target.value as UILanguage)}
                 className="bg-transparent border-none focus:ring-0 text-xs font-bold uppercase text-gray-600 cursor-pointer"
               >
                 <option value="pt">Português</option>
                 <option value="en">English</option>
                 <option value="es">Español</option>
               </select>
             </div>

             {generatedData.length > 0 && (
                <div className="flex items-center gap-2">
                  <button
                    onClick={handleExportJSON}
                    className="flex items-center gap-2 px-4 py-2 bg-white hover:bg-gray-50 text-indigo-600 border border-indigo-100 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-sm active:scale-95"
                  >
                    <DocumentArrowDownIcon className="w-4 h-4" /> {t.export.json}
                  </button>
                  <button
                    onClick={() => downloadCSV(generateCSV(generatedData, columnOrder), `${basics.week_title} - ${basics.day_name}.csv`)}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-lg shadow-indigo-100 active:scale-95"
                  >
                    <ArrowDownTrayIcon className="w-4 h-4" /> {t.export.csv}
                  </button>
                </div>
             )}
          </div>
        </div>
      </header>

      <main className="flex-1 p-4 sm:p-6 lg:p-8 overflow-hidden">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-10rem)]">

          <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-hidden">
            <div className="overflow-y-auto custom-scrollbar flex-1 space-y-6 pr-1">

              <section className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden flex flex-col">
                <div className="flex border-b border-gray-200 bg-gray-50/50">
                  <button onClick={() => setActiveTab('basics')} className={`flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'basics' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PencilSquareIcon className="w-3.5 h-3.5" /> {t.tabs.basics}
                  </button>
                  <button onClick={() => setActiveTab('smart')} className={`flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'smart' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <ScissorsIcon className="w-3.5 h-3.5" /> {t.tabs.smart}
                  </button>
                  <button onClick={() => setActiveTab('upload')} className={`flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'upload' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PhotoIcon className="w-3.5 h-3.5" /> {t.tabs.upload}
                  </button>
                </div>

                <div className="p-5">
                  {activeTab === 'basics' && <BasicsForm metadata={basics} onChange={handleBasicsChange} disabled={isLoading} uiLanguage={uiLanguage} />}

                  {activeTab === 'smart' && (
                    <div className="space-y-4">
                      <div className="flex items-center justify-between">
                        <h3 className="text-[10px] font-black text-gray-900 uppercase tracking-widest">{t.smart.blockEditor}</h3>
                        <span className="bg-indigo-100 text-indigo-600 px-2.5 py-1 rounded-lg text-[9px] font-black">{smartBlocks.length}</span>
                      </div>

                      <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-1">
                        {smartBlocks.length === 0 ? (
                          <div className="border-2 border-dashed border-gray-100 rounded-2xl p-8 text-center bg-gray-50/30">
                            <CommandLineIcon className="w-8 h-8 text-gray-200 mx-auto mb-3" />
                            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest leading-relaxed">{t.smart.emptyState}</p>
                          </div>
                        ) : (
                          smartBlocks.map((block, idx) => (
                            <div key={block.id} className="group bg-white border border-gray-100 rounded-2xl p-3 shadow-sm hover:border-indigo-200 transition-all animate-in slide-in-from-bottom-2">
                              <div className="flex items-center justify-between mb-2">
                                <button 
                                    onClick={() => toggleBlockType(block.id)}
                                    className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-full cursor-pointer hover:opacity-80 transition-opacity ${
                                        block.type === 't' ? 'bg-purple-100 text-purple-700' :
                                        block.type === 'q' ? 'bg-amber-100 text-amber-700' :
                                        'bg-blue-100 text-blue-700'
                                    }`}
                                >
                                    {block.type === 't' ? t.smart.t : block.type === 'q' ? t.smart.q : t.smart.x}
                                </button>
                                <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => openFocusModal(block)} className="p-1 text-gray-300 hover:text-indigo-600" title={t.smart.focusEdit}>
                                      <ArrowsPointingOutIcon className="w-3.5 h-3.5" />
                                    </button>
                                    <button onClick={() => moveBlock(idx, 'up')} className="p-1 text-gray-300 hover:text-indigo-600"><ChevronUpIcon className="w-3 h-3"/></button>
                                    <button onClick={() => moveBlock(idx, 'down')} className="p-1 text-gray-300 hover:text-indigo-600"><ChevronDownIcon className="w-3 h-3"/></button>
                                    <button onClick={() => setSmartBlocks(prev => prev.filter(b => b.id !== block.id))} className="p-1 text-gray-300 hover:text-red-500 ml-1"><TrashIcon className="w-3 h-3"/></button>
                                </div>
                              </div>
                              <textarea 
                                value={block.text}
                                onChange={(e) => updateBlockText(block.id, e.target.value)}
                                onFocus={() => openFocusModal(block)}
                                readOnly
                                className="w-full bg-gray-50 rounded-lg p-2 text-[11px] text-gray-600 border-none focus:ring-1 focus:ring-indigo-100 resize-none min-h-[40px] custom-scrollbar cursor-pointer hover:bg-gray-100 transition-colors"
                              />
                            </div>
                          ))
                        )}
                      </div>

                      <div className="grid grid-cols-1 gap-3">
                        <button 
                            onClick={addNewBlock}
                            className="w-full py-3 bg-gray-50 hover:bg-gray-100 text-gray-500 rounded-xl text-[9px] font-black uppercase tracking-widest border border-dashed border-gray-200 flex items-center justify-center gap-2 transition-all shadow-sm"
                        >
                            <PlusIcon className="w-3.5 h-3.5" /> {t.smart.addBlock}
                        </button>

                        {canProcess && (
                            <button 
                                onClick={finalizeProcess}
                                className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 flex items-center justify-center gap-2 animate-in zoom-in-95"
                            >
                                <SparklesIcon className="w-4 h-4" /> {generatedData.length > 0 ? t.smart.updateTable : t.smart.generateTable}
                            </button>
                        )}
                      </div>
                    </div>
                  )}
                  {activeTab === 'upload' && (
                    <FileUpload 
                      onFileSelect={handleImageProcess} 
                      onCancel={handleCancelProcess}
                      isLoading={isLoading} 
                      progress={extractionProgress}
                      uiLanguage={uiLanguage} 
                    />
                  )}
                </div>
              </section>
            </div>
          </div>

          <div className="lg:col-span-8 h-full">
            {activeTab === 'smart' ? (
              <SmartSplitter 
                onBlocksUpdate={setSmartBlocks}
                blocks={smartBlocks}
                uiLanguage={uiLanguage}
              />
            ) : generatedData.length > 0 ? (
              <TablePreview 
                data={generatedData} 
                columns={columnOrder} 
                onMoveColumn={handleMoveColumn}
                onDeleteColumn={handleDeleteColumn}
                onClear={() => {
                  if(confirm(t.table.confirmClear)) {
                    setGeneratedData([]); 
                    setSmartBlocks([]);
                  }
                }} 
                uiLanguage={uiLanguage}
              />
            ) : (
              <div className="h-full bg-white rounded-3xl shadow-sm border border-gray-200 flex flex-col items-center justify-center text-center p-12">
                <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] flex items-center justify-center mb-8 transform rotate-3 hover:rotate-0 transition-transform duration-500">
                  <CommandLineIcon className="w-12 h-12 text-indigo-100" />
                </div>
                <h3 className="text-2xl font-black text-gray-900 tracking-tight">{t.welcome.title}</h3>
                <p className="text-gray-400 max-w-sm mt-4 text-sm leading-relaxed font-medium">
                  {t.welcome.description}
                </p>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Focus Edit Modal */}
      {editingBlockId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-4xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col max-h-[90vh]">
            <div className="p-6 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-indigo-600 p-2 rounded-xl text-white">
                  <PencilSquareIcon className="w-5 h-5" />
                </div>
                <h3 className="text-lg font-black text-gray-900 uppercase tracking-tight">{t.smart.modalTitle}</h3>
              </div>
              <button 
                onClick={() => setEditingBlockId(null)}
                className="p-2 hover:bg-red-50 text-gray-400 hover:text-red-500 rounded-xl transition-all"
              >
                <XMarkIcon className="w-6 h-6" />
              </button>
            </div>

            <div className="flex-1 p-8 bg-white">
              <textarea 
                autoFocus
                value={focusEditText}
                onChange={(e) => setFocusEditText(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
                    saveFocusEdit();
                  }
                  if (e.key === 'Escape') {
                    setEditingBlockId(null);
                  }
                }}
                className="w-full h-full min-h-[400px] text-2xl font-medium leading-relaxed text-gray-800 placeholder-gray-200 focus:ring-0 border-none resize-none custom-scrollbar"
                placeholder="..."
              />
            </div>

            <div className="p-6 border-t border-gray-100 flex justify-end items-center gap-4 bg-gray-50/50">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest hidden sm:inline">
                Ctrl + Enter para salvar
              </span>
              <button 
                onClick={saveFocusEdit}
                className="px-8 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-lg shadow-indigo-100 transition-all active:scale-95"
              >
                {t.smart.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useRef, useMemo, useEffect, useCallback } from 'react';
import { FileUpload } from './components/FileUpload';
import { TablePreview } from './components/TablePreview';
import { BasicsForm } from './components/BasicsForm';
import { SmartSplitter } from './components/SmartSplitter';
import { generateCSV, downloadCSV, generateJSON, downloadJSON, DEFAULT_HEADERS } from './utils/csvHelper';
import { processImageWithGemini } from './services/geminiService';
import { CSVRow, StudyMetadata } from './types';
import { UILanguage, translations } from './utils/translations';
import { 
  ArrowDownTrayIcon, 
  TableCellsIcon, 
  PhotoIcon,
  PencilSquareIcon,
  ScissorsIcon,
  CommandLineIcon,
  TrashIcon,
  ChevronUpIcon,
  ChevronDownIcon,
  SparklesIcon,
  PlusIcon,
  DocumentArrowDownIcon,
  LanguageIcon,
  ComputerDesktopIcon,
  ArrowsPointingOutIcon,
  XMarkIcon
} from '@heroicons/react/24/outline';

const DAY_MAP: Record<string, string> = {
  '1': 'Saturday', '2': 'Sunday', '3': 'Monday', '4': 'Tuesday', '5': 'Wednesday', '6': 'Thursday', '7': 'Friday',
};

interface SplitBlock {
  id: string;
  type: 't' | 'x' | 'q';
  text: string;
}

const App: React.FC = () => {
  const [uiLanguage, setUiLanguage] = useState<UILanguage>('pt');
  const t = translations[uiLanguage];

  // Logic to prevent mobile use
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 1024);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const [basics, setBasics] = useState<StudyMetadata & { lesson_title: string }>({
    week_number: '', week_title: '', day_number: '', day_name: '', language: '', lesson_title: ''
  });

  const [activeTab, setActiveTab] = useState<'upload' | 'basics' | 'smart'>('basics');
  const [generatedData, setGeneratedData] = useState<CSVRow[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [extractionProgress, setExtractionProgress] = useState(0);
  const [columnOrder, setColumnOrder] = useState<(keyof CSVRow)[]>(DEFAULT_HEADERS);
  const [smartBlocks, setSmartBlocks] = useState<SplitBlock[]>([]);

  // State for Focus Edit Modal
  const [editingBlockId, setEditingBlockId] = useState<string | null>(null);
  const [focusEditText, setFocusEditText] = useState('');

  const canProcess = useMemo(() => {
    const basicsDone = basics.week_title.trim().length > 0 && basics.day_name.trim().length > 0;
    const hasBlocks = smartBlocks.length > 0;
    return basicsDone && hasBlocks;
  }, [basics, smartBlocks]);

  const syncTableFromBlocks = useCallback((currentBlocks: SplitBlock[], currentBasics: typeof basics) => {
    if (currentBlocks.length === 0) return;

    const row: Partial<CSVRow> = { ...currentBasics };
    let textCount = 0;
    let questionCount = 0;

    currentBlocks.forEach(block => {
      if (block.type === 't') {
        row.lesson_title = block.text;
      } else if (block.type === 'q') {
        questionCount++;
        const qKey = `question_${questionCount}` as keyof CSVRow;
        if (questionCount <= 4) {
          (row as any)[qKey] = block.text;
          (row as any)[`input_${questionCount}`] = "";
        }
      } else if (block.type === 'x') {
        textCount++;
        if (questionCount === 0) {
          if (textCount === 1) row.text_1 = block.text;
          else if (textCount === 2) row.text_2 = block.text;
          else row.text_3 = (row.text_3 ? row.text_3 + '\n' : '') + block.text;
        } else if (questionCount === 1) {
          row.text_4 = (row.text_4 ? row.text_4 + '\n' : '') + block.text;
        } else if (questionCount === 2) {
          row.text_5 = (row.text_5 ? row.text_5 + '\n' : '') + block.text;
        } else if (questionCount === 3) {
          row.text_6 = (row.text_6 ? row.text_6 + '\n' : '') + block.text;
        } else if (questionCount >= 4) {
          if (!row.text_7) row.text_7 = block.text;
          else row.text_8 = (row.text_8 ? row.text_8 + '\n' : '') + block.text;
        }
      }
    });

    setGeneratedData([row as CSVRow]);
  }, []);

  useEffect(() => {
    if (generatedData.length > 0) {
        syncTableFromBlocks(smartBlocks, basics);
    }
  }, [basics, smartBlocks, syncTableFromBlocks, generatedData.length]);

  const handleBasicsChange = (field: string, value: string) => {
    setBasics(prev => {
      const updated = { ...prev, [field]: value };
      if (field === 'day_number') {
        const mappedName = DAY_MAP[value];
        if (mappedName) updated.day_name = mappedName;
      } else if (field === 'day_name') {
        const mappedNumber = Object.keys(DAY_MAP).find(key => DAY_MAP[key] === value);
        if (mappedNumber) updated.day_number = mappedNumber;
      }
      return updated;
    });
  };

  const handleImageProcess = async (base64: string) => {
    setIsLoading(true);
    setExtractionProgress(0);
    abortControllerRef.current = new AbortController();

    try {
      const results = await processImageWithGemini(
        base64, 
        abortControllerRef.current.signal,
        (prog) => setExtractionProgress(prog)
      );

      if (results && results.length > 0) {
        const data = results[0];

        if (data.lesson_title) {
          setBasics(prev => ({ ...prev, lesson_title: data.lesson_title || '' }));
        }

        const newBlocks: SplitBlock[] = [];

        if (data.lesson_title) newBlocks.push({ id: crypto.randomUUID(), type: 't', text: data.lesson_title });
        if (data.text_1) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_1 });
        if (data.text_2) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_2 });
        if (data.text_3) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_3 });

        if (data.question_1) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_1 });
        if (data.text_4) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_4 });

        if (data.question_2) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_2 });
        if (data.text_5) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_5 });

        if (data.question_3) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_3 });
        if (data.text_6) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_6 });

        if (data.question_4) newBlocks.push({ id: crypto.randomUUID(), type: 'q', text: data.question_4 });
        if (data.text_7) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_7 });
        if (data.text_8) newBlocks.push({ id: crypto.randomUUID(), type: 'x', text: data.text_8 });

        setSmartBlocks(newBlocks);
        syncTableFromBlocks(newBlocks, basics);
        setActiveTab('smart');
      }
    } catch (err: any) {
      if (err.name !== 'AbortError') {
        alert("Falha na extração: " + err.message);
      }
    } finally {
      setIsLoading(false);
      setExtractionProgress(0);
      abortControllerRef.current = null;
    }
  };

  const handleCancelProcess = () => {
    if (abortControllerRef.current) {
      abortControllerRef.current.abort();
    }
  };

  const finalizeProcess = () => {
    syncTableFromBlocks(smartBlocks, basics);
    setActiveTab('basics');
  };

  const moveBlock = (index: number, direction: 'up' | 'down') => {
    if ((direction === 'up' && index === 0) || (direction === 'down' && index === smartBlocks.length - 1)) return;
    const newBlocks = [...smartBlocks];
    const swapIdx = direction === 'up' ? index - 1 : index + 1;
    [newBlocks[index], newBlocks[swapIdx]] = [newBlocks[swapIdx], newBlocks[index]];
    setSmartBlocks(newBlocks);
  };

  const addNewBlock = () => {
    const newBlock: SplitBlock = {
        id: crypto.randomUUID(),
        type: 'x',
        text: ''
    };
    setSmartBlocks(prev => [...prev, newBlock]);
  };

  const updateBlockText = (id: string, text: string) => {
    setSmartBlocks(prev => prev.map(b => b.id === id ? { ...b, text } : b));
  };

  const openFocusModal = (block: SplitBlock) => {
    setEditingBlockId(block.id);
    setFocusEditText(block.text);
  };

  const saveFocusEdit = () => {
    if (editingBlockId) {
      updateBlockText(editingBlockId, focusEditText);
      setEditingBlockId(null);
    }
  };

  const toggleBlockType = (id: string) => {
    const types: ('t' | 'x' | 'q')[] = ['t', 'x', 'q'];
    setSmartBlocks(prev => prev.map(b => {
        if (b.id === id) {
            const nextIdx = (types.indexOf(b.type) + 1) % types.length;
            return { ...b, type: types[nextIdx] };
        }
        return b;
    }));
  };

  const handleMoveColumn = (index: number, direction: 'left' | 'right') => {
    const newOrder = [...columnOrder];
    const targetIdx = direction === 'left' ? index - 1 : index + 1;
    [newOrder[index], newOrder[targetIdx]] = [newOrder[targetIdx], newOrder[index]];
    setColumnOrder(newOrder);
  };

  const handleDeleteColumn = (header: keyof CSVRow) => {
    const msg = t.table.deleteColConfirm.replace('{header}', String(header).replace(/_/g, ' '));
    if (window.confirm(msg)) {
      setColumnOrder(current => current.filter(col => col !== header));
    }
  };

  const handleExportJSON = () => {
    if (!basics.week_number) {
        alert(t.export.weekRequired);
        return;
    }
    const jsonStr = generateJSON(basics, smartBlocks);
    downloadJSON(jsonStr, `${basics.week_title || 'export'} - ${basics.day_name || 'day'}.json`);
  };

  // Mobile Blocking Screen
  if (isMobile) {
    return (
      <div className="min-h-screen bg-gray-50 flex flex-col items-center justify-center p-8 text-center animate-in fade-in duration-500">
        <div className="absolute top-8 right-8">
           <div className="flex items-center gap-2 bg-white border border-gray-200 rounded-xl px-2 py-1 shadow-sm">
             <LanguageIcon className="w-4 h-4 text-gray-400" />
             <select 
               value={uiLanguage}
               onChange={(e) => setUiLanguage(e.target.value as UILanguage)}
               className="bg-transparent border-none focus:ring-0 text-xs font-bold uppercase text-gray-600 cursor-pointer"
             >
               <option value="pt">Português</option>
               <option value="en">English</option>
               <option value="es">Español</option>
             </select>
           </div>
        </div>
        <div className="bg-white p-12 rounded-[3rem] shadow-xl border border-gray-100 flex flex-col items-center max-w-lg">
          <div className="bg-indigo-50 p-6 rounded-full mb-8">
            <ComputerDesktopIcon className="w-16 h-16 text-indigo-600" />
          </div>
          <h2 className="text-3xl font-black text-gray-900 mb-6 tracking-tight">{t.mobileBlock.title}</h2>
          <p className="text-gray-500 text-base leading-relaxed font-medium">
            {t.mobileBlock.message}
          </p>
          <div className="mt-10 h-1.5 w-24 bg-gray-100 rounded-full overflow-hidden">
            <div className="h-full bg-indigo-600 w-1/2 animate-[shimmer_2s_infinite_linear]"></div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-gray-50">
      <header className="bg-white border-b border-gray-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg shadow-lg shadow-indigo-100">
              <TableCellsIcon className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">{t.appTitle}</h1>
          </div>
          <div className="flex items-center gap-4">
             <div className="flex items-center gap-2 bg-gray-50 border border-gray-200 rounded-xl px-2 py-1">
               <LanguageIcon className="w-4 h-4 text-gray-400" />
               <select 
                 value={uiLanguage}
                 onChange={(e) => setUiLanguage(e.target.value as UILanguage)}
                 className="bg-transparent border-none focus:ring-0 text-xs font-bold uppercase text-gray-600 cursor-pointer"
               >
                 <option value="pt">Português</option>
                 <option value="en">English</option>
                 <option value="es">Español</option>
               </select>
             </div>

             {generatedData.length > 0 && (
                <div className="flex items-center gap-2">
                  <button
                    onClick={handleExportJSON}
                    className="flex items-center gap-2 px-4 py-2 bg-white hover:bg-gray-50 text-indigo-600 border border-indigo-100 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-sm active:scale-95"
                  >
                    <DocumentArrowDownIcon className="w-4 h-4" /> {t.export.json}
                  </button>
                  <button
                    onClick={() => downloadCSV(generateCSV(generatedData, columnOrder), `${basics.week_title} - ${basics.day_name}.csv`)}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-lg shadow-indigo-100 active:scale-95"
                  >
                    <ArrowDownTrayIcon className="w-4 h-4" /> {t.export.csv}
                  </button>
                </div>
             )}
          </div>
        </div>
      </header>

      <main className="flex-1 p-4 sm:p-6 lg:p-8 overflow-hidden">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-6 h-[calc(100vh-10rem)]">

          <div className="lg:col-span-4 flex flex-col gap-6 h-full overflow-hidden">
            <div className="overflow-y-auto custom-scrollbar flex-1 space-y-6 pr-1">

              <section className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden flex flex-col">
                <div className="flex border-b border-gray-200 bg-gray-50/50">
                  <button onClick={() => setActiveTab('basics')} className={`flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'basics' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <PencilSquareIcon className="w-3.5 h-3.5" /> {t.tabs.basics}
                  </button>
                  <button onClick={() => setActiveTab('smart')} className={`flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors ${activeTab === 'smart' ? 'bg-white text-indigo-600 border-b-2 border-indigo-600' : 'text-gray-400 hover:text-gray-600'}`}>
                    <ScissorsIcon className="w-3.5 h-3.5" /> {t.tabs.smart}
                  </button>
                  {/* Disabled Image Tab */}
                  <button 
                    disabled 
                    title="Temporarily Disabled"
                    className="flex-1 py-3 text-[10px] font-black uppercase flex items-center justify-center gap-1.5 transition-colors text-gray-300 cursor-not-allowed opacity-50"
                  >
                    <PhotoIcon className="w-3.5 h-3.5" /> {t.tabs.upload}
                  </button>
                </div>

                <div className="p-5">
                  {activeTab === 'basics' && <BasicsForm metadata={basics} onChange={handleBasicsChange} disabled={isLoading} uiLanguage={uiLanguage} />}

                  {activeTab === 'smart' && (
                    <div className="space-y-4">
                      <div className="flex items-center justify-between">
                        <h3 className="text-[10px] font-black text-gray-900 uppercase tracking-widest">{t.smart.blockEditor}</h3>
                        <span className="bg-indigo-100 text-indigo-600 px-2.5 py-1 rounded-lg text-[9px] font-black">{smartBlocks.length}</span>
                      </div>

                      <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-1">
                        {smartBlocks.length === 0 ? (
                          <div className="border-2 border-dashed border-gray-100 rounded-2xl p-8 text-center bg-gray-50/30">
                            <CommandLineIcon className="w-8 h-8 text-gray-200 mx-auto mb-3" />
                            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest leading-relaxed">{t.smart.emptyState}</p>
                          </div>
                        ) : (
                          smartBlocks.map((block, idx) => (
                            <div key={block.id} className="group bg-white border border-gray-100 rounded-2xl p-3 shadow-sm hover:border-indigo-200 transition-all animate-in slide-in-from-bottom-2">
                              <div className="flex items-center justify-between mb-2">
                                <button 
                                    onClick={() => toggleBlockType(block.id)}
                                    className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-full cursor-pointer hover:opacity-80 transition-opacity ${
                                        block.type === 't' ? 'bg-purple-100 text-purple-700' :
                                        block.type === 'q' ? 'bg-amber-100 text-amber-700' :
                                        'bg-blue-100 text-blue-700'
                                    }`}
                                >
                                    {block.type === 't' ? t.smart.t : block.type === 'q' ? t.smart.q : t.smart.x}
                                </button>
                                <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button onClick={() => openFocusModal(block)} className="p-1 text-gray-300 hover:text-indigo-600" title={t.smart.focusEdit}>
                                      <ArrowsPointingOutIcon className="w-3.5 h-3.5" />
                                    </button>
                                    <button onClick={() => moveBlock(idx, 'up')} className="p-1 text-gray-300 hover:text-indigo-600"><ChevronUpIcon className="w-3 h-3"/></button>
                                    <button onClick={() => moveBlock(idx, 'down')} className="p-1 text-gray-300 hover:text-indigo-600"><ChevronDownIcon className="w-3 h-3"/></button>
                                    <button onClick={() => setSmartBlocks(prev => prev.filter(b => b.id !== block.id))} className="p-1 text-gray-300 hover:text-red-500 ml-1"><TrashIcon className="w-3 h-3"/></button>
                                </div>
                              </div>
                              <textarea 
                                value={block.text}
                                onChange={(e) => updateBlockText(block.id, e.target.value)}
                                onFocus={() => openFocusModal(block)}
                                readOnly
                                className="w-full bg-gray-50 rounded-lg p-2 text-[11px] text-gray-600 border-none focus:ring-1 focus:ring-indigo-100 resize-none min-h-[40px] custom-scrollbar cursor-pointer hover:bg-gray-100 transition-colors"
                              />
                            </div>
                          ))
                        )}
                      </div>

                      <div className="grid grid-cols-1 gap-3">
                        <button 
                            onClick={addNewBlock}
                            className="w-full py-3 bg-gray-50 hover:bg-gray-100 text-gray-500 rounded-xl text-[9px] font-black uppercase tracking-widest border border-dashed border-gray-200 flex items-center justify-center gap-2 transition-all shadow-sm"
                        >
                            <PlusIcon className="w-3.5 h-3.5" /> {t.smart.addBlock}
                        </button>

                        {canProcess && (
                            <button 
                                onClick={finalizeProcess}
                                className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-indigo-100 flex items-center justify-center gap-2 animate-in zoom-in-95"
                            >
                                <SparklesIcon className="w-4 h-4" /> {generatedData.length > 0 ? t.smart.updateTable : t.smart.generateTable}
                            </button>
                        )}
                      </div>
                    </div>
                  )}
                  {activeTab === 'upload' && (
                    <FileUpload 
                      onFileSelect={handleImageProcess} 
                      onCancel={handleCancelProcess}
                      isLoading={isLoading} 
                      progress={extractionProgress}
                      uiLanguage={uiLanguage} 
                    />
                  )}
                </div>
              </section>
            </div>
          </div>

          <div className="lg:col-span-8 h-full">
            {activeTab === 'smart' ? (
              <SmartSplitter 
                onBlocksUpdate={setSmartBlocks}
                blocks={smartBlocks}
                uiLanguage={uiLanguage}
              />
            ) : generatedData.length > 0 ? (
              <TablePreview 
                data={generatedData} 
                columns={columnOrder} 
                onMoveColumn={handleMoveColumn}
                onDeleteColumn={handleDeleteColumn}
                onClear={() => {
                  if(confirm(t.table.confirmClear)) {
                    setGeneratedData([]); 
                    setSmartBlocks([]);
                  }
                }} 
                uiLanguage={uiLanguage}
              />
            ) : (
              <div className="h-full bg-white rounded-3xl shadow-sm border border-gray-200 flex flex-col items-center justify-center text-center p-12">
                <div className="w-24 h-24 bg-gray-50 rounded-[2.5rem] flex items-center justify-center mb-8 transform rotate-3 hover:rotate-0 transition-transform duration-500">
                  <CommandLineIcon className="w-12 h-12 text-indigo-100" />
                </div>
                <h3 className="text-2xl font-black text-gray-900 tracking-tight">{t.welcome.title}</h3>
                <p className="text-gray-400 max-w-sm mt-4 text-sm leading-relaxed font-medium">
                  {t.welcome.description}
                </p>
              </div>
            )}
          </div>
        </div>
      </main>

      {/* Focus Edit Modal */}
      {editingBlockId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-4xl rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-300 flex flex-col max-h-[90vh]">
            <div className="p-6 border-b border-gray-100 flex items-center justify-between bg-gray-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-indigo-600 p-2 rounded-xl text-white">
                  <PencilSquareIcon className="w-5 h-5" />
                </div>
                <h3 className="text-lg font-black text-gray-900 uppercase tracking-tight">{t.smart.modalTitle}</h3>
              </div>
              <button 
                onClick={() => setEditingBlockId(null)}
                className="p-2 hover:bg-red-50 text-gray-400 hover:text-red-500 rounded-xl transition-all"
              >
                <XMarkIcon className="w-6 h-6" />
              </button>
            </div>

            <div className="flex-1 p-8 bg-white">
              <textarea 
                autoFocus
                value={focusEditText}
                onChange={(e) => setFocusEditText(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
                    saveFocusEdit();
                  }
                  if (e.key === 'Escape') {
                    setEditingBlockId(null);
                  }
                }}
                className="w-full h-full min-h-[400px] text-2xl font-medium leading-relaxed text-gray-800 placeholder-gray-200 focus:ring-0 border-none resize-none custom-scrollbar"
                placeholder="..."
              />
            </div>

            <div className="p-6 border-t border-gray-100 flex justify-end items-center gap-4 bg-gray-50/50">
              <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest hidden sm:inline">
                Ctrl + Enter para salvar
              </span>
              <button 
                onClick={saveFocusEdit}
                className="px-8 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-lg shadow-indigo-100 transition-all active:scale-95"
              >
                {t.smart.save}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
